import { useState, useEffect, useRef } from "react";

// ═══════════════════════════════════════════════════════════
// WIREREADY PRO — 500-QUESTION CA ELECTRICIAN EXAM PREP APP
// All questions original field knowledge, no NEC text reproduced
// ═══════════════════════════════════════════════════════════

const ALL_QUESTIONS = [
// MODULE 1: DEFINITIONS & GENERAL (30)
{id:1,mod:1,cat:"Definitions",diff:"Easy",q:"What is the definition of 'ampacity'?",opts:["Max voltage a conductor can carry","Current in amperes a conductor can carry continuously without exceeding its temperature rating","Resistance per 1,000 feet","Cross-sectional area in circular mils"],ans:1,ref:"NEC Article 100",exp:"Ampacity = current a conductor carries continuously without exceeding its temperature rating. Drives all conductor sizing decisions."},
{id:2,mod:1,cat:"Definitions",diff:"Easy",q:"Which article contains primary NEC definitions?",opts:["Article 90","Article 100","Article 110","Article 200"],ans:1,ref:"NEC Article 100",exp:"Article 100 = primary definitions. Article 90 = purpose/scope. Know Article 100 cold — foundation for every other article."},
{id:3,mod:1,cat:"Definitions",diff:"Easy",q:"A 'dwelling unit' must have space for:",opts:["Human habitation","Eating, living, sleeping, AND permanent cooking facilities","Any overnight occupancy","Two or more separate living units"],ans:1,ref:"NEC Article 100",exp:"Dwelling unit requires ALL four: eating, living, sleeping, permanent cooking. Hotel rooms don't qualify — no permanent cooking. Critical for determining which NEC rules apply."},
{id:4,mod:1,cat:"Definitions",diff:"Easy",q:"'Authority Having Jurisdiction' (AHJ) refers to:",opts:["NFPA committee","Organization or individual responsible for enforcing the NEC","Utility company","Licensed contractor"],ans:1,ref:"NEC Article 100",exp:"AHJ = enforcing authority, typically the local electrical inspector. Has final say on code interpretation and can approve alternatives."},
{id:5,mod:1,cat:"Definitions",diff:"Easy",q:"A 'feeder' consists of:",opts:["All conductors between service equipment and the final branch circuit overcurrent device","Conductors from transformer to meter","Any conductor larger than 10 AWG","Conductors between two panels"],ans:0,ref:"NEC Article 100",exp:"Feeder = conductors between service equipment and the final OCPD. Feeders supply panelboards; branch circuits supply loads."},
{id:6,mod:1,cat:"Definitions",diff:"Easy",q:"A 'branch circuit' consists of:",opts:["Any conductor under 100A","Conductors between the final overcurrent device and the outlet(s)","Conductors from utility to service panel","Any wiring within a dwelling"],ans:1,ref:"NEC Article 100",exp:"Branch circuit = conductors between the FINAL overcurrent device and outlet(s). Determines which Article 210 rules apply."},
{id:7,mod:1,cat:"Definitions",diff:"Medium",q:"An 'individual branch circuit' supplies:",opts:["Only one piece of utilization equipment","Multiple general-purpose receptacles","A single appliance rated over 1,000 watts","Only lighting loads"],ans:0,ref:"NEC Article 100",exp:"Individual branch circuit = one piece of utilization equipment only. Examples: dedicated refrigerator, single motor circuit."},
{id:8,mod:1,cat:"Definitions",diff:"Medium",q:"A 'qualified person' per Article 100 has:",opts:["Any valid electrician license","Skills, knowledge of electrical equipment, and safety training to recognize and avoid hazards","An electrical engineering degree","5+ years of experience"],ans:1,ref:"NEC Article 100",exp:"Qualified person = training, knowledge, AND safety training for the specific voltage/equipment. Licensure alone isn't enough for every task."},
{id:9,mod:1,cat:"Definitions",diff:"Medium",q:"Minimum working space depth for a 480V panel — live parts one side, grounded parts other (Condition 2)?",opts:["2.5 feet","3 feet","3.5 feet","4 feet"],ans:2,ref:"NEC 110.26(A)(1), Table 110.26(A)(1)",exp:"151–600V, Condition 2 = 3.5 feet. Condition 1 = 3 feet, Condition 3 = 4 feet. Table 110.26 is heavily tested on the CA exam."},
{id:10,mod:1,cat:"Definitions",diff:"Medium",q:"Minimum headroom in front of service equipment?",opts:["6 feet","6 feet 3 inches","6 feet 6 inches","7 feet"],ans:2,ref:"NEC 110.26(E)",exp:"Minimum headroom = 6 feet 6 inches for service equipment, switchboards, panelboards, and MCCs."},
{id:11,mod:1,cat:"Definitions",diff:"Medium",q:"Which is PERMITTED in the dedicated electrical working space?",opts:["Storing electrical materials","Piping and ducts in the space","Foreign systems above the equipment","None — must be completely clear"],ans:3,ref:"NEC 110.26(B) & 110.26(F)",exp:"Dedicated space must be free from piping, ducts, and foreign systems. Storage never permitted. Most commonly cited code violation during inspections."},
{id:12,mod:1,cat:"Definitions",diff:"Medium",q:"Equipment required by the NEC shall be acceptable if:",opts:["Approved by the installer","Listed by a testing laboratory","Approved by the AHJ","Manufactured per industry standards"],ans:2,ref:"NEC 110.2",exp:"Equipment must be approved by the AHJ. Listed equipment is generally accepted but AHJ has ultimate authority."},
{id:13,mod:1,cat:"Definitions",diff:"Easy",q:"The purpose of the NEC per Article 90 is:",opts:["Comprehensive electrical design guide","Practical safeguarding of persons and property from electrical hazards","Specifying the most economical methods","Standardizing equipment for manufacturing"],ans:1,ref:"NEC 90.1",exp:"NEC purpose = practical safeguarding of persons and property from electrical hazards. Minimum safety requirements — better designs may exceed code."},
{id:14,mod:1,cat:"Definitions",diff:"Easy",q:"Standard US residential service voltage is:",opts:["110/220V single-phase","120/240V single-phase three-wire","277/480V three-phase","208/120V three-phase"],ans:1,ref:"NEC Article 100",exp:"Standard residential = 120/240V single-phase three-wire. 240V for large appliances; 120V for lighting and receptacles."},
{id:15,mod:1,cat:"Definitions",diff:"Medium",q:"Required width of working space in front of electrical equipment:",opts:["Equal to width of equipment","At least 24 inches","Width of equipment or 30 inches, whichever is greater","At least 36 inches regardless of equipment width"],ans:2,ref:"NEC 110.26(A)(2)",exp:"Working space width = equipment width OR 30 inches, whichever is greater."},
{id:16,mod:1,cat:"Definitions",diff:"Hard",q:"'Continuous load' means:",opts:["Operates 24 hours","Maximum current expected to continue for 3 hours or more","Never cycles off","Connected directly to service entrance"],ans:1,ref:"NEC Article 100",exp:"Continuous load = maximum current for 3+ hours. Triggers the 80% loading rule. Examples: commercial lighting, HVAC, signs."},
{id:17,mod:1,cat:"Definitions",diff:"Medium",q:"'Listed' means equipment:",opts:["Tested by local inspector","Included in a list by an organization confirming it meets applicable standards","Approved by NFPA","Manufactured by a certified company"],ans:1,ref:"NEC Article 100",exp:"Listed = appears on a published list from a recognized testing organization (UL, ETL, CSA) confirming it meets applicable standards."},
{id:18,mod:1,cat:"Definitions",diff:"Easy",q:"Difference between 'grounded' and 'grounding' conductors?",opts:["Same — both are the neutral","Grounded conductor (neutral) carries normal current; grounding conductor (EGC) provides fault current path","Grounded = connected to earth; grounding = connected to neutral","No difference — interchangeable"],ans:1,ref:"NEC Article 100",exp:"Grounded conductor (neutral) = carries normal return current. EGC = safety conductor for fault current only, no normal current. Confusing these is a dangerous and common mistake."},
{id:19,mod:1,cat:"Definitions",diff:"Medium",q:"A 'separately derived system' is:",opts:["Any generator-derived system","Electrical source with no direct metallic connection from its circuit conductors to circuit conductors of another system","Any transformer installation","A system with its own grounding electrode"],ans:1,ref:"NEC Article 100",exp:"Separately derived system = no direct metallic connection between its circuit conductors and another system's conductors (except through grounding). Requires its own grounding electrode."},
{id:20,mod:1,cat:"Definitions",diff:"Hard",q:"What illumination is required at electrical equipment working spaces?",opts:["No minimum specified","Sufficient as determined by AHJ","Lighting must be provided for service equipment, switchboards, and panelboards","50 foot-candles minimum"],ans:2,ref:"NEC 110.26(D)",exp:"Illumination required for service equipment, switchboards, panelboards, and MCC working spaces. Light switch must not require entering the working space to operate."},
{id:21,mod:1,cat:"Definitions",diff:"Medium",q:"Which installation is NOT covered by the NEC?",opts:["Manufactured homes","Recreational vehicles","Ships and watercraft","Agricultural buildings"],ans:2,ref:"NEC 90.2(B)",exp:"Ships and watercraft excluded from NEC scope, along with railway rolling stock, aircraft, and automotive vehicles. Agricultural buildings, manufactured homes, and RVs ARE covered."},
{id:22,mod:1,cat:"Definitions",diff:"Easy",q:"A 'panelboard' per Article 100 is:",opts:["Any metal enclosure containing electrical equipment","Panel assembly accessible from the front, in a cabinet or cutout box, containing buses and overcurrent devices","Switchboard used in industrial facilities","Any panel rated over 200 amperes"],ans:1,ref:"NEC Article 100",exp:"Panelboard = front-accessible panel assembly with buses and overcurrent devices in a cabinet. Differs from switchboards (accessible front and rear)."},
{id:23,mod:1,cat:"Definitions",diff:"Medium",q:"What encroachment is permitted in dedicated electrical space?",opts:["None — no encroachment permitted","25% of required width","Space above equipment may have encroachments","Only prohibited directly in front of equipment"],ans:0,ref:"NEC 110.26(F)(1)",exp:"Dedicated electrical space (floor to 6 feet above equipment or ceiling, whichever is lower) must be completely free. No encroachments permitted. Period."},
{id:24,mod:1,cat:"Definitions",diff:"Hard",q:"Article 110.14 termination temperature rating rule:",opts:["Always use 75°C column","Ampacity at terminations based on LOWEST temperature rating of conductor, termination, or device","Always use 60°C column at terminations","Temperature ratings need not be matched if conductors are properly sized"],ans:1,ref:"NEC 110.14(C)",exp:"Termination rule: lowest temperature rating wins. A 90°C conductor at a 60°C lug = use 60°C ampacity from Table 310.16. This causes many undersized connections in the field."},
{id:25,mod:1,cat:"Definitions",diff:"Medium",q:"'In sight from' means:",opts:["Visible from any point in the building","Visible AND not more than 50 feet distant","Within 10 feet direct line of sight","Able to be seen without optical instruments"],ans:1,ref:"NEC Article 100",exp:"In sight from = visible AND ≤50 feet. Both conditions required. A disconnect 75 feet away even if visible is NOT 'in sight from' the motor."},
{id:26,mod:1,cat:"Definitions",diff:"Easy",q:"Nominal voltage of commercial lighting on a 277/480V system?",opts:["120V","208V","240V","277V"],ans:3,ref:"NEC Article 100",exp:"In 480V three-phase commercial systems, lighting circuits operate at 277V (phase-to-neutral). Hence commercial 277V fluorescent and LED fixtures."},
{id:27,mod:1,cat:"Definitions",diff:"Hard",q:"Field-installed wire connectors must be:",opts:["Any approved wire nut for any conductor","Listed and suitable for the application, conductor material, and temperature rating","Only copper conductors may be spliced","Splices only in boxes"],ans:1,ref:"NEC 110.14(A)",exp:"Wire connectors must be listed and suitable for: specific application, conductor material (copper vs aluminum), and temperature rating. Wrong connector on aluminum = fire hazard."},
{id:28,mod:1,cat:"Definitions",diff:"Medium",q:"Minimum clearance between service conductors and an openable window?",opts:["12 inches","24 inches","3 feet","Service conductors may not pass near openable windows"],ans:2,ref:"NEC 230.9(A)",exp:"Service entrance conductors = 3 feet minimum from openable windows, doors, porches, balconies, and fire escapes. Conductors passing above the top of a window are exempt."},
{id:29,mod:1,cat:"Definitions",diff:"Easy",q:"The NEC is published by:",opts:["OSHA","ANSI","NFPA (National Fire Protection Association)","IEEE"],ans:2,ref:"NEC 90.1",exp:"NEC published by NFPA (National Fire Protection Association). ANSI approves it as ANSI/NFPA 70. Updated every 3 years. NFPA publishes; AHJ enforces."},
{id:30,mod:1,cat:"Definitions",diff:"Medium",q:"Conductors of different voltage systems may share a raceway when:",opts:["Never — different voltage systems must be separate","All conductors are insulated for the maximum voltage present","Separated by a metallic barrier","Combined load doesn't exceed fill limit"],ans:1,ref:"NEC 300.3(C)(1)",exp:"Different voltage systems may share a raceway if ALL conductors are insulated for the maximum voltage present. 120V and 277V can share a conduit if all are rated ≥277V."},
// MODULE 2: WIRING & OVERCURRENT (45)
{id:31,mod:2,cat:"Wiring & Overcurrent",diff:"Easy",q:"Minimum number of 20A small appliance branch circuits required in a dwelling unit kitchen?",opts:["One circuit","At least two 20A circuits","Three per California code","No specific number required"],ans:1,ref:"NEC 210.11(C)(1)",exp:"At least two 20-ampere small appliance branch circuits are required for kitchen, dining room, pantry, and similar areas. Cannot supply loads other than small appliances in these rooms."},
{id:32,mod:2,cat:"Wiring & Overcurrent",diff:"Easy",q:"Maximum continuous load on a 20A, 120V branch circuit?",opts:["2,400 watts","2,000 watts","1,920 watts","1,440 watts"],ans:2,ref:"NEC 210.20(A)",exp:"Continuous loads = 80% max. 20A × 120V × 0.80 = 1,920 VA. The 80%/125% rule for continuous loads is one of the most tested calculation concepts on the CA exam."},
{id:33,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"GFCI protection is required in which dwelling locations per 2020 NEC?",opts:["Living rooms only","Bathrooms, garages, outdoors, crawl spaces, unfinished basements, kitchen near sinks, and boathouses","Bathrooms and kitchens only","All receptacles in the dwelling"],ans:1,ref:"NEC 210.8(A)",exp:"2020 NEC expanded GFCI locations. Full list: bathrooms, garages, outdoors, crawl spaces, unfinished basements, kitchen countertop surfaces within 6 feet of sinks, boathouses, and washing machine locations."},
{id:34,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"AFCI protection per 2020 NEC is required for 120V 15A/20A circuits in which dwelling rooms?",opts:["Bedrooms only","Bedrooms and living rooms only","All rooms in the dwelling unit","Only rooms with sleeping occupants"],ans:2,ref:"NEC 210.12(A)",exp:"2020 NEC expanded AFCI to ALL rooms in dwelling units — not just bedrooms as in earlier editions. Includes living rooms, dining rooms, kitchens, hallways, closets."},
{id:35,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"Maximum spacing for dwelling unit wall receptacle outlets?",opts:["6 feet","12 feet","No point along the floor line more than 6 feet from an outlet","No point along the floor line more than 12 feet from an outlet"],ans:2,ref:"NEC 210.52(A)(1)",exp:"No point along the floor line can be more than 6 feet from an outlet, measured along the floor. Results in outlets no more than 12 feet apart. Any wall space 2 feet or wider requires an outlet."},
{id:36,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"Kitchen receptacle placement rule?",opts:["No minimum — anywhere on countertop","Within 24 inches of the sink edge","Within 2 feet along the wall","No receptacle required within 6 feet of a sink"],ans:1,ref:"NEC 210.52(C)(1)",exp:"Receptacles must be placed so no point along the countertop is more than 24 inches from an outlet. No receptacle may be installed face-up in the countertop."},
{id:37,mod:2,cat:"Wiring & Overcurrent",diff:"Easy",q:"Bathroom receptacle location requirement?",opts:["Adjacent to the toilet","Within 36 inches of the outside edge of each basin","Adjacent to the mirror","Anywhere in the bathroom"],ans:1,ref:"NEC 210.52(D)",exp:"At least one receptacle within 36 inches of the outside edge of EACH basin — measured from the basin edge, not along the wall. Corner vanities need a receptacle within 36 inches of each basin."},
{id:38,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"The 'next size up' rule for overcurrent protection permits a larger standard device when:",opts:["Calculated load exceeds conductor ampacity","Conductor ampacity doesn't correspond to a standard overcurrent device rating AND the circuit isn't a motor branch circuit or feeder","When the inspector approves a larger device","For any residential circuit up to 30 amperes"],ans:1,ref:"NEC 240.4(B)",exp:"Next-size-up rule: conductor ampacity doesn't match a standard size → use next larger standard size. Conditions: not a motor branch circuit, next size doesn't exceed 800A."},
{id:39,mod:2,cat:"Wiring & Overcurrent",diff:"Hard",q:"Standard overcurrent device ratings in Article 240 include which common residential sizes?",opts:["Any rating matching the connected load","15, 20, 25, 30, 35, 40, 45, 50, 60, 70, 80, 90, 100, 110, 125, 150, 175, 200 amperes and more","Any round number","Only UL-listed ratings"],ans:1,ref:"NEC 240.6(A)",exp:"Standard sizes are specified. Know the common residential sizes: 15, 20, 25, 30, 35, 40, 45, 50, 60, 70, 80, 90, 100, 110, 125, 150, 175, 200A. Critical for next-size-up rule application."},
{id:40,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"A circuit breaker used as a switch for 125V fluorescent lighting must be:",opts:["Any breaker may be used as a switch","Rated SWD (Switching Duty) for this application","A separate disconnect is required — breakers can't be switches","A GFCI type"],ans:1,ref:"NEC 240.83(D)",exp:"Circuit breakers used as switches for fluorescent lighting must be rated SWD (Switching Duty). Standard breakers aren't rated for repeated switching cycles under load."},
{id:41,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"What is required for a dedicated circuit supplying a household dishwasher?",opts:["15A circuit is sufficient","20A individual branch circuit required","Match the dishwasher nameplate rating","Dishwashers must use small appliance circuits"],ans:1,ref:"NEC 422.16(B)(2)",exp:"Dishwashers require a 20-ampere individual branch circuit. Cannot supply other loads. One of several appliances requiring individual circuits per NEC."},
{id:42,mod:2,cat:"Wiring & Overcurrent",diff:"Hard",q:"Maximum fuse rating for a 12 AWG copper THWN conductor?",opts:["15 amperes","20 amperes","25 amperes","30 amperes"],ans:1,ref:"NEC 240.4(D)(5)",exp:"12 AWG THWN copper ampacity = 20A (Table 310.16, 75°C). Overcurrent device cannot exceed conductor ampacity. 20A is the absolute maximum. Using 25A or 30A on 12 AWG is dangerous overprotection."},
{id:43,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"The laundry circuit for a dwelling may also supply:",opts:["An adjacent receptacle outlet in the laundry area","Lighting in the laundry room","A gas dryer","Nothing else — individual circuit required"],ans:0,ref:"NEC 210.11(C)(2)",exp:"The NEC requires at least one 20A circuit for laundry purposes. It can supply the laundry area receptacles (not individual circuit required for laundry unless for specific appliances like dishwashers or disposals)."},
{id:44,mod:2,cat:"Wiring & Overcurrent",diff:"Hard",q:"Minimum circuit rating for a household electric range rated at 8¾ kW or more?",opts:["30 amperes","40 amperes","50 amperes","60 amperes"],ans:1,ref:"NEC 210.19(A)(3)",exp:"Electric range rated ≥8¾ kW requires a branch circuit rated not less than 40A and not more than 50A. 50A is the typical residential range circuit."},
{id:45,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"Commercial garage 125V single-phase 15/20A receptacles require:",opts:["Only near water sources","GFCI protection for all 125V single-phase 15 and 20A receptacles","Only receptacles within 6 feet of a drain","No special protection"],ans:1,ref:"NEC 511.12",exp:"In commercial garages for vehicle service, ALL 125V, single-phase, 15 and 20-ampere receptacles require GFCI protection. Water from vehicle washing creates serious shock hazard."},
{id:46,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"Minimum circuit ampacity for a 4,500-watt, 240V residential electric water heater?",opts:["20 amperes","25 amperes","30 amperes","Size by nameplate only"],ans:1,ref:"NEC 422.13 & 210.20(A)",exp:"4,500W ÷ 240V = 18.75A × 125% (continuous) = 23.4A minimum. Next standard size = 25A. Water heaters are continuous loads."},
{id:47,mod:2,cat:"Wiring & Overcurrent",diff:"Hard",q:"Multiwire branch circuit breakers must:",opts:["Standard individual breakers may be used","Connect to separate phases — individual breakers are fine","Have handle ties or two-pole breaker so all ungrounded conductors open simultaneously","Only one GFCI breaker needed"],ans:2,ref:"NEC 210.4(B)",exp:"2020 NEC: multiwire branch circuits must have a means to simultaneously disconnect all ungrounded conductors. Handle-tied pair or two-pole breaker required. Prevents dangerous partial de-energization."},
{id:48,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"Minimum overhead conductor clearance over a residential driveway?",opts:["10 feet","12 feet","15 feet","18 feet"],ans:3,ref:"NEC 230.24(B)(1)",exp:"Service drop conductors must clear residential driveways by 18 feet minimum. Higher than the 15-foot commercial clearance and the 12-foot clearance for areas not subject to vehicle traffic."},
{id:49,mod:2,cat:"Wiring & Overcurrent",diff:"Easy",q:"Required circuit size for a dedicated bathroom receptacle circuit?",opts:["15 amperes minimum","20 amperes minimum","Based on load calculation","No dedicated circuit required"],ans:1,ref:"NEC 210.11(C)(3)",exp:"20-ampere circuit required for bathroom receptacle outlets. Cannot supply receptacles in other rooms. May serve receptacles in a single bathroom including bathroom lighting."},
{id:50,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"Tamper-resistant receptacles per 2020 NEC are required:",opts:["Only in areas accessible to children","In all 125V, 15 and 20A non-locking receptacles throughout the entire dwelling","Only in bathrooms and kitchens","Only on circuits below 20A"],ans:1,ref:"NEC 406.12",exp:"Tamper-resistant receptacles required for ALL 125V, 15 and 20-ampere non-locking receptacles throughout the entire dwelling unit. All rooms, not just those with children."},
{id:51,mod:2,cat:"Wiring & Overcurrent",diff:"Hard",q:"A 60A overcurrent device protects a circuit with 55A-rated conductors. Is this permitted?",opts:["No — OCPD must not exceed conductor ampacity","Yes — next-size-up rule permits 60A since 55A doesn't correspond to a standard size","Only with AHJ approval","Yes — 60A is within 10% of the conductor ampacity"],ans:1,ref:"NEC 240.4(B)",exp:"55A doesn't match a standard size (standard sizes: 50A and 60A). Next-size-up rule permits the 60A device here. Classic exam scenario — 55A conductor, 60A breaker is code-compliant."},
{id:52,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"Maximum cord length for a household garbage disposal?",opts:["18 inches","2 feet","3 feet","4 feet"],ans:2,ref:"NEC 422.16(B)(1)",exp:"Maximum cord length for a garbage disposal = 3 feet. Must be connected to a 20A, 120V individual branch circuit."},
{id:53,mod:2,cat:"Wiring & Overcurrent",diff:"Hard",q:"'Inverse time' circuit breaker terminology means:",opts:["Trips faster at higher overload currents","Takes longer to trip at higher currents","Doesn't trip on overloads, only short circuits","Resets automatically after a set time"],ans:0,ref:"NEC Article 100 & 240.6",exp:"Inverse time = trips FASTER at higher currents. Small overload = minutes to trip; heavy overload = seconds; short circuit = nearly instantaneous. Allows current surges while protecting against sustained overheating."},
{id:54,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"Minimum circuit rating for a 5,000-watt, 240V residential clothes dryer?",opts:["20 amperes","30 amperes","40 amperes","125% of nameplate"],ans:1,ref:"NEC 210.23(B) & 220.54",exp:"Clothes dryers require minimum 30-ampere branch circuit (four-wire in new installations). NEC minimum of 30A governs even if the calculation yields less."},
{id:55,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"Outdoor receptacle requirement for a single-family dwelling?",opts:["One at front or back","At least one at the front AND one at the back accessible at grade level","Two front and two back","One per 1,000 sq ft of exterior wall"],ans:1,ref:"NEC 210.52(E)(1)",exp:"At least one receptacle at the front AND one at the rear of single-family dwellings, accessible at grade level. Both must be GFCI protected. Balconies, decks, and porches also require receptacles."},
{id:56,mod:2,cat:"Wiring & Overcurrent",diff:"Hard",q:"What is special about a 20A receptacle versus a 15A receptacle?",opts:["Larger physical size","T-shaped (horizontal) slot on one hot slot to accept 20A plugs","Three slots instead of two","Requires a 4-wire connection"],ans:1,ref:"NEC 406.3(B)",exp:"20A receptacle has a T-shaped slot on one hot terminal to accept 20A plugs while still accepting standard 15A plugs. Required on 20A circuits where single-outlet use is expected."},
{id:57,mod:2,cat:"Wiring & Overcurrent",diff:"Easy",q:"Minimum number of circuits required for laundry area of a single-family dwelling?",opts:["No dedicated circuit required","One 15A circuit","At least one 20A circuit for laundry appliances","Two — one for washer, one for dryer"],ans:2,ref:"NEC 210.11(C)(2)",exp:"At least one 20-ampere branch circuit must serve laundry appliances. Cannot supply outlets in other areas."},
{id:58,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"In hotels/motels, the bathroom receptacle circuit may serve:",opts:["A dedicated 20A circuit for each room","GFCI receptacles on any circuit","No more than one guest room bathroom","Multiple rooms — same rules as dwelling units"],ans:2,ref:"NEC 210.11(C)(3) Exception",exp:"Hotel/motel bathroom circuits may serve the bathroom of no more than one guest room. Different from dwelling unit rules where one circuit can serve multiple bathrooms."},
{id:59,mod:2,cat:"Wiring & Overcurrent",diff:"Hard",q:"General lighting load for an office building per Article 220 is:",opts:["1 VA per square foot","2 VA per square foot","3.5 VA per square foot","10 VA per square foot"],ans:2,ref:"NEC Table 220.12",exp:"Office buildings = 3.5 VA/sq ft per Table 220.12. Dwelling units = 3 VA/sq ft. Warehouses = 0.25 VA/sq ft. Schools = 3 VA/sq ft. Know these values — essential for commercial load calculations."},
{id:60,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"A GFCI detects what and at what level?",opts:["Overloads and short circuits","Small ground fault currents (approximately 5mA) and trips to protect people from electrocution","It provides a ground connection for equipment","Equipment voltage surges"],ans:1,ref:"NEC 210.8 & Article 100",exp:"GFCI detects current imbalance between hot and neutral (~5mA) indicating current flowing through a person. GFCI protects people; standard overcurrent devices protect conductors and equipment."},
{id:61,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"Minimum height for wall switches per the NEC in a dwelling unit?",opts:["3 feet","4 feet","No minimum height specified — switches must be accessible","6 feet 7 inches maximum"],ans:2,ref:"NEC 404.8(A)",exp:"NEC doesn't specify a minimum height for switches, only that they be accessible. Maximum is 6 feet 7 inches. ADA requirements may impose specific heights in commercial applications."},
{id:62,mod:2,cat:"Wiring & Overcurrent",diff:"Hard",q:"Feeder demand load is 28,000 VA at 240V. Minimum feeder ampacity?",opts:["100 amperes","117 amperes","125 amperes","150 amperes"],ans:1,ref:"NEC 215.2(A)(1)",exp:"28,000VA ÷ 240V = 116.7A ≈ 117A minimum feeder ampacity. The conductor must have at least 117A ampacity. Next standard overcurrent device would be 125A."},
{id:63,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"A 15/20A GFCI receptacle means:",opts:["Protects both 15A and 20A circuits","Rated 15A with 20A feed-through GFCI","Listed for installation on 15A or 20A circuits and provides GFCI protection for downstream devices","All of the above"],ans:2,ref:"NEC 210.8 & 406.4(D)",exp:"15/20A GFCI = suitable for installation on 15A or 20A circuits, and when used in feed-through mode, provides GFCI protection to downstream outlets on the same circuit."},
{id:64,mod:2,cat:"Wiring & Overcurrent",diff:"Hard",q:"Maximum overcurrent device for a 60A feeder?",opts:["60 amperes","70 amperes","80 amperes","100 amperes"],ans:0,ref:"NEC 215.3 & 240.4",exp:"60A feeder = maximum 60A overcurrent device. Standard fuse ratings include 60A as a listed size. Overcurrent device cannot exceed feeder's calculated load or conductor ampacity."},
{id:65,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"An arc fault circuit interrupter (AFCI) protects against:",opts:["Ground faults to people (same as GFCI)","Parallel arcing faults in conductors that can cause fires","Overloads exceeding conductor ampacity","Voltage surges from lightning"],ans:1,ref:"NEC 210.12",exp:"AFCIs detect arcing fault waveform patterns — the type that starts fires in walls and ceilings without tripping standard breakers. AFCI = fire protection; GFCI = shock protection."},
{id:66,mod:2,cat:"Wiring & Overcurrent",diff:"Easy",q:"Maximum voltage for use of 14 AWG copper branch circuit conductors?",opts:["120V only","120/240V","Up to 600V","Any voltage"],ans:1,ref:"NEC 240.4(D)(3)",exp:"14 AWG copper (ampacity 15A) is used almost exclusively on 120V and 240V residential circuits. The limitation is practical ampacity, not voltage rating of the insulation."},
{id:67,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"In a sub-panel, the neutral must:",opts:["Bond to the equipment ground just like the main panel","Connect to an isolated neutral bus — NOT bonded to equipment ground","Connect to either the neutral or ground bus","Connect to the main breaker terminal only"],ans:1,ref:"NEC 408.40",exp:"Sub-panel: neutral bus must be ISOLATED from equipment ground. Neutral and EGC only bonded at the service. Bonding neutral to ground in sub-panels creates dangerous parallel neutral current paths."},
{id:68,mod:2,cat:"Wiring & Overcurrent",diff:"Hard",q:"A circuit has 35A continuous load. Minimum overcurrent device rating?",opts:["35 amperes","40 amperes","43.75 amperes (125% of 35A)","50 amperes"],ans:2,ref:"NEC 210.20(A) & 240.4",exp:"Continuous loads × 125% = 35A × 1.25 = 43.75A minimum. 43.75A doesn't match a standard size, so next standard size = 45A. The conductor must also be rated 43.75A minimum."},
{id:69,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"Receptacles within what distance of a swimming pool's inside walls must be GFCI protected?",opts:["10 feet","15 feet","20 feet","25 feet"],ans:2,ref:"NEC 680.22(A)(1)",exp:"Per Article 680, receptacle outlets within 20 feet of inside walls of a pool must be GFCI protected. Receptacles must be at least 6 feet from pool edge."},
{id:70,mod:2,cat:"Wiring & Overcurrent",diff:"Hard",q:"GFCI protection in commercial and institutional kitchens per 2020 NEC?",opts:["Standard circuit protection only — not required in commercial kitchens","GFCI required for all receptacles in commercial kitchens","GFCI required within 6 feet of a sink only","AFCI required in commercial kitchens"],ans:1,ref:"NEC 210.8(B)(2)",exp:"2020 NEC: GFCI protection required for ALL receptacles in commercial and institutional kitchens. Major expansion from previous editions. Water, wet surfaces, and high current appliances = serious shock hazard."},
{id:71,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"Dwelling unit hallways 10 feet or more in length require:",opts:["No receptacle outlets","At least one receptacle outlet","Two receptacle outlets — one at each end","One for every 10 feet of length"],ans:1,ref:"NEC 210.52(H)",exp:"Dwelling unit hallways ≥10 feet long require at least one receptacle outlet. Ensures appliances like vacuums can be used without extension cords."},
{id:72,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"Holiday lighting illuminated for 3 weeks — what loading rule applies?",opts:["Standard 100% loading — only a few weeks","Continuous load rules — maximum 12A on a 15A circuit","No limit for seasonal decorative lighting","80% only applies to commercial circuits"],ans:1,ref:"NEC Article 100 & 210.20(A)",exp:"Holiday lighting on for 3+ hours continuously = continuous load. 80% rule applies: 15A × 0.80 = 12A maximum continuous load. Even seasonal loads follow continuous load rules. Classic exam trap."},
{id:73,mod:2,cat:"Wiring & Overcurrent",diff:"Hard",q:"A 20A circuit breaker rating represents:",opts:["Maximum load in watts","Continuous current rating — will carry 20A continuously without tripping","Maximum fault current it can interrupt","The short circuit current rating"],ans:1,ref:"NEC Article 100 & 240.6",exp:"20A rating = continuous current rating. NOT the trip point (breakers typically trip at 100-125% of rating). Interrupting capacity (fault current the breaker can safely break) is a separate rating, often 10,000 AIC for residential."},
{id:74,mod:2,cat:"Wiring & Overcurrent",diff:"Medium",q:"Disconnecting means for a dwelling unit 240V air conditioner must be:",opts:["Panel breaker serves as disconnect — no additional disconnect needed","Within sight of and readily accessible from the air conditioning equipment","Lockable regardless of sight distance","Only required if unit is more than 50 feet from panel"],ans:1,ref:"NEC 440.14",exp:"Readily accessible disconnecting means must be within sight of and within 50 feet of A/C equipment. Allows service personnel to de-energize before working on the unit."},
{id:75,mod:2,cat:"Wiring & Overcurrent",diff:"Easy",q:"A dedicated circuit for a residential sump pump?",opts:["Not required — any available circuit acceptable","A dedicated 20A circuit is required","Must share a circuit with other laundry equipment","15A circuit is sufficient"],ans:0,ref:"NEC 210.52 (no sump pump req.)",exp:"The NEC does NOT require a dedicated circuit for residential sump pumps. Good practice to dedicate a circuit, but not required. Know what the NEC doesn't require — as important as what it does require."},
// MODULE 3: SERVICES & FEEDERS (35)
{id:76,mod:3,cat:"Services & Feeders",diff:"Easy",q:"Minimum service ampacity for a new single-family dwelling?",opts:["60 amperes","80 amperes","100 amperes","150 amperes"],ans:2,ref:"NEC 230.79(C)",exp:"Minimum service for a single-family dwelling = 100 amperes. In practice, 200A is standard for new construction, but 100A is the NEC minimum."},
{id:77,mod:3,cat:"Services & Feeders",diff:"Easy",q:"Maximum number of service disconnects for a single building?",opts:["One only","Four","Six","No maximum"],ans:2,ref:"NEC 230.71(A)",exp:"Maximum of six service disconnects grouped at one location. The 'rule of six' is classic exam material. Each disconnect serves a different load group."},
{id:78,mod:3,cat:"Services & Feeders",diff:"Medium",q:"Minimum clearance of service drop conductors over a residential driveway?",opts:["10 feet","12 feet","15 feet","18 feet"],ans:3,ref:"NEC 230.24(B)(1)",exp:"Service drop conductors must clear residential driveways by 18 feet minimum. Higher than the 15-foot commercial clearance and 12-foot for areas without vehicle traffic."},
{id:79,mod:3,cat:"Services & Feeders",diff:"Medium",q:"Minimum clearance of service entrance conductors over a roof surface?",opts:["3 feet","6 feet","8 feet","10 feet"],ans:0,ref:"NEC 230.24(A) Exception 2",exp:"Service conductors over a roof = 8 feet clearance minimum, EXCEPT where voltage ≤300V to ground AND roof slope ≥4 in 12, then 3 feet is acceptable. The 3-foot exception for steep residential roofs is commonly tested."},
{id:80,mod:3,cat:"Services & Feeders",diff:"Medium",q:"Where must the service disconnect be located?",opts:["In a locked room only","At a readily accessible location outside or inside nearest the point of entrance of service conductors","In the center of the building","Any inside location is acceptable"],ans:1,ref:"NEC 230.70(A)(1)",exp:"Service disconnect must be readily accessible — outside or inside nearest to point of entry of service conductors. 'Readily accessible' = no ladder, moving obstacles, or unlocking enclosures required."},
{id:81,mod:3,cat:"Services & Feeders",diff:"Hard",q:"Minimum clearance between service conductors and an openable window?",opts:["12 inches","24 inches","3 feet","Service conductors may not pass near openable windows"],ans:2,ref:"NEC 230.9(A)",exp:"Service entrance conductors must maintain at least 3 feet clearance from openable windows, doors, porches, balconies, and fire escapes. Conductors passing above the top of a window are exempt."},
{id:82,mod:3,cat:"Services & Feeders",diff:"Medium",q:"When two or more sets of service conductors are used, the combined ampacity must:",opts:["Each set must be sized for the total load","Combined ampacity of all sets must equal at least the required service ampacity","Each set must carry exactly one-half the service load","The largest set must equal the total service ampacity"],ans:1,ref:"NEC 230.40 & 310.10(H)",exp:"Multiple sets of service conductors: combined ampacity of all sets must equal or exceed the required service ampacity. Each set need not carry the full load independently."},
{id:83,mod:3,cat:"Services & Feeders",diff:"Medium",q:"Minimum size service entrance conductors for a 200A residential service using copper?",opts:["2 AWG","1 AWG","2/0 AWG","3/0 AWG"],ans:2,ref:"NEC Table 310.16 & 240.4(B)",exp:"For 200A service, 2/0 AWG copper (195A at 75°C) or 4/0 AWG aluminum. Per next-size-up rule, 2/0 AWG copper is acceptable for 200A service. Standard residential service conductor size."},
{id:84,mod:3,cat:"Services & Feeders",diff:"Hard",q:"Service lateral conductors (underground service) are:",opts:["Utility property not covered by NEC","Service entrance conductors — meet all service conductor requirements","Feeder conductors sized per Article 215","Low voltage conductors not requiring protection"],ans:1,ref:"NEC Article 100 & 230.2",exp:"Service lateral conductors = underground service entrance conductors. Carry full service current and must meet all service conductor requirements including sizing, protection, and grounding."},
{id:85,mod:3,cat:"Services & Feeders",diff:"Medium",q:"Service conduit must be sealed at its entrance to service equipment to:",opts:["Prevent water from entering","Prevent insects from entering","Prevent condensation-causing air circulation","All of the above"],ans:3,ref:"NEC 230.8",exp:"Service conduit must be sealed at the service head and service equipment to prevent water infiltration, insects, and air circulation that causes condensation. Condensation in service equipment causes corrosion and failure."},
{id:86,mod:3,cat:"Services & Feeders",diff:"Hard",q:"Optional calculation method for single-family dwelling load: how is demand calculated?",opts:["Optional method cannot be used with electric heat","10,000 VA plus loads exceeding 10 kW","First 10 kVA at 100% plus remainder at 40%","8,000 VA minimum regardless"],ans:2,ref:"NEC 220.82(B)",exp:"Optional method: 100% of first 10 kVA of all loads + 40% of remainder. Electric heat and A/C — the larger of the two included. Often results in lower calculated demand than standard method."},
{id:87,mod:3,cat:"Services & Feeders",diff:"Medium",q:"Minimum burial depth for service lateral conductors in rigid metal conduit (RMC)?",opts:["6 inches","12 inches","18 inches","24 inches"],ans:0,ref:"NEC Table 300.5",exp:"RMC and IMC may be buried at minimum 6 inches depth. PVC conduit requires 18 inches; direct burial cable requires 24 inches. RMC's heavy steel construction allows shallower burial."},
{id:88,mod:3,cat:"Services & Feeders",diff:"Easy",q:"'Service point' is defined as:",opts:["Location of the main service disconnect","Point of connection between the serving utility's facilities and the premises wiring","The metering location","The grounding electrode connection point"],ans:1,ref:"NEC Article 100",exp:"Service point = connection between utility's facilities and customer's premises wiring. Everything from the service point inward is covered by the NEC. Utility equipment up to service point is covered by NESC."},
{id:89,mod:3,cat:"Services & Feeders",diff:"Medium",q:"Minimum burial depth for PVC conduit under a residential driveway not subject to truck traffic?",opts:["6 inches","12 inches","18 inches","24 inches"],ans:1,ref:"NEC Table 300.5",exp:"Under residential driveways (not subject to truck traffic), all conduit (including PVC) must be buried minimum 12 inches. Under truck traffic areas: 24 inches. Know burial depths by location and conduit type."},
{id:90,mod:3,cat:"Services & Feeders",diff:"Hard",q:"Meter pulling requirements for California services?",opts:["All meters must be capable of being pulled","Only when disconnect is not adjacent to meter","California utilities require pull-out capability for emergency","Meter pulling is a utility requirement, not NEC"],ans:3,ref:"CEC / Utility Requirements",exp:"Metering and meter pulling are utility requirements, not NEC requirements. California utilities (SCE, PG&E, SDG&E) have their own requirements. Always coordinate with the serving utility on California services."},
{id:91,mod:3,cat:"Services & Feeders",diff:"Medium",q:"A feeder to a detached garage must include:",opts:["Only ungrounded conductors and neutral","An equipment grounding conductor in addition to the neutral, unless certain conduit conditions are met","Only ungrounded conductors if garage has its own electrode","Any configuration with GFCI protection"],ans:1,ref:"NEC 250.32(B)",exp:"Feeder to a separate structure must include an EGC. May be omitted ONLY if: no EGC in existing feeder, no grounding-type receptacles in structure, and no metallic path back to main building. New installations require an EGC."},
{id:92,mod:3,cat:"Services & Feeders",diff:"Medium",q:"When service conductors run in parallel, each raceway must contain:",opts:["Same size conductors only","All phase conductors and neutral in each raceway","All phases, neutral, and EGC must each be in one of the raceways","One phase per raceway"],ans:1,ref:"NEC 310.10(H)(6)",exp:"Parallel service conductors: each raceway must contain all phase conductors, neutral (if needed), and EGC. Running all phases in one raceway prevents inductive heating in metal raceways."},
{id:93,mod:3,cat:"Services & Feeders",diff:"Hard",q:"Maximum total ampere rating of branch circuit breakers in a 200A panel?",opts:["200 amperes — sum cannot exceed 200A","May exceed 200A based on demand factors and load diversity","Must be limited to 42 circuits","Cannot exceed 200A of connected load"],ans:1,ref:"NEC 408.54",exp:"Branch circuit breaker total CAN exceed the main breaker rating. This is load diversity — not all circuits are fully loaded simultaneously. Panel sized on calculated demand, not sum of all breaker ratings."},
{id:94,mod:3,cat:"Services & Feeders",diff:"Medium",q:"The service head must be located:",opts:["At the highest point on the roof","Above the service equipment","Above the point where service drop conductors attach, with drip loops formed","At the utility's service point"],ans:2,ref:"NEC 230.54(C)",exp:"Service head must be ABOVE the point where service drop conductors attach. Allows drip loops — downward curves preventing water from flowing along conductors into the service head."},
{id:95,mod:3,cat:"Services & Feeders",diff:"Easy",q:"Color identification for the grounded service conductor (neutral)?",opts:["Green","White or gray","Black","Any color with white tape at terminations"],ans:1,ref:"NEC 200.6",exp:"Grounded conductor (neutral) must be white or gray. Green = EGC. Black = typically hot (ungrounded). Color coding prevents dangerous cross-connections. For conductors >6 AWG, white tape at terminals is acceptable."},
{id:96,mod:3,cat:"Services & Feeders",diff:"Hard",q:"A 600A service uses four parallel sets of 350 kcmil copper conductors (each = 350A ampacity). Adequate?",opts:["No — each parallel set must handle the full service","Yes — 4 sets × 350A = 1,400A combined ampacity, exceeding 600A","No — parallel conductors must be same size as single conductors","Yes, but only if all four conduits are same size"],ans:1,ref:"NEC 310.10(H)",exp:"Parallel conductors valid when combined ampacity meets or exceeds required service ampacity. 4 × 350A = 1,400A combined > 600A required. Parallel conductors must be same size, material, insulation type, and length."},
{id:97,mod:3,cat:"Services & Feeders",diff:"Medium",q:"Each parallel conduit for service conductors must contain:",opts:["One conductor per conduit to prevent heating","All phase conductors, neutral, and grounding conductor in same conduit","One complete set per conduit — all phases, neutral, and EGC in each conduit","Two conductors per conduit maximum"],ans:2,ref:"NEC 310.10(H)(6)",exp:"Each parallel conduit must contain one complete set: all phase conductors + neutral (if required) + EGC. Balances current in each raceway and prevents inductive heating in metallic conduits."},
{id:98,mod:3,cat:"Services & Feeders",diff:"Medium",q:"Minimum size neutral when largest service entrance conductor is 3/0 AWG copper?",opts:["Same size as ungrounded conductors","At least 6 AWG copper","At least 1/0 AWG copper","Based on actual neutral load, not phase conductors"],ans:3,ref:"NEC 220.61 & 250.24(C)",exp:"Neutral sized based on maximum unbalanced load — not automatically same as phase conductors. Large services often use reduced-size neutrals. But minimums apply: neutral cannot be smaller than required GEC size for that service ampacity."},
{id:99,mod:3,cat:"Services & Feeders",diff:"Hard",q:"Minimum aluminum conductor size for a 200A underground service lateral?",opts:["2 AWG","1/0 AWG","4/0 AWG","250 kcmil"],ans:2,ref:"NEC Table 310.16 & 240.4(B)",exp:"For 200A service using aluminum, 4/0 AWG aluminum (180A at 75°C) is commonly accepted minimum using demand factors. 250 kcmil aluminum = exactly 200A at 75°C. Most AHJs accept 4/0 aluminum for 200A residential service."},
{id:100,mod:3,cat:"Services & Feeders",diff:"Medium",q:"Clearance required between service conductors and a sign on a building?",opts:["3 feet above, 1 foot to sides","1 foot minimum from all points","3 feet — same as from openable windows","Signs must be removed"],ans:2,ref:"NEC 230.9(A)",exp:"Service conductors must maintain at least 3 feet clearance from windows, doors, porches, balconies, ladders, stairs, fire escapes, and attachment points where a person could contact them."},
{id:101,mod:3,cat:"Services & Feeders",diff:"Medium",q:"Service entrance conductors between service head and service disconnect must be in:",opts:["No protection required — service conductors are heavy gauge","Rigid metal conduit only","Service entrance cable (SE) or approved raceway","Service conductors protected by main breaker only"],ans:2,ref:"NEC 230.43",exp:"Service entrance conductors must be in SE cable or approved raceway. Protected by the main overcurrent device at the service disconnect. Must be kept as short as practical within the building."},
{id:102,mod:3,cat:"Services & Feeders",diff:"Hard",q:"Demand factor for 4–6 electric clothes dryers per Table 220.54?",opts:["100%","70%","4 dryers = 80%, 5 = 75%, 6–7 = 70%","All dryers calculated at 5,000 VA — no demand factor"],ans:2,ref:"NEC Table 220.54",exp:"Table 220.54: 4 dryers = 80%, 5 = 75%, 6–7 = 70%. These demand factors significantly reduce calculated service load for multi-family buildings with multiple dryers. Minimum load per dryer = 5,000W."},
{id:103,mod:3,cat:"Services & Feeders",diff:"Easy",q:"Service lateral conductors run underground from the utility to the service entrance. They may be:",opts:["Direct buried cables only","Direct buried cables or in conduit","Underground feeder (UF) cable only","Service entrance (SE) cable only"],ans:1,ref:"NEC 230.30 & 230.32",exp:"Service lateral conductors may be direct buried cables or in conduit depending on utility and AHJ requirements. California utilities have specific requirements for service lateral installations."},
{id:104,mod:3,cat:"Services & Feeders",diff:"Medium",q:"Every service must have at least:",opts:["One disconnect per service","One disconnect for every 100A of capacity","No minimum — some buildings may not need a disconnect","At least one disconnecting means"],ans:3,ref:"NEC 230.70(A)",exp:"Every service must have at least one disconnecting means to allow de-energizing the entire premises. Maximum is six. The disconnect must be accessible to emergency responders."},
{id:105,mod:3,cat:"Services & Feeders",diff:"Hard",q:"Feeder demand of 75A — minimum copper conductor at 75°C terminations?",opts:["4 AWG (85A ampacity)","6 AWG (65A — insufficient)","4 AWG — next size meeting 75A","3 AWG (100A) for safety margin"],ans:0,ref:"NEC Table 310.16",exp:"6 AWG copper at 75°C = 65A (insufficient). 4 AWG copper at 75°C = 85A (sufficient). Minimum conductor for 75A demand = 4 AWG copper. Ampacity must equal or exceed demand load."},
{id:106,mod:3,cat:"Services & Feeders",diff:"Medium",q:"How many service disconnects are permitted for a 1,200A commercial building service?",opts:["Only one for services over 1,000A","Up to six grouped at one location","As many as needed with AHJ approval","Two — one per 600A of capacity"],ans:1,ref:"NEC 230.71(A)",exp:"Rule of six applies regardless of service ampacity. Up to six service disconnects for any service ampacity, grouped at one location. Large commercial services commonly use multiple parallel service sections."},
{id:107,mod:3,cat:"Services & Feeders",diff:"Medium",q:"Exterior branch circuits and feeders (Article 225) subject to physical damage:",opts:["No additional protection required","Must be in rigid metal conduit on all exterior surfaces","Where subject to physical damage, conductors shall be protected","Must be in Schedule 80 PVC conduit"],ans:2,ref:"NEC 225.22",exp:"Article 225 requires exterior conductors be protected from physical damage where exposed to it. The AHJ determines what constitutes 'subject to physical damage.' Conduit is generally used for exposed exterior wiring."},
{id:108,mod:3,cat:"Services & Feeders",diff:"Hard",q:"For a 400A service with only ground rod electrodes, maximum GEC size required?",opts:["6 AWG copper (maximum for ground rods)","4 AWG copper","2 AWG copper","GEC must match service conductor size"],ans:0,ref:"NEC 250.66(A)",exp:"For ground rod and concrete-encased electrodes only, the GEC never needs to exceed 6 AWG copper regardless of service size. Table 250.66 caps the GEC at 6 AWG copper for ground rod electrodes. The 'large service, small GEC' rule surprises many electricians."},
{id:109,mod:3,cat:"Services & Feeders",diff:"Medium",q:"In California, who must approve the service installation before utility connects power?",opts:["Utility company only","The licensed electrical contractor","The local electrical inspector (AHJ)","Both the AHJ and the utility"],ans:3,ref:"CEC & Utility Requirements",exp:"California: local electrical inspector (AHJ) must approve and sign off the service installation, AND the utility must be satisfied before energizing. Utilities have their own standards for metering, clearances, and conductor sizing that may exceed NEC minimums."},
{id:110,mod:3,cat:"Services & Feeders",diff:"Easy",q:"SE cable versus USE cable: what is the difference?",opts:["SE = 120V services; USE = 240V services","SE = above-grade service entrance use; USE (Underground Service Entrance) = listed for direct burial","SE = aluminum; USE = copper","They are interchangeable — marketing terms only"],ans:1,ref:"NEC Article 338",exp:"SE (Service Entrance) cable = above-grade use. USE (Underground Service Entrance) cable = listed for underground direct burial. Using standard SE cable underground without burial rating is a code violation."},
// MODULE 4: GROUNDING & BONDING (40)
{id:111,mod:4,cat:"Grounding & Bonding",diff:"Easy",q:"Purpose of equipment grounding conductors (EGC)?",opts:["Carry normal return current back to source","Provide a low-impedance fault current path to facilitate overcurrent device operation","Connect equipment to earth for lightning protection","Provide voltage reference for electronic equipment"],ans:1,ref:"NEC 250.4(A)(5)",exp:"EGC provides a low-impedance fault current path allowing enough current to flow during a ground fault to trip the OCPD. Does NOT carry normal current — only fault current."},
{id:112,mod:4,cat:"Grounding & Bonding",diff:"Easy",q:"Single ground rod tests at 28 ohms resistance. What must be done?",opts:["Single rod is acceptable","Install a second rod at least 6 feet from the first","Replace with concrete-encased electrode","Drive a second rod in the same hole"],ans:1,ref:"NEC 250.56",exp:"Single ground rod exceeding 25 ohms → second supplemental electrode required at least 6 feet away. The two-rod system does NOT need to be tested — just installing the second rod satisfies the requirement."},
{id:113,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"Minimum length for a ground rod?",opts:["4 feet","6 feet","8 feet","10 feet"],ans:2,ref:"NEC 250.52(A)(5)",exp:"Ground rods must be at least 8 feet long and driven to full depth. If rock prevents full depth, rod may be driven at up to 45-degree angle, or buried horizontally in a trench at least 30 inches deep."},
{id:114,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"Minimum diameter of a steel ground rod?",opts:["1/4 inch","3/8 inch","1/2 inch","5/8 inch"],ans:3,ref:"NEC 250.52(A)(5)",exp:"Steel ground rods must be at least 5/8 inch diameter. Copper or copper-clad rods = 1/2 inch minimum. Know the difference: 5/8\" steel, 1/2\" copper."},
{id:115,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"A concrete-encased grounding electrode (Ufer ground) must consist of at least:",opts:["10 feet of bare 6 AWG copper encased in footing","20 feet of 4 AWG or larger bare copper or 20 feet of 1/2-inch rebar encased in footing concrete","6 feet of copper rod in concrete","Any metal embedded in foundation qualifies"],ans:1,ref:"NEC 250.52(A)(3)",exp:"Concrete-encased electrode: at least 20 feet of 4 AWG (or larger) bare copper conductor OR at least 20 feet of 1/2-inch (or larger) steel reinforcing bar in concrete footing. One of the best available grounding electrodes."},
{id:116,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"The main bonding jumper's function in a service panel?",opts:["Connects GEC to panel enclosure","Connects the grounded conductor (neutral) to the panel enclosure and EGC at the SERVICE only","Provides path for normal neutral current","Connects service conductors to main breaker"],ans:1,ref:"NEC 250.28",exp:"Main bonding jumper connects neutral to EGC and service enclosure AT THE SERVICE ONLY. Allows fault current to return to source via neutral to trip the OCPD. Must NOT be duplicated in downstream sub-panels."},
{id:117,mod:4,cat:"Grounding & Bonding",diff:"Hard",q:"Size of EGC for a circuit protected by a 60A overcurrent device (copper)?",opts:["8 AWG","10 AWG","12 AWG","14 AWG"],ans:1,ref:"NEC Table 250.122",exp:"Per Table 250.122: 60A OCPD → 10 AWG copper EGC. Key values to memorize: 15A=14AWG, 20A=12AWG, 30A=10AWG, 60A=10AWG, 100A=8AWG, 200A=6AWG."},
{id:118,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"GEC connections must be accessible for inspection, EXCEPT:",opts:["All GEC connections must be accessible","Connections to concrete-encased or buried electrodes need not be accessible","Connections may be buried if in a junction box","Grounding connections must be inside the panel only"],ans:1,ref:"NEC 250.68(A) Exception",exp:"Connections to concrete-encased or underground electrodes need not be accessible — cannot be practically accessed once buried. Connections to accessible electrodes (ground rods above grade, water pipes) must remain accessible."},
{id:119,mod:4,cat:"Grounding & Bonding",diff:"Hard",q:"GEC size for a 200A service using a metal underground water pipe as electrode?",opts:["8 AWG copper","6 AWG copper","4 AWG copper","2 AWG copper"],ans:2,ref:"NEC Table 250.66",exp:"Per Table 250.66: service conductors 2/0-3/0 AWG copper (typical for 200A) → GEC must be 4 AWG copper. For metal water pipe electrode, GEC must be full size (unlike ground rods which cap at 6 AWG)."},
{id:120,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"When is the grounded conductor (neutral) permitted to serve as EGC?",opts:["Never — must always be separate","Only at the service equipment where the main bonding jumper is installed","In dwelling units with copper wiring only","When AHJ approves"],ans:1,ref:"NEC 250.142(A)",exp:"Neutral may carry fault current back to source ONLY at the service, through the main bonding jumper. Downstream of service, neutral and EGC must be SEPARATE. Critical — sub-panel rule."},
{id:121,mod:4,cat:"Grounding & Bonding",diff:"Easy",q:"Color of equipment grounding conductors?",opts:["White or gray","Red","Green, green with yellow stripe, or bare","Black with green tape"],ans:2,ref:"NEC 250.119",exp:"EGC must be green, green with yellow stripes, or bare. Critical color coding — accidentally connecting green to line voltage creates lethal hazards."},
{id:122,mod:4,cat:"Grounding & Bonding",diff:"Hard",q:"Why must a metal water pipe as grounding electrode be supplemented?",opts:["Water pipes are supplemental electrodes only — don't qualify as primary","Metal water pipes are likely to be replaced with plastic, interrupting the grounding path","Water pipes have too high resistance","Water pipes only acceptable in commercial buildings"],ans:1,ref:"NEC 250.53(D)(2)",exp:"Metal water pipes are likely to be replaced with non-metallic pipe, which would interrupt the grounding path. Must be supplemented with at least one other electrode to ensure continuity after pipe replacement."},
{id:123,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"Interior metal gas piping must be:",opts:["Connected to ground through the appliance EGC — no additional bonding","Bonded to the electrical grounding system through an approved bonding connection","Never used as part of the grounding system","Only high-pressure gas lines require bonding"],ans:1,ref:"NEC 250.104(B)",exp:"Interior metal gas piping must be bonded to the electrical grounding system. Prevents dangerous voltage differences between gas appliances and electrical grounding that could cause sparks or shock."},
{id:124,mod:4,cat:"Grounding & Bonding",diff:"Hard",q:"Size of bonding jumper to bond metal water pipe to service entrance?",opts:["Same size as main bonding jumper","Per Table 250.102(C)(1) based on service entrance conductor size","Always 6 AWG copper for residential","8 AWG minimum regardless of service size"],ans:1,ref:"NEC Table 250.102(C)(1)",exp:"Bonding jumper for metal water piping sized per Table 250.102(C)(1), based on service entrance conductor size — same table as for GECs. Ensures bond is adequate for available fault current."},
{id:125,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"Where are bare copper EGCs permitted?",opts:["Never — all EGCs must be insulated","Only in conduit or otherwise protected","Only for conductors 6 AWG and larger","Bare EGCs permitted in conduit, cable assemblies, or other approved locations"],ans:3,ref:"NEC 250.119",exp:"Bare EGCs permitted when protected — in conduit, in cable assemblies, or other locations. The bare wire in 12/2 NM cable with ground is the EGC. Bare EGCs are common and code-compliant when properly protected."},
{id:126,mod:4,cat:"Grounding & Bonding",diff:"Hard",q:"System bonding jumper for a transformer (separately derived system) must be installed:",opts:["At the main service panel","At the transformer itself or at the first disconnecting means on the secondary","At any convenient point in the secondary","Transformers do not require system bonding jumpers"],ans:1,ref:"NEC 250.30(A)(1)",exp:"System bonding jumper for a separately derived system must be installed at the source (transformer) or at the first means of disconnect and OCPD on the secondary. Equivalent to the main bonding jumper at a service."},
{id:127,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"Bonding of service equipment enclosures ensures:",opts:["Voltage stability","Electrical continuity of the grounding path and ability to conduct safely any fault current","Protection from corrosion","Compliance with utility metering requirements"],ans:1,ref:"NEC 250.92",exp:"Bonding ensures electrical continuity of the grounding path and that fault current can safely flow to operate overcurrent devices. Loose or corroded connections prevent adequate fault current flow."},
{id:128,mod:4,cat:"Grounding & Bonding",diff:"Easy",q:"Single ground rod resistance threshold requiring a second rod?",opts:["10 ohms","25 ohms","50 ohms","100 ohms"],ans:1,ref:"NEC 250.56",exp:"25 ohms is the threshold. A single ground rod exceeding 25 ohms requires a second supplemental electrode. California soil varies widely — desert soils may have very high resistance, coastal soils typically lower."},
{id:129,mod:4,cat:"Grounding & Bonding",diff:"Hard",q:"Sub-panel fed by 4-wire feeder — how must neutral and ground be configured?",opts:["Bond neutral to ground like main panel","Keep neutral ISOLATED from equipment ground — no bonding jumper","Use green screw to bond neutral to enclosure","Feeder neutral may serve as both neutral and EGC"],ans:1,ref:"NEC 408.40",exp:"Sub-panel with 4-wire feeder: neutral bus must be ISOLATED from panel enclosure — no bonding jumper. EGC connects to enclosure. Bonding neutral to ground in sub-panel creates dangerous parallel neutral current paths."},
{id:130,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"Minimum length of a ground ring electrode?",opts:["At least 10 feet","At least 20 feet","At least 50 feet of bare copper buried at least 30 inches deep","At least 100 feet around building perimeter"],ans:2,ref:"NEC 250.52(A)(4)",exp:"Ground ring = at least 50 feet of 2 AWG (or larger) bare copper encircling the building, buried at least 30 inches deep. Large circumference provides large soil contact area."},
{id:131,mod:4,cat:"Grounding & Bonding",diff:"Hard",q:"Aluminum or copper-clad aluminum GECs cannot be used where:",opts:["They may be used anywhere copper is used","They must be 2 sizes larger than copper equivalents","In contact with masonry or earth, or subject to corrosive conditions","They require corrosion-inhibiting compound at all connections"],ans:2,ref:"NEC 250.64(A)",exp:"Aluminum/copper-clad aluminum GECs cannot be used where they contact masonry, earth, or corrosive environments. Aluminum oxidizes rapidly in these conditions, creating high-resistance connections that fail the grounding system."},
{id:132,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"May an isolated EGC run in the same conduit as current-carrying conductors?",opts:["No — must be in separate conduit","Yes — an isolated EGC may run in the same conduit as the conductors it grounds","Only in commercial buildings","Only if conduit isn't used as an EGC"],ans:1,ref:"NEC 250.146(D)",exp:"An isolated EGC (for sensitive electronics) is permitted in the same conduit as the circuit conductors it serves. Runs back to service panel or transformer for a clean ground path separate from the conduit system."},
{id:133,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"GEC connection method requirements?",opts:["Sheet metal screws are acceptable","Must use approved clamps, exothermic welds, or listed connections","Sheet metal screws acceptable only for concrete-encased electrodes","Sheet metal screws may be used for temporary connections"],ans:1,ref:"NEC 250.70",exp:"GEC connections must use approved means: listed clamps, exothermic welding (Cadweld), listed lugs, or other approved connectors. Sheet metal screws create high-resistance connections that can fail under fault current."},
{id:134,mod:4,cat:"Grounding & Bonding",diff:"Hard",q:"A building has multiple grounding electrodes — metal water pipe, two ground rods, and a concrete-encased electrode. How must they be connected?",opts:["Only the best electrode needs connection","All electrodes must be bonded together to form a grounding electrode system","Only the two lowest-resistance electrodes need connection","Each electrode serves a different circuit — no interconnection needed"],ans:1,ref:"NEC 250.50",exp:"When multiple grounding electrodes exist, ALL must be bonded together to form a single grounding electrode system. Prevents voltage differences between electrodes that could create dangerous potential differences."},
{id:135,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"Size of bonding bushing to bond metal conduit to service panel?",opts:["8 AWG","6 AWG","4 AWG","Per Table 250.102"],ans:3,ref:"NEC Table 250.102(C)(1) & 250.92",exp:"Bonding jumpers at service equipment sized per Table 250.102 based on service entrance conductors. Undersized bonding means during a fault the high current may vaporize the bonding conductor before the OCPD trips."},
{id:136,mod:4,cat:"Grounding & Bonding",diff:"Hard",q:"California CSST gas piping requires direct bonding:",opts:["CSST is not electrically conductive — no bonding needed","Within 6 feet of the gas meter or building entry point because lightning-induced currents can cause CSST to arc through, creating gas leaks","Only in commercial buildings","Using 2 AWG copper bonding conductor regardless of service size"],ans:1,ref:"NEC 250.104(B) & CEC Amendment",exp:"California requires CSST to be directly bonded within 6 feet of the point where gas piping enters the building. Lightning-induced current can arc through thin CSST wall, creating a gas leak. Direct bonding provides a safe path for lightning current."},
{id:137,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"GEC size for a 100A service with 1 AWG copper service entrance conductors?",opts:["10 AWG copper","8 AWG copper","6 AWG copper","4 AWG copper"],ans:2,ref:"NEC Table 250.66",exp:"Per Table 250.66: 1 AWG copper service entrance conductors → GEC = 6 AWG copper. Key table entries: 2 AWG SE = 8 AWG GEC, 1/0 AWG SE = 6 AWG GEC, 2/0-3/0 AWG SE = 4 AWG GEC."},
{id:138,mod:4,cat:"Grounding & Bonding",diff:"Easy",q:"Which of the following is a grounding electrode?",opts:["The green wire in a cable assembly","A metal underground water pipe with at least 10 feet in contact with earth","The equipment grounding conductor","The service neutral conductor"],ans:1,ref:"NEC 250.52(A)(1)",exp:"Metal underground water pipe with ≥10 feet earth contact = grounding electrode. Grounding electrodes include: metal underground water pipes, metal building frames, concrete-encased electrodes, ground rings, ground rods, and plate electrodes."},
{id:139,mod:4,cat:"Grounding & Bonding",diff:"Hard",q:"Generator used as a separately derived system requires:",opts:["EGC connects back to main panel ground — no new electrode needed","Its own grounding electrode system and system bonding jumper at the generator or first disconnect","Generator grounding only required for permanent standby systems","Generators <15 kW exempt from grounding requirements"],ans:1,ref:"NEC 250.30(A)",exp:"Generator operating as a separately derived system (transfer switch opens the neutral) requires its own grounding electrode and system bonding jumper. If transfer switch doesn't switch the neutral, it may not be a separately derived system."},
{id:140,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"Purpose of bonding metal water pipes, gas pipes, and structural steel together with the electrical grounding system?",opts:["To use these as additional grounding electrodes","To ensure all conductive surfaces are at the same potential, preventing dangerous voltage differences","To provide multiple paths for lightning current","To satisfy utility company bonding requirements"],ans:1,ref:"NEC 250.104",exp:"Bonding all metallic systems = equipotential. All metal surfaces in building stay at same voltage. Without bonding, a fault could energize one metal system while another is at different potential — shock hazard at junction points."},
{id:141,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"What identifies the main bonding jumper screw in a service panel?",opts:["Green bonding screw","White screw","Red screw indicating main bonding jumper","No color coding required"],ans:0,ref:"NEC 250.28(D)",exp:"Main bonding jumper screw connecting neutral bar to panel enclosure is traditionally green. Visual identifier that bonding is complete at the service. Green screw only in service panel — must be absent in sub-panels."},
{id:142,mod:4,cat:"Grounding & Bonding",diff:"Hard",q:"In a 3-phase 4-wire wye system, what is typical voltage between phase conductor and neutral?",opts:["120V on 208/120V system; 277V on 480/277V system","208V on both systems","Phase-to-neutral voltage equals phase-to-phase voltage","Always 120V regardless of phase-to-phase voltage"],ans:0,ref:"NEC Article 100",exp:"Wye system: phase-to-neutral = phase-to-phase / 1.732. For 208V: 208/1.732 = 120V. For 480V: 480/1.732 = 277V. Standard commercial voltages: 120/208V and 277/480V three-phase wye systems."},
{id:143,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"FMC can serve as EGC when:",opts:["Always — FMC is metallic and provides a grounding path","Listed for grounding, ≤6 feet total length, with listed fittings, and circuit ≤20A for equipment","Never — separate EGC always required with FMC","Only for circuits 30A and below"],ans:1,ref:"NEC 250.118(5)",exp:"FMC as EGC conditions: (1) listed for grounding, (2) total length ≤6 feet, (3) listed fittings, (4) circuit ≤20A for equipment circuits. Beyond 6 feet, a separate EGC is required. Classic 6-foot FMC rule."},
{id:144,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"Copper conductor size for bonding metal water pipe when service entrance conductors are 350 kcmil copper?",opts:["6 AWG copper","4 AWG copper","2 AWG copper","1/0 AWG copper"],ans:2,ref:"NEC Table 250.66",exp:"Per Table 250.66: 350 kcmil copper service conductors → GEC (and water pipe bonding jumper) = 2 AWG copper. As service conductors get larger, GEC requirement increases to handle higher fault currents."},
{id:145,mod:4,cat:"Grounding & Bonding",diff:"Hard",q:"What is a 'ground fault' and why is it dangerous?",opts:["Current flowing through grounding electrode to earth — safe because earth absorbs it","Current flowing through an unintended path to ground, potentially through a person or creating arcing that can cause fire","A fault when grounding electrode is disconnected","An overload that trips the GFCI"],ans:1,ref:"NEC Article 100 & 250.4(A)(5)",exp:"Ground fault = unintended current flow through a path to ground — through a person, building structure, or creating an arc. Dangerous because: may not carry enough current to trip standard breakers, can electrocute people, and arcing ground faults cause fires."},
{id:146,mod:4,cat:"Grounding & Bonding",diff:"Easy",q:"Color of EGC in a flexible cord?",opts:["White or gray","Green or green with yellow stripe","Black","Bare copper"],ans:1,ref:"NEC 250.119(A)",exp:"In flexible cord, EGC must be green or green with yellow stripes. Same as for fixed wiring. Three-wire grounded cord: black (hot), white (neutral), green (EGC)."},
{id:147,mod:4,cat:"Grounding & Bonding",diff:"Hard",q:"Aluminum EGC in direct contact with concrete?",opts:["Permitted — aluminum is durable in concrete","Permitted if coated with aluminum-compatible compound","Not permitted — aluminum corrodes in alkaline concrete environment","Permitted only if coated or sleeved"],ans:2,ref:"NEC 250.64(A) & 250.120(B)",exp:"Aluminum and copper-clad aluminum EGCs cannot contact masonry (concrete, brick, mortar) — the alkaline environment causes rapid corrosion. Same restriction as for GECs. Always use copper where contact with concrete or earth occurs."},
{id:148,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"Building structural steel that doesn't contact earth directly must be:",opts:["Bonded to another grounding electrode","Cannot be used as a grounding electrode","Building must install a separate ground ring","Qualified if bonded to metal water pipe"],ans:0,ref:"NEC 250.52(A)(2)",exp:"Building structural steel not directly contacting earth must be bonded to the grounding electrode system through service grounding connections. Steel frame becomes part of the grounding electrode system through bonding."},
{id:149,mod:4,cat:"Grounding & Bonding",diff:"Medium",q:"Minimum burial depth for a ground ring electrode?",opts:["6 inches","18 inches","24 inches","30 inches"],ans:3,ref:"NEC 250.52(A)(4)",exp:"Ground ring must be buried at least 30 inches deep. Depth ensures conductor stays in moist soil and avoids freeze/thaw damage. The 30-inch depth + 50-foot minimum length + 2 AWG minimum copper are all required."},
{id:150,mod:4,cat:"Grounding & Bonding",diff:"Hard",q:"When multiple sets of service entrance conductors run in parallel, main bonding jumper sizing:",opts:["One jumper sized for the entire service","Separate bonding jumper for each parallel set, each sized based on that set's conductor size","Total cross-sectional area determines one combined jumper","Main bonding jumpers not required with parallel conductors"],ans:1,ref:"NEC 250.28(D)(2)",exp:"Parallel service conductors: a separate main bonding jumper is required for each set (each service section), with each jumper sized based on the conductor size in that raceway."},
// MODULE 5: WIRING METHODS (55)
{id:151,mod:5,cat:"Wiring",diff:"Easy",q:"Maximum conduit fill percentage for a single conductor?",opts:["31 percent","40 percent","53 percent","60 percent"],ans:2,ref:"NEC Chapter 9, Table 1",exp:"One conductor = 53% max fill. Two conductors = 31%. Three or more = 40%. From Chapter 9 Table 1. The 53% single-conductor rule allows efficient packing of a round conductor in a round conduit."},
{id:152,mod:5,cat:"Wiring",diff:"Easy",q:"Maximum total degrees of bends between pull points in a conduit run?",opts:["180 degrees","270 degrees","360 degrees","No limit on bends"],ans:2,ref:"NEC 358.26 (EMT)",exp:"360 degrees maximum between pull points — equivalent to four 90-degree bends. More bends make it impossible to pull wire. Universal rule regardless of conduit type or size."},
{id:153,mod:5,cat:"Wiring",diff:"Medium",q:"NM cable must be supported within what distance of every box or fitting?",opts:["6 inches","8 inches","12 inches","18 inches"],ans:2,ref:"NEC 334.30(A)",exp:"NM cable must be supported within 12 inches of every electrical box, cabinet, or fitting, and at intervals not exceeding 4.5 feet. The 12-inch rule ensures the cable is secured before entering the box."},
{id:154,mod:5,cat:"Wiring",diff:"Medium",q:"NM cable (Romex) is NOT permitted in:",opts:["Attics with insulation","Concealed spaces of masonry, concrete, or adobe","Wood-frame construction","Buildings less than three stories"],ans:1,ref:"NEC 334.10 & 334.12",exp:"NM cable prohibited in masonry, concrete, adobe construction, areas with corrosive fumes, embedded in concrete, or exposed where subject to physical damage. NM cable's plastic jacket is not rated for these conditions."},
{id:155,mod:5,cat:"Wiring",diff:"Hard",q:"Minimum burial depth for PVC conduit (Schedule 40) under a residential driveway not subject to truck traffic?",opts:["6 inches","12 inches","18 inches","24 inches"],ans:1,ref:"NEC Table 300.5",exp:"Under residential driveways (not subject to truck traffic), conduit must be buried at least 12 inches per Table 300.5. In open trenches, PVC requires 18 inches. Know burial depths by location and conduit type."},
{id:156,mod:5,cat:"Wiring",diff:"Medium",q:"EMT is NOT permitted in:",opts:["In walls of commercial buildings","Exposed on rooftops in direct sunlight","Where subject to severe physical damage or in concrete","In 2-inch diameter or less"],ans:2,ref:"NEC 358.10 & 358.12",exp:"EMT not permitted where subject to severe physical damage, embedded in concrete, or in direct contact with earth. EMT's thin walls make it vulnerable to corrosion in soil and crushing under concrete. Use RMC or IMC in these conditions."},
{id:157,mod:5,cat:"Wiring",diff:"Medium",q:"Maximum number of 90-degree bends in a run of EMT between pull points?",opts:["Two 90-degree bends","Three 90-degree bends","Four 90-degree bends — 360 degrees total","Number of bends doesn't matter — only conductor size determines pull points"],ans:2,ref:"NEC 358.26",exp:"Four 90-degree bends = 360 degrees maximum. Universal conduit bend rule regardless of conduit type or size. Four 90s are the absolute maximum before a pull box or conduit body is required."},
{id:158,mod:5,cat:"Wiring",diff:"Easy",q:"Maximum support spacing for EMT?",opts:["Every 2 feet","Every 3 feet","Every 10 feet — within 3 feet of boxes/fittings","Every 6 feet"],ans:2,ref:"NEC 358.30(A)",exp:"EMT must be secured at intervals not exceeding 10 feet and within 3 feet of each outlet box, junction box, device box, cabinet, conduit body, or other termination."},
{id:159,mod:5,cat:"Wiring",diff:"Hard",q:"Minimum bending radius for conduit depends on:",opts:["Outside diameter only","Trade size only","Trade size AND number of conductors inside","Trade size, insulation type, and bending method (one-shot vs. hand)"],ans:3,ref:"NEC 344.24 & Chapter 9 Table 2",exp:"Minimum bending radius depends on trade size, conductor insulation type (lead-covered requires larger radius), and whether a one-shot bender or hand bender is used. Bending too tightly can crack conductor insulation."},
{id:160,mod:5,cat:"Wiring",diff:"Medium",q:"What is required when conduit enters a wet location box from below?",opts:["A drain fitting must be installed","No special requirements — water doesn't flow upward","A sealing fitting is required to prevent moisture migration","Flexible conduit must be used for the last 18 inches"],ans:2,ref:"NEC 314.15",exp:"When conduit enters an enclosure from below in a wet location, a sealing fitting or other approved means must prevent moisture from entering. Condensation and water can travel through conduit by capillary action."},
{id:161,mod:5,cat:"Wiring",diff:"Medium",q:"Maximum support spacing for 1/2-inch trade size RMC?",opts:["5 feet","6 feet","8 feet","10 feet"],ans:3,ref:"NEC Table 344.30(B)(2)",exp:"RMC 1/2-inch to 3/4-inch trade size must be supported within 3 feet of outlets and at intervals not exceeding 10 feet. For 1-inch to 1¼-inch, support every 12 feet. Know support intervals by conduit type."},
{id:162,mod:5,cat:"Wiring",diff:"Hard",q:"How many 12 AWG THWN conductors in a 1/2-inch EMT conduit per Annex C?",opts:["3","4","5","7"],ans:3,ref:"NEC Annex C, Table C1",exp:"Per Annex C (Table C1 for EMT): 1/2-inch EMT = 7 conductors of 12 AWG THWN. Direct table lookup at the test site — the fastest way to answer fill questions on the exam. Memorize: 1/2\" EMT holds 7×12AWG or 9×14AWG THWN."},
{id:163,mod:5,cat:"Wiring",diff:"Medium",q:"Schedule 40 PVC versus Schedule 80 PVC — key difference?",opts:["Schedule 80 has same OD but thicker walls and smaller ID — better crush resistance","Schedule 40 for underground; Schedule 80 for above-ground","Schedule 80 rated for higher voltage","Schedule 40 is gray; Schedule 80 is white"],ans:0,ref:"NEC 352.10 & 352.12",exp:"Schedule 80 = same outside diameter (OD) as Schedule 40 but thicker walls → smaller interior diameter (ID). Stronger, required where exposed to physical damage. Holds fewer conductors than Schedule 40 of the same trade size."},
{id:164,mod:5,cat:"Wiring",diff:"Hard",q:"When must expansion fittings be used with PVC conduit?",opts:["Always — PVC always requires expansion fittings","When run exceeds 10 feet","When temperature change would cause expansion exceeding 1/4 inch based on coefficient of expansion","Expansion fittings optional for residential"],ans:2,ref:"NEC 352.44",exp:"PVC has high coefficient of thermal expansion — much higher than metal conduit. Expansion fittings required when conduit length change due to temperature changes exceeds allowable limits. Long straight runs in California's temperature extremes can buckle without expansion fittings."},
{id:165,mod:5,cat:"Wiring",diff:"Medium",q:"MC cable must be terminated with:",opts:["Standard NM cable connectors","Connectors specifically listed for MC cable","No connector needed — armor provides its own seal","Only anti-short bushings"],ans:1,ref:"NEC 330.40",exp:"MC cable must be terminated with connectors specifically listed for MC cable. These connectors grip the armor correctly and provide the transition from armored cable to the box. Wrong connector can damage conductor insulation."},
{id:166,mod:5,cat:"Wiring",diff:"Easy",q:"Purpose of the anti-short bushing used with armored cable (AC/BX)?",opts:["Protect wire insulation from sharp edges of cut armor at the termination","Provide the grounding path through the armor","Prevent moisture from entering the cable","Secure the cable to the junction box"],ans:0,ref:"NEC 320.40",exp:"Anti-short bushing ('red head') inserted between cut armor end and conductors to protect wire insulation from sharp metal edges. Missing anti-short bushings = one of the most common AC/BX cable inspection failures."},
{id:167,mod:5,cat:"Wiring",diff:"Hard",q:"Cubic inches needed per 12 AWG conductor entering a box?",opts:["2.00 cubic inches","2.25 cubic inches","2.50 cubic inches","3.00 cubic inches"],ans:1,ref:"NEC Table 314.16(B)",exp:"Per Table 314.16(B): 12 AWG = 2.25 cubic inches per conductor. 14 AWG = 2.0 cu in, 10 AWG = 2.5 cu in. Each conductor entering the box (regardless of whether it's spliced) counts as one conductor for fill."},
{id:168,mod:5,cat:"Wiring",diff:"Hard",q:"Box contains: four 12 AWG conductors, one EGC, and one duplex receptacle. Minimum cubic inch box required?",opts:["9 cubic inches","11.25 cubic inches","13.5 cubic inches","15.75 cubic inches"],ans:3,ref:"NEC 314.16(B)",exp:"Box fill: 4 conductors × 2.25 = 9.0 cu in + EGC group (1 conductor's worth = 2.25 cu in) + device (2 conductors' worth = 4.50 cu in) = 15.75 cu in minimum."},
{id:169,mod:5,cat:"Wiring",diff:"Medium",q:"LFMC (Liquidtight Flexible Metal Conduit) is commonly used for:",opts:["Underground services only","Motor and HVAC equipment requiring vibration isolation and liquidtight protection","Panel-to-panel connections in wet locations","Fluorescent lighting fixtures in commercial buildings"],ans:1,ref:"NEC 350.10",exp:"LFMC ideal for motors, HVAC, and other vibrating equipment in wet or oily locations. Standard connection method for rooftop HVAC units and compressors. Flexible construction absorbs vibration; liquidtight jacket prevents oil and moisture."},
{id:170,mod:5,cat:"Wiring",diff:"Medium",q:"'Trade size' for conduit refers to:",opts:["Actual outside diameter","Nominal designation approximating the inside diameter for conductor fill purposes","Maximum conductor size that fits","Wall thickness"],ans:1,ref:"NEC Chapter 9, Note 1",exp:"Trade size = nominal designation (approximate inside diameter) used for standardization. Actual inside diameter differs from trade size. Trade size determines which Annex C fill tables to use."},
{id:171,mod:5,cat:"Wiring",diff:"Hard",q:"Underground raceways entering buildings must:",opts:["Have an expansion fitting installed","Be sealed at their entry point to prevent moisture, gases, and insects from entering the building","Transition to RMC at the building wall","No special treatment required at building entry"],ans:1,ref:"NEC 300.5(G)",exp:"Underground raceways entering buildings must be sealed at entry point to prevent moisture, gases, and insects from migrating into the building. Especially important in California where natural gas can accumulate in conduits from underground utility leaks."},
{id:172,mod:5,cat:"Wiring",diff:"Medium",q:"FMC can serve as EGC up to what total length?",opts:["3 feet","6 feet","10 feet","25 feet"],ans:1,ref:"NEC 250.118(5)",exp:"FMC as EGC maximum = 6 feet total length (for circuits up to 20A, or 60A with listed fittings for larger circuits). Beyond 6 feet, separate EGC required. Longer FMC has too much impedance for reliable fault current flow."},
{id:173,mod:5,cat:"Wiring",diff:"Medium",q:"What wiring method is preferred for conduit runs in a concrete slab poured on grade?",opts:["PVC Schedule 40 is preferred","EMT preferred for thin walls","RMC or IMC — or Schedule 80 PVC","Any conduit is acceptable in concrete"],ans:0,ref:"NEC 352.10(C) & 344.10",exp:"PVC Schedule 40 preferred for concrete-encased installations — doesn't corrode, concrete provides protection. RMC also acceptable. EMT not listed for direct burial in earth or concrete."},
{id:174,mod:5,cat:"Wiring",diff:"Medium",q:"Where NM cable passes through a wood stud with less than 1-1/4 inch from the stud edge, what is required?",opts:["No protection required for NM cable in wood studs","A 1/16-inch thick steel plate (nail plate) must protect the cable","The cable must be in conduit through the stud","Reroute cable to maintain minimum edge distance"],ans:1,ref:"NEC 300.4(A)(1)",exp:"Where NM cable or any wiring passes through a stud with less than 1¼-inch clearance from the edge, a 1/16-inch thick steel nail plate must protect the cable from drywall nails and screws."},
{id:175,mod:5,cat:"Wiring",diff:"Easy",q:"Maximum support spacing for NM cable?",opts:["18 inches","2.5 feet","4.5 feet","6 feet"],ans:2,ref:"NEC 334.30",exp:"NM cable must be supported at intervals not exceeding 4.5 feet (54 inches) and within 12 inches of every box, cabinet, or fitting. Prevents sagging and protects cable from damage."},
{id:176,mod:5,cat:"Wiring",diff:"Medium",q:"Underground feeder (UF) cable versus NM cable — key difference?",opts:["UF has solid PVC jacket suitable for direct burial in earth","UF and NM are interchangeable","UF rated for higher voltages","UF uses aluminum conductors only"],ans:0,ref:"NEC Article 340",exp:"UF cable has solid PVC jacket encapsulating individual conductors, making it suitable for direct burial. NM cable's outer jacket is NOT rated for direct soil contact. Use UF for direct burial; NM for in-wall applications."},
{id:177,mod:5,cat:"Wiring",diff:"Medium",q:"Purpose of a pull box in a conduit system?",opts:["Provide weatherproof enclosure","Allow conductors to be pulled through conduit runs with many bends or long straight sections","Provide access for splice connections","Connect conduit at 90-degree angles"],ans:1,ref:"NEC 314.28",exp:"Pull boxes allow conductors to be pulled through long or complex conduit runs. Required when bends exceed 360 degrees. Must remain accessible. Need not contain splices."},
{id:178,mod:5,cat:"Wiring",diff:"Hard",q:"When more than 4 current-carrying conductors are installed in a single conduit, what adjustment factor applies per Table 310.15(B)(3)(a)?",opts:["No derating required for 4 conductors","4-6 conductors: 80% of ampacity; 7-9 conductors: 70%","4-6 conductors: 70%; 7-9 conductors: 50%","3-5 conductors: 80%; 6-8 conductors: 60%"],ans:1,ref:"NEC Table 310.15(B)(3)(a)",exp:"Standard derating table: 4-6 current-carrying conductors = 80%; 7-9 = 70%; 10-20 = 50%; 21-30 = 45%; 31-40 = 40%; 41+ = 35%. These factors account for mutual heating of multiple loaded conductors in the same raceway."},
{id:179,mod:5,cat:"Wiring",diff:"Medium",q:"Minimum burial depth for direct-buried conductors (without conduit) under residential property not subject to vehicle traffic?",opts:["12 inches","18 inches","24 inches","30 inches"],ans:2,ref:"NEC Table 300.5",exp:"Direct-buried conductors (not in conduit) require 24 inches of cover under general conditions. Reduced to 18 inches for most raceway applications and 6 inches for RMC. The 24-inch depth protects from routine digging like garden spading."},
{id:180,mod:5,cat:"Wiring",diff:"Hard",q:"What is required when conductors in a raceway have different temperatures on opposite ends (temperature differentials)?",opts:["Expansion fittings at the temperature boundary","Sealed with appropriate compound to prevent condensation and air flow through the raceway","Installed horizontally to prevent condensation drain","Made of PVC to handle thermal expansion"],ans:1,ref:"NEC 300.7(A)",exp:"Raceways between areas with significant temperature differences must be sealed to prevent warm moist air flowing toward the cold end where it condenses. Critical for California buildings crossing temperature-controlled boundaries."},
{id:181,mod:5,cat:"Wiring",diff:"Easy",q:"Main advantage of RMC over EMT?",opts:["RMC is easier to bend","RMC can be used in concrete, in fill, and in direct contact with earth — where EMT is not permitted","RMC conducts electricity better","RMC is less expensive"],ans:1,ref:"NEC 344.10 vs 358.12",exp:"RMC's thick galvanized steel walls allow direct earth contact, embedding in concrete, and use where subject to severe physical damage — all applications where EMT is prohibited. Tradeoff = higher cost and more difficult installation."},
{id:182,mod:5,cat:"Wiring",diff:"Hard",q:"How must PVC conduit cut ends be prepared before making connections?",opts:["Cut ends can be connected without preparation","Cut ends must be reamed and all burrs removed to prevent conductor insulation damage","PVC ends must be flame-polished to seal the cut edge","Only factory-cut ends may be used"],ans:1,ref:"NEC 352.28",exp:"After cutting PVC conduit, cut end must be reamed to remove burrs that could damage conductor insulation during pulling. Also true for metal conduits. Failing to ream is a primary cause of insulation damage during wire pulling."},
{id:183,mod:5,cat:"Wiring",diff:"Medium",q:"May MC cable armor serve as the equipment grounding conductor?",opts:["Always — metal armor provides a grounding path","Only when the armor is listed as a grounding means and proper listed connectors are used","Never — separate EGC always required","Only for circuits up to 20A"],ans:1,ref:"NEC 250.118(10)",exp:"MC cable armor may serve as EGC when the cable is listed for that purpose AND proper listed connectors are used. Some MC cable types require a separate EGC within the cable assembly. Always check listing information."},
{id:184,mod:5,cat:"Wiring",diff:"Medium",q:"Junction box covers must:",opts:["Be secured with screws and the box must remain accessible","Bond the box to the conduit with a grounding screw","Have a minimum of 10 cubic inches capacity","Be marked with the circuit number"],ans:0,ref:"NEC 314.28(C) & 314.29",exp:"Junction box covers must be secured AND the box must remain accessible — cannot be covered with building finishes without providing access. Boxes behind drywall with no access panel are code violations."},
{id:185,mod:5,cat:"Wiring",diff:"Medium",q:"In wet locations, EMT fittings must be:",opts:["Standard compression fittings are acceptable","Set-screw fittings if painted","Raintight or weatherproof fittings listed for wet locations","EMT not permitted in wet locations"],ans:0,ref:"NEC 358.42",exp:"In wet locations, EMT fittings must be raintight type listed for wet locations. Set-screw fittings are suitable for dry locations only. EMT itself is permitted in wet locations with appropriate raintight fittings."},
{id:186,mod:5,cat:"Wiring",diff:"Medium",q:"What type of cable is used for Type MC in healthcare facilities (patient care areas)?",opts:["Commercial buildings only","MC cable with full-size insulated neutral and EGC where permitted by Article 517","Residential applications only","Any application where NM cable is permitted"],ans:1,ref:"NEC Article 330",exp:"MC cable is widely used in commercial construction and can be used in healthcare facilities, patient care areas, and similar applications where metallic protection is required but rigid conduit would be impractical."},
{id:187,mod:5,cat:"Wiring",diff:"Hard",q:"Minimum trade size conduit permitted for connecting to luminaires (light fixtures)?",opts:["1/2 inch — smaller sizes not listed for branch circuit wiring","3/8 inch — may be used for short sections connecting to luminaires","1/4 inch FMC for 6 feet or less","1/2 inch is absolute minimum for all applications"],ans:1,ref:"NEC 348.20(A)(1) Exception",exp:"3/8-inch trade size flexible metal conduit is permitted for short sections (up to 6 feet) connecting to luminaires. For general wiring, 1/2-inch is the minimum. The 3/8-inch FMC exception is specific to fixture connections."},
{id:188,mod:5,cat:"Wiring",diff:"Medium",q:"NM cable in an unfinished basement that is exposed on the surface of joists must be:",opts:["Only if within 7 feet of the floor requires protection","Only if accessible from a floor below","Protected from physical damage when exposed","All exposed basement wiring must be in conduit"],ans:2,ref:"NEC 334.15",exp:"NM cable in unfinished basements must be protected from physical damage when exposed. Many inspectors require NM cable to run through drilled holes in joists rather than along surfaces to ensure protection."},
{id:189,mod:5,cat:"Wiring",diff:"Hard",q:"When multiple conduits run together in a parallel bank with little spacing — what applies?",opts:["Conduits must touch each other to save space","No spacing requirement for parallel conduits","For more than 3 current-carrying conductors in a bundle, ampacity adjustment factors apply","Only conduits carrying 200A+ require spacing"],ans:2,ref:"NEC Table 310.15(B)(3)(a)",exp:"When conductors are bundled or multiple conduits run closely together, mutual heating occurs. Table 310.15(B)(3)(a) derating applies when more than 3 current-carrying conductors are bundled. Significant for densely routed conduit banks."},
{id:190,mod:5,cat:"Wiring",diff:"Hard",q:"For derating purposes, which conductors are NOT current-carrying?",opts:["Neutral conductors are never current-carrying","When neutral carries only unbalanced load in 3-phase system, it is not counted as current-carrying","EGCs and certain neutral conductors are not current-carrying for derating purposes","All conductors in a raceway count for derating"],ans:2,ref:"NEC 310.15(B)(5)",exp:"For derating purposes: EGCs never count. A neutral carrying only unbalanced current in a 3-phase system is NOT counted. However, if the neutral carries significant harmonic currents (common with electronic loads), it DOES count. This nuance appears on advanced exam questions."},
{id:191,mod:5,cat:"Wiring",diff:"Easy",q:"Most commonly used conduit for exposed residential wiring in garages and basements?",opts:["PVC Schedule 80","EMT (Electrical Metallic Tubing)","RMC (Rigid Metal Conduit)","FMC (Flexible Metal Conduit)"],ans:1,ref:"NEC Article 358",exp:"EMT = most common conduit for exposed residential and light commercial wiring. Lightweight, easy to bend, good protection. Not rated for direct burial in earth, but excellent for exposed above-grade applications."},
{id:192,mod:5,cat:"Wiring",diff:"Hard",q:"NEC mandatory conductor color codes for 3-phase systems above 50V?",opts:["Phase A=black, B=red, C=blue; Neutral=white — required","Brown, orange, yellow for phases; gray for neutral — required","No mandatory color code for ungrounded conductors above 50V — only grounded and EGC conductors have mandatory colors","Red, black, and blue for phases is the only acceptable scheme"],ans:2,ref:"NEC 210.5(C)",exp:"NEC does NOT mandate specific color codes for ungrounded (hot) conductors above 50V. Grounded conductors must be white or gray; EGCs must be green. Industry uses black-red-blue (120/208V) and brown-orange-yellow (277/480V) as conventions, not code requirements."},
{id:193,mod:5,cat:"Wiring",diff:"Medium",q:"Type THWN-2 cable maximum ambient temperature rating?",opts:["60°C in dry locations only","75°C in wet locations only","90°C in both wet and dry locations","THWN-2 is only rated for dry at 75°C"],ans:2,ref:"NEC Table 310.4",exp:"THWN-2 = 90°C in BOTH wet and dry locations. Regular THWN = 75°C wet, 90°C dry. THHN = 90°C dry only. For conductors in wet locations, THWN or THWN-2 required. Temperature rating determines which Table 310.16 column to use."},
{id:194,mod:5,cat:"Wiring",diff:"Medium",q:"Reducing washers when installing conduit into a knockout serve to:",opts:["Reduce the conduit trade size at entry","Fill the gap between an oversized knockout and smaller conduit — maintaining enclosure integrity AND providing grounding bond","Only provide the grounding bond","Only fill the gap"],ans:1,ref:"NEC 250.97 & 314.21",exp:"Reducing washer fills space between oversized knockout and smaller conduit, maintaining box enclosure AND contributing to the grounding bond between conduit and box. Wrong-size conduit in knockout without reducing washer fails both enclosure integrity and grounding."},
{id:195,mod:5,cat:"Wiring",diff:"Hard",q:"What minimum conduit trade size is permitted for general wiring in NEC?",opts:["1/2 inch — smaller sizes not listed for branch circuit wiring","3/8 inch FMC may be used for short sections connecting to luminaires","1/4 inch FMC permitted for 6 feet or less","1/2 inch is absolute minimum for all applications"],ans:1,ref:"NEC 348.20(A)(1)",exp:"For general wiring, 1/2-inch is the minimum. However, 3/8-inch FMC is permitted for limited applications — short sections up to 6 feet connecting to luminaires. The 3/8-inch exception is specific."},
{id:196,mod:5,cat:"Wiring",diff:"Hard",q:"Conduit body (LB, LL, LR, T-body) may be used for splices when:",opts:["Conduit bodies may always be used for splices","Only when the cubic inch capacity is marked and adequate AND the body is listed for that use","Conduit bodies shall not be used as junction boxes — only pull boxes","Splices are never permitted in conduit bodies"],ans:1,ref:"NEC 314.16(C)(2)",exp:"Conduit bodies may only be used for splices when listed for that use AND marked with fill capacity in cubic inches. If not marked for splicing, may only be used as a pull point. Most standard conduit bodies are NOT listed for splicing."},
{id:197,mod:5,cat:"Wiring",diff:"Medium",q:"Support interval for 1-inch PVC conduit?",opts:["Every 3 feet","Every 5 feet — within 3 feet of boxes","Every 6 feet — within 3 feet of boxes","Every 10 feet for all PVC sizes"],ans:0,ref:"NEC Table 352.30(B)",exp:"PVC conduit support intervals vary by trade size. 1/2-inch to 1-inch PVC must be supported every 3 feet. Larger sizes allow longer spacing. PVC is less rigid than metal conduit and requires more frequent support to prevent sagging."},
{id:198,mod:5,cat:"Wiring",diff:"Hard",q:"Pull boxes for conductors 4 AWG and larger must:",opts:["Be larger than the standard junction box — minimum size required by code","Be large enough to permit the minimum conductor bending radius based on conduit sizes entering the box","Only be required when more than three conduits enter the box","No size requirements — any accessible box qualifies"],ans:1,ref:"NEC 314.28(A)",exp:"Pull boxes for conductors 4 AWG+ must meet specific dimension requirements based on conduit sizes entering the box. The minimum dimensions ensure conductors aren't bent too sharply, which would damage insulation."},
{id:199,mod:5,cat:"Wiring",diff:"Medium",q:"Cable trays in industrial facilities — permitted materials?",opts:["Steel only","Aluminum or steel only","Fiberglass or metallic materials as approved","Any listed material including non-metallic"],ans:3,ref:"NEC 392.10(A)",exp:"Cable trays may be metal (steel, aluminum, stainless steel) or non-metallic (fiberglass) as long as listed for the application. Fiberglass cable trays are common in corrosive environments like chemical plants."},
{id:200,mod:5,cat:"Wiring",diff:"Hard",q:"12 current-carrying conductors in a conduit — what derating factor applies?",opts:["80% (4-6 conductors)","70% (7-9 conductors)","50% (10-20 conductors)","35% (21-30 conductors)"],ans:2,ref:"NEC Table 310.15(B)(3)(a)",exp:"Per Table 310.15(B)(3)(a): 10-20 current-carrying conductors = 50% adjustment factor. Conductor normally rated 30A must be derated to 30 × 0.50 = 15A. Severe derating for many conductors reflects substantial mutual heating."},
{id:201,mod:5,cat:"Wiring",diff:"Medium",q:"For corrosive industrial environments, recommended conduit type?",opts:["Standard galvanized EMT","PVC Schedule 80 or stainless steel RMC","Flexible metal conduit (FMC)","Aluminum conduit preferred for corrosive environments"],ans:1,ref:"NEC 352.10 & 344.10",exp:"PVC Schedule 80 or stainless steel RMC for corrosive industrial environments. Standard galvanized steel and aluminum conduit corrode in chemical atmospheres. In California food processing facilities, stainless steel conduit is often specified."},
{id:202,mod:5,cat:"Wiring",diff:"Hard",q:"Maximum length of LFNC (Liquidtight Flexible Nonmetallic Conduit) for a single connection?",opts:["3 feet","6 feet","12 feet","No length restriction"],ans:1,ref:"NEC 356.60",exp:"LFNC maximum = 6 feet for general use. Beyond 6 feet, a rigid conduit system should be used. The 6-foot limit prevents LFNC from substituting for permanent raceway installations."},
{id:203,mod:5,cat:"Wiring",diff:"Medium",q:"LFMC maximum length to serve as EGC?",opts:["3 feet","6 feet","10 feet","25 feet"],ans:1,ref:"NEC 250.118(6)",exp:"LFMC as EGC: same 6-foot maximum rule as FMC for circuits up to 20A. Beyond 6 feet, a separate EGC is required. Longer flexible conduit has too much impedance for reliable fault current flow."},
{id:204,mod:5,cat:"Wiring",diff:"Medium",q:"When bundling conductors for derating, which conductors are counted as current-carrying?",opts:["All conductors count","EGCs never count; neutrals may or may not count depending on loading conditions","Only phase conductors count — neutrals are never current-carrying","Only conductors over 10 AWG need to be counted"],ans:1,ref:"NEC 310.15(B)(5)",exp:"EGCs never count for derating. Neutral conductors: count when carrying unbalanced current in single-phase systems; may not count in balanced 3-phase systems with linear loads. Neutrals in systems with non-linear loads (harmonics) DO count."},
{id:205,mod:5,cat:"Wiring",diff:"Hard",q:"Maximum ambient temperature rating for standard THWN (not THWN-2) in a wet location?",opts:["60°C in wet locations","75°C in wet locations","90°C in both wet and dry locations","THWN is only rated for dry locations at 75°C"],ans:1,ref:"NEC Table 310.4",exp:"THWN (not -2): 75°C in wet locations; 90°C in dry locations. THWN-2: 90°C in both wet and dry locations. For wet locations requiring 90°C ampacity, THWN-2 is required. Know the insulation type designations and their ratings."},
// MODULE 6: EQUIPMENT GENERAL USE (35)
{id:206,mod:6,cat:"Equipment General Use",diff:"Easy",q:"Which is a permitted use of flexible cord?",opts:["Running cord through a wall between rooms","Permanently supplying a ceiling fan","Connecting portable appliances that are frequently moved","Using cord as feeder between two panels"],ans:2,ref:"NEC 400.7 & 400.8",exp:"Portable appliances frequently moved = primary permitted use of flexible cord. Cord cannot substitute for fixed wiring — cannot be concealed in walls, passed through holes in walls, or used as permanent wiring."},
{id:207,mod:6,cat:"Equipment General Use",diff:"Medium",q:"A luminaire in a clothes closet must maintain what clearance from storage areas?",opts:["6 inches for fluorescent; 12 inches for incandescent with enclosed lamp","3 inches","18 inches","24 inches"],ans:0,ref:"NEC 410.16(A) & (B)",exp:"Incandescent and LED with enclosed lamp = 12 inches clearance. Surface-mounted fluorescent or LED without exposed lamp = 6 inches. Pendant and track luminaires prohibited in clothes closets."},
{id:208,mod:6,cat:"Equipment General Use",diff:"Easy",q:"What box is required to support a ceiling fan?",opts:["Any listed 4-inch octagonal box rated 35 lbs","A box specifically listed for ceiling fan support","Standard lighting box with fan brace","Any metallic box attached directly to joists"],ans:1,ref:"NEC 314.27(C)",exp:"Ceiling fans must be supported by a box specifically listed for fan support. Standard lighting boxes cannot handle dynamic loads (vibration, rotation, lateral movement) of a ceiling fan. Required by listing, not just weight rating."},
{id:209,mod:6,cat:"Equipment General Use",diff:"Medium",q:"Running an extension cord permanently through a doorway to supply a freezer on a porch is:",opts:["Acceptable — extension cords are safe up to 12 feet","Prohibited — permanent use of extension cords through building elements","Acceptable if the cord is rated for outdoor use","Requires only GFCI protection to be acceptable"],ans:1,ref:"NEC 400.8(5)",exp:"Running extension cords permanently through doorways, windows, or similar openings is prohibited. Extension cords are for temporary, portable use. Permanent routing creates wear and shock hazards."},
{id:210,mod:6,cat:"Equipment General Use",diff:"Medium",q:"The switch controlling a bathroom fan-heater combination must be:",opts:["A standard single-pole switch","A double-pole switch","Listed for the specific heater load and voltage","A timer switch"],ans:2,ref:"NEC 424.19 & 404.14(A)",exp:"Switches controlling bathroom heating devices must be listed for the specific load. Fan-heater combinations with heating elements require switches rated for the heater's current and voltage. Using an under-rated switch can cause switch failure or fire."},
{id:211,mod:6,cat:"Equipment General Use",diff:"Hard",q:"Maximum cord length for a cord-supported pendant luminaire without supplemental support?",opts:["3 feet","No maximum — limited by the listing","6 feet of cord maximum without additional support","10 feet for pendants over 50 watts"],ans:2,ref:"NEC 410.36(G)",exp:"Cord-connected pendant luminaires must not have more than 6 feet of cord from the box unless supplemental support is provided. The cord must be suitable for the purpose and the luminaire weight must not exceed cord rating."},
{id:212,mod:6,cat:"Equipment General Use",diff:"Medium",q:"A switch controlling a fluorescent lighting circuit at 120V must be rated:",opts:["Standard AC general-use snap switch is sufficient","SWD (Switching Duty) rated switch or breaker","A 277V rated switch must be used for any fluorescent circuit","No specific switch rating required for fluorescent"],ans:1,ref:"NEC 404.14(B)(1)",exp:"Switches controlling fluorescent lighting loads must be rated SWD (Switching Duty). Standard AC switches are not rated for the repetitive switching cycles with fluorescent lighting. SWD rating ensures the switch can handle inductive switching stress."},
{id:213,mod:6,cat:"Equipment General Use",diff:"Easy",q:"A freestanding electric range in a dwelling may be:",opts:["Permanently hardwired only — cord-and-plug prohibited","Cord-and-plug connected using a 4-wire range cord","Cord-and-plug with a 3-wire cord for older outlet compatibility","Hardwired with 8 AWG minimum"],ans:1,ref:"NEC 422.16(B)(3)",exp:"Electric ranges may be cord-and-plug connected using a 4-wire range cord (in new installations). The four wires: hot, hot, neutral, and EGC. New installations since 1996 require 4-wire cords. Old 3-wire connections in existing dwellings may remain."},
{id:214,mod:6,cat:"Equipment General Use",diff:"Hard",q:"Table 220.55 demand factors for household electric ranges — for one range rated 11 kW?",opts:["11,000 VA at 100%","8,000 VA per NEC Table 220.55","11,000 × 80% = 8,800 VA","Column C for one range: 8,000 VA"],ans:3,ref:"NEC Table 220.55",exp:"For one household range 8¾ kW to 12 kW, Table 220.55 Column C = 8,000 VA demand. The actual 11 kW nameplate is irrelevant — the table value governs. For ranges over 12 kW, add 5% per kW above 12 kW to the 8 kW base."},
{id:215,mod:6,cat:"Equipment General Use",diff:"Medium",q:"Disconnecting means for a dwelling unit 240V central A/C must be:",opts:["Panel breaker is sufficient — no additional disconnect","Within sight of and accessible from the equipment","Lockable disconnect at equipment regardless of sight distance","Only required if unit is more than 50 feet from panel"],ans:1,ref:"NEC 440.14",exp:"Readily accessible disconnecting means within sight of air conditioning and heat pump equipment. 'Within sight' = visible and within 50 feet. May be a fusible switch, non-fused disconnect, or circuit breaker."},
{id:216,mod:6,cat:"Equipment General Use",diff:"Medium",q:"Electric space heaters in bathrooms must be:",opts:["GFCI protected","Permanently installed — cord-and-plug connected heaters prohibited in bathrooms","Permanently installed and maximum 1,500 watts","Approved for wet locations"],ans:1,ref:"NEC 424.16 & 424.58",exp:"Electric space heaters in bathrooms must be permanently installed — cord-and-plug connected space heaters are prohibited in bathrooms. Prevents dangerous use of moveable electric heaters near water."},
{id:217,mod:6,cat:"Equipment General Use",diff:"Hard",q:"Luminaires in bathtub or shower zones must be:",opts:["No special protection if mounted on the ceiling","Listed and marked suitable for the zone — wet locations within tub/shower space require wet-location listing","A GFCI circuit is required but fixture needs no special rating","AFCI protected"],ans:1,ref:"NEC 410.10(D)",exp:"Luminaires in zone 1 (inside tub or shower) must be listed and marked suitable for wet locations. Zone 2 (immediately outside tub) requires damp-location listing. Using a standard dry-rated fixture in a shower is dangerous."},
{id:218,mod:6,cat:"Equipment General Use",diff:"Easy",q:"The maximum overcurrent protection for a panelboard is:",opts:["The panelboard overcurrent protection may not exceed the panelboard bus rating","Total of all branch circuit breakers cannot exceed the bus rating","A 200A panel may have no more than a 200A main breaker","The feeder OCPD must not exceed the panelboard's bus bar rating"],ans:3,ref:"NEC 408.36",exp:"Overcurrent device protecting a panelboard feeder must not exceed the rating of the panelboard's bus bar. Protects bus bars from overload. Exception: main lugs only panels protected by the building's service OCPD."},
{id:219,mod:6,cat:"Equipment General Use",diff:"Medium",q:"Maximum cord length for a household garbage disposal?",opts:["18 inches","2 feet","3 feet","4 feet"],ans:2,ref:"NEC 422.16(B)(1)",exp:"Garbage disposals: maximum 3-foot cord length. Must be connected to a 20A, 120V individual branch circuit. 3-foot limit keeps cord under the sink and prevents hazards."},
{id:220,mod:6,cat:"Equipment General Use",diff:"Medium",q:"A single GFCI outlet can protect multiple bathroom receptacles through:",opts:["Only one GFCI per circuit — additional protection not possible","The load-side terminals of the GFCI outlet","A dedicated panel GFCI breaker only","Multiple GFCIs must be installed — one per outlet"],ans:1,ref:"NEC 406.4(D)(2)",exp:"A single GFCI outlet or GFCI breaker can protect multiple downstream outlets through the load-side connections. One GFCI at the first outlet can protect additional bathroom outlets in the same bathroom. Economical and common practice."},
{id:221,mod:6,cat:"Equipment General Use",diff:"Hard",q:"IC-rated versus non-IC recessed luminaires in an attic:",opts:["No clearance required for modern LED recessed fixtures","3 inches minimum from all sides if rated IC","IC-rated fixtures may have insulation against them; non-IC fixtures must maintain clearance","At least 6 inches from all insulation"],ans:2,ref:"NEC 410.116(B)",exp:"IC-rated (Insulation Contact) recessed fixtures: insulation may be placed directly against them. Non-IC rated fixtures: must maintain clearance from insulation per their listing. Using a non-IC fixture covered with insulation is a fire hazard."},
{id:222,mod:6,cat:"Equipment General Use",diff:"Medium",q:"HVAC equipment nameplates specify MCA and MOCP. What do these values determine?",opts:["MCA = motor current; MOCP = motor overload protection","MCA = minimum circuit ampacity (conductor size); MOCP = maximum overcurrent protection (breaker/fuse size)","MCA = minimum current allowed; MOCP = maximum operating current permitted","Both values are advisory only — use 125% FLA for all HVAC sizing"],ans:1,ref:"NEC 440.4(B) & 440.22",exp:"MCA (Minimum Circuit Ampacity) determines conductor sizing. MOCP (Maximum Overcurrent Protection) determines maximum breaker or fuse size. The MOCP on the nameplate governs — not a percentage calculation. Never exceed the MOCP rating."},
{id:223,mod:6,cat:"Equipment General Use",diff:"Medium",q:"Portable space heaters are continuous loads. A 1,500W, 120V heater draws how much current?",opts:["10 amperes","12.5 amperes","15 amperes","20 amperes"],ans:1,ref:"NEC Article 100 & 210.20(A)",exp:"1,500W ÷ 120V = 12.5A. On a 15A circuit, 80% continuous limit = 12A. 12.5A exceeds 12A continuous limit — technically requires a 20A circuit. In practice, this is why dedicated circuits for space heaters prevent tripped breakers."},
{id:224,mod:6,cat:"Equipment General Use",diff:"Easy",q:"'Listed' electrical equipment means:",opts:["Approved by local building department","Included in a published list from an organization like UL or ETL that verified it meets applicable standards","Recommended by the manufacturer","Certified by the installing electrician"],ans:1,ref:"NEC Article 100",exp:"Listed = appears in a published list from a recognized testing lab (UL, ETL, CSA, etc.) confirming the product meets applicable safety standards. The listing mark on products indicates testing. NEC generally requires listed equipment throughout."},
{id:225,mod:6,cat:"Equipment General Use",diff:"Medium",q:"A 120V, 20A appliance circuit supplies a countertop microwave rated 1,500 watts. Is this code compliant?",opts:["Yes — 12.5A is under 15A and well within the 20A circuit","Not unless microwave is connected to a dedicated 20A circuit","Microwaves are not continuous loads — appliance cycles on and off","Microwave requires a 30A circuit due to startup current"],ans:0,ref:"NEC 210.20(A)",exp:"1,500W ÷ 120V = 12.5A. On a 20A circuit, continuous load limit = 16A (80%). Microwaves generally are NOT continuous loads (don't run 3+ hours). 12.5A on a 20A circuit is code compliant. "},
{id:226,mod:6,cat:"Equipment General Use",diff:"Hard",q:"Minimum clearance between cooking surface and bottom of overhead combustible cabinet?",opts:["18 inches","24 inches","30 inches","No NEC requirement — kitchen design standards govern"],ans:2,ref:"NEC 410.10(C)",exp:"30 inches minimum between cooking surface and bottom of combustible overhead cabinets. Prevents fires from range-top cooking. Kitchen vent hoods also need specific clearances from the cooking surface."},
{id:227,mod:6,cat:"Equipment General Use",diff:"Hard",q:"Box fill calculation for a single-gang box with single-pole switch, 4 conductors of 14 AWG, one EGC?",opts:["12 cubic inches","14 cubic inches","18 cubic inches","Box fill depends on connections, not conductor count"],ans:1,ref:"NEC 314.16(B)",exp:"Box fill: 4 conductors × 2.0 (14 AWG) = 8.0 cu in + device (2 conductors = 4.0 cu in) + EGC group (1 × 2.0 = 2.0 cu in) = 14.0 cu in minimum. Standard 2×4×1.875 device boxes are 13.5 cu in — this installation needs a deeper box."},
{id:228,mod:6,cat:"Equipment General Use",diff:"Medium",q:"Maximum ampere rating for a standard household receptacle outlet?",opts:["15 amperes","20 amperes","30 amperes","No maximum — match circuit rating"],ans:1,ref:"NEC 406.3",exp:"Standard household receptacles are rated 15A or 20A. A 15A receptacle may be used on a 20A circuit. 30A and 50A receptacles are for large appliances but are not 'standard household' receptacles."},
{id:229,mod:6,cat:"Equipment General Use",diff:"Hard",q:"When replacing a non-grounding (2-prong) outlet on a circuit without an EGC, the NEC permits:",opts:["Must replace with grounding-type outlet — no exceptions","Replace with another non-grounding type; replace with a GFCI receptacle marked 'No Equipment Ground'; or install grounding-type if a grounding path is provided","Circuit must be rewired before any outlet replacement","Only licensed electricians may work on circuits without EGC"],ans:1,ref:"NEC 406.4(D)(2)",exp:"Three options for replacing non-grounding outlet: (1) Another non-grounding outlet, (2) GFCI outlet marked 'No Equipment Ground,' (3) Grounding-type outlet if a grounding path is provided. Option 2 (GFCI) is most practical in old homes."},
{id:230,mod:6,cat:"Equipment General Use",diff:"Medium",q:"New clothes dryer installation requires which type of outlet?",opts:["3-wire, 30A, 240V outlet (NEMA 10-30)","4-wire, 30A, 240V outlet (NEMA 14-30)","2-wire plus ground, 240V receptacle","50A, 240V outlet (NEMA 6-50)"],ans:1,ref:"NEC 250.140 & 406.9",exp:"New installations require 4-wire (hot, hot, neutral, ground) 30-ampere, 240V NEMA 14-30 outlet for clothes dryers. The separate grounding wire (4th wire) was required for new installations after 1996. Existing 3-wire installations may remain."},
{id:231,mod:6,cat:"Equipment General Use",diff:"Medium",q:"Every circuit in a panelboard must be identified by a circuit directory showing:",opts:["Only circuit numbers","Circuit numbers and ampere ratings only","The purpose or load description for each circuit, clearly identified","Circuit numbers and installation date"],ans:2,ref:"NEC 408.4(A)",exp:"Every circuit must be identified on the circuit directory inside the panel door with the purpose or load for each circuit. Vague labels like 'circuit 1' or 'bedroom' are insufficient — specific identification required."},
{id:232,mod:6,cat:"Equipment General Use",diff:"Medium",q:"Snap switches (standard wall switches) must have 'snap action' for what reason?",opts:["Make positive, fast-acting contact to prevent arcing at the contacts","Must be self-locking in both on and off positions","Must be spring-loaded to prevent accidental operation","Ensures the switch can be operated with one hand"],ans:0,ref:"NEC 404.13",exp:"Snap switches must make contact quickly with positive snap action. Slow-making switches allow arc formation at contacts during switching, which erodes contacts and can cause fires. Positive snap-action minimizes arcing duration."},
{id:233,mod:6,cat:"Equipment General Use",diff:"Easy",q:"Outlet box for a ceiling fan must be:",opts:["Not required — the listing of the box provides the information","Marked with its maximum fan weight rating","Labeled 'Fan Only' to prevent light fixture installation","Stamped with the fan manufacturer's name"],ans:1,ref:"NEC 314.27(C)",exp:"Outlet boxes listed for fan support must be marked with their maximum fan weight rating. This allows installers and inspectors to verify the installed fan doesn't exceed the box's rated capacity."},
{id:234,mod:6,cat:"Equipment General Use",diff:"Medium",q:"Luminaires in wet locations must be listed as:",opts:["Damp locations only","Suitable for wet locations","Wet-location fixtures required only within 3 feet of water source","Only UL-listed fixtures permitted in wet locations"],ans:1,ref:"NEC 410.10(A)",exp:"Luminaires in wet locations must be listed and marked as suitable for wet locations. Wet locations include: exposed to weather, embedded in masonry, exposed to water spray. 'Damp location' ratings insufficient for wet locations."},
{id:235,mod:6,cat:"Equipment General Use",diff:"Hard",q:"A 120V, 20A GFCI circuit supplies a bathroom with a 1,800-watt load. Compliant?",opts:["No — bathroom circuits limited to 1,500 watts","Yes — 1,800W ÷ 120V = 15A, within 80% (1,920 VA) continuous limit","Yes — as long as load is not continuous","No — bathroom circuits may not exceed 1,440 watts"],ans:1,ref:"NEC 210.20(A) & 210.11(C)(3)",exp:"1,800W ÷ 120V = 15A. On a 20A circuit, continuous limit = 16A (80% × 20A). If load is non-continuous, can use full 20A. If continuous (3+ hours), 15A < 16A continuous limit = compliant. 80% rule only restricts CONTINUOUS loads."},
{id:236,mod:6,cat:"Equipment General Use",diff:"Hard",q:"Type THHN cable temperature rating:",opts:["75°C in both wet and dry locations","75°C dry; 60°C wet","90°C in dry locations only","90°C in both wet and dry locations"],ans:2,ref:"NEC Table 310.4",exp:"THHN = 90°C in dry locations ONLY. For wet locations, THWN (75°C wet, 90°C dry) or THWN-2 (90°C wet and dry) must be used. Many conduit installations use THWN or dual-rated THHN/THWN-2 conductors to cover all installation environments."},
{id:237,mod:6,cat:"Equipment General Use",diff:"Medium",q:"A 1,500W continuous-load heating unit at 120V on a 15A circuit — compliant?",opts:["Yes — 1,500W ÷ 120V = 12.5A, within circuit rating","Not for continuous loads — 15A × 80% = 12A max continuous; 12.5A exceeds this","Yes, because 1,500W heaters are exempt from continuous load rules","Yes — heating loads are not classified as continuous"],ans:1,ref:"NEC 210.20(A)",exp:"1,500W ÷ 120V = 12.5A. Continuous load limit on 15A circuit = 15A × 80% = 12A. 12.5A > 12A = NOT compliant on a 15A circuit. A 20A circuit (80% = 16A) properly handles the 12.5A continuous heating load."},
{id:238,mod:6,cat:"Equipment General Use",diff:"Medium",q:"Cord-and-plug connected electric water heater?",opts:["May be cord-and-plug connected if listed for this purpose","Residential water heaters must be permanently hardwired — cord-and-plug prohibited","240V water heaters may use a 30A dryer cord","Only tankless heaters may be cord-and-plug"],ans:0,ref:"NEC 422.16(B)",exp:"Some small point-of-use water heaters are listed for cord-and-plug connection. Standard tank-type water heaters must be permanently connected. The listing determines what's permitted. Always follow equipment listing and manufacturer's installation instructions."},
{id:239,mod:6,cat:"Equipment General Use",diff:"Easy",q:"The minimum illumination level for electrical equipment working spaces per NEC?",opts:["50 foot-candles","The NEC requires lighting be provided but does not specify foot-candle levels","25 foot-candles at the equipment face","Illumination is optional — good practice but not required"],ans:1,ref:"NEC 110.26(D)",exp:"NEC requires illumination for working spaces about electrical equipment including service equipment, switchboards, panelboards, and MCCs. The NEC requires the lighting but doesn't specify foot-candle levels."},
{id:240,mod:6,cat:"Equipment General Use",diff:"Hard",q:"When a motor controller is to also serve as the disconnecting means, it must:",opts:["All motor controllers serve as disconnecting means","Be listed and rated for the purpose — not all controllers qualify as disconnects","A contactor-type controller always qualifies","Only manually operated controllers qualify"],ans:1,ref:"NEC 430.111",exp:"Not all motor controllers qualify as disconnecting means. A controller used as a disconnect must be listed and rated for the purpose, including being rated for horsepower and capable of opening under motor running current. Many contactors are NOT rated for use as disconnects."},
// MODULE 7: SPECIAL OCCUPANCIES (30)
{id:241,mod:7,cat:"Special Occupancies",diff:"Easy",q:"Class I, Division 1 hazardous locations contain:",opts:["Combustible dust that can cause fires","Flammable gases or vapors present continuously or intermittently under normal operating conditions","Flammable gases present only under abnormal conditions","Easily ignitable fibers"],ans:1,ref:"NEC 500.5(B)(1)",exp:"Class I, Division 1 = flammable gases/vapors NORMALLY present. Division 2 = only present under abnormal conditions. Class I equipment must be explosion-proof for the specific gas group."},
{id:242,mod:7,cat:"Special Occupancies",diff:"Easy",q:"Class II hazardous locations involve:",opts:["Flammable gases","Combustible dust","Easily ignitable fibers","Flammable liquids only"],ans:1,ref:"NEC 500.5(C)",exp:"Class II = combustible dust hazards. Examples: grain elevators, flour mills, coal handling, certain manufacturing. Dust clouds can explode with extreme violence."},
{id:243,mod:7,cat:"Special Occupancies",diff:"Medium",q:"Equipment in Class I, Division 1 locations must be:",opts:["GFCI protected","Explosion-proof and rated for the specific gas group and temperature class","Simply weatherproof","Any listed equipment is acceptable"],ans:1,ref:"NEC 501.5",exp:"Class I, Division 1 equipment must be explosion-proof AND rated for: (1) the specific hazardous gas group (A through D), and (2) the temperature class (T1 through T6). Wrong group or temperature class = fire hazard."},
{id:244,mod:7,cat:"Special Occupancies",diff:"Hard",q:"Which gas requires the most restrictive equipment rating in Class I hazardous locations?",opts:["Propane (Group D)","Hydrogen (Group B)","Acetylene (Group A)","Natural gas (Group D)"],ans:2,ref:"NEC Table 500.8(C)(1)",exp:"Group A (acetylene) requires the most restrictive equipment — acetylene is extremely explosive. Group B = hydrogen, manufactured gas. Group C = ethylene, cyclopropane. Group D = propane, gasoline, natural gas. Group A equipment will be rated for any Group."},
{id:245,mod:7,cat:"Special Occupancies",diff:"Medium",q:"Conduit seals in Class I hazardous locations are required:",opts:["Only at conduit entry to motors","Within 18 inches of each enclosure and at boundaries between classified and unclassified areas","Only for conduit runs over 100 feet","Seals required only in Division 1 — not Division 2"],ans:1,ref:"NEC 501.15",exp:"Conduit seals: within 18 inches of each enclosure entry AND at every boundary between classified and unclassified areas. Prevents flammable vapors from traveling through conduit to non-classified areas where they could ignite."},
{id:246,mod:7,cat:"Special Occupancies",diff:"Medium",q:"Commercial garages for vehicle service are classified as:",opts:["Unclassified — ventilation prevents hazardous atmosphere","Class I, Division 2 within 18 inches of the floor and up to 18 inches from doors/vents","Class I, Division 1 throughout","Class II due to tire dust"],ans:1,ref:"NEC 511.3",exp:"Commercial garages: Class I, Division 2 within 18 inches of the floor (gasoline vapors settle at low levels), and within 18 inches of dispenser openings. Above 18 inches from floor is unclassified with adequate ventilation."},
{id:247,mod:7,cat:"Special Occupancies",diff:"Hard",q:"Article 505 Zone Classification System is an alternative to Division classification. Zone 0 corresponds approximately to:",opts:["Division 2","Division 1","Division 1 with continuous hazard presence","Division 1 where hazardous atmosphere is continuously present"],ans:3,ref:"NEC 505.5(A)",exp:"Zone 0 = flammable atmosphere continuously present (more restrictive than Division 1). Zone 1 ≈ Division 1. Zone 2 ≈ Division 2. Zone system is international standard (IEC); Division system is North American standard."},
{id:248,mod:7,cat:"Special Occupancies",diff:"Medium",q:"A gasoline dispensing station — what is the hazardous zone classification within 20 feet of a dispenser?",opts:["Unclassified with ventilation","Class I, Division 2 within 20 feet horizontal radius of dispenser and to 18 inches above grade","Class I, Division 1 at all dispensers","No hazardous classification for outdoor dispensers"],ans:1,ref:"NEC 514.3 & Table 514.3(B)(1)",exp:"Gas stations: Class I, Division 2 within 20 feet horizontal radius of each dispenser and within 18 inches above grade. Above 18 inches and beyond 20 feet horizontal = unclassified. Dispensers themselves and areas immediately around them are more restrictive."},
{id:249,mod:7,cat:"Special Occupancies",diff:"Hard",q:"In healthcare patient care areas (Article 517), what special wiring is required?",opts:["Standard commercial wiring is acceptable in all patient care areas","Isolated power systems or GFCI protection plus equipotential bonding for invasive procedure rooms","Only Class 2 low-voltage circuits permitted near patients","GFCI protection for all circuits in patient care areas"],ans:1,ref:"NEC 517.160 & 517.20",exp:"Healthcare critical care areas with invasive procedures require isolated power systems OR GFCI plus equipotential bonding. Isolated power prevents ground faults from interrupting life support. Equipotential bonding minimizes voltage between exposed conductive surfaces."},
{id:250,mod:7,cat:"Special Occupancies",diff:"Easy",q:"Temporary construction wiring (Article 590) requires:",opts:["Permanent wiring methods","GFCI protection for all receptacles — no time limit on temporary wiring during construction","Temporary wiring must be removed within 90 days","Only conduit is acceptable for construction sites"],ans:1,ref:"NEC 590.6(A)",exp:"Construction sites: GFCI protection required for all 125V, 15 and 20A receptacle outlets. Cable assemblies may be used without boxes for temporary wiring. No 90-day limit during construction — temporary wiring stays for the project duration."},
{id:251,mod:7,cat:"Special Occupancies",diff:"Easy",q:"Holiday lighting and decorative displays under Article 590 have what time limit?",opts:["No time limit — decorative lighting is not covered by Article 590","90 days — temporary wiring must be removed after 90 days for non-construction purposes","No limit for lighting on the exterior only","Limited only by the duration of the permit"],ans:1,ref:"NEC 590.3(B)",exp:"Non-construction temporary wiring (including holiday lighting): maximum 90 days. Construction temporary wiring has no time limit. After 90 days, holiday lighting must either be removed or converted to permanent wiring methods."},
{id:252,mod:7,cat:"Special Occupancies",diff:"Hard",q:"Class II, Group E dust (conductive metal dust) requires what level of protection?",opts:["Class II, Division 2 equipment only","Explosion-proof equipment (same as Class I equipment) because metal dust is electrically conductive","Standard dust-tight enclosures","Metal dust areas are unclassified if below the explosion concentration"],ans:1,ref:"NEC 502.5 & Table 500.6(B)(1)",exp:"Group E = conductive metal dusts (magnesium, aluminum, etc.). These require the most stringent Class II protection — explosion-proof equipment. Conductive dust can penetrate enclosures and create electrical faults in addition to explosion hazard."},
{id:253,mod:7,cat:"Special Occupancies",diff:"Medium",q:"Intrinsically safe wiring systems are grounded according to:",opts:["Standard NEC grounding rules","A specific control drawing from the equipment manufacturer that may require special grounding arrangements","Earth grounding only — no connection to building ground","Intrinsically safe systems don't require grounding"],ans:1,ref:"NEC 504.60",exp:"Intrinsically safe systems must be installed per the manufacturer's control drawing, which specifies the exact grounding requirements. Standard grounding methods may not apply — the control drawing governs the entire installation."},
{id:254,mod:7,cat:"Special Occupancies",diff:"Easy",q:"Which NEC article covers healthcare facilities?",opts:["Article 500","Article 505","Article 517","Article 700"],ans:2,ref:"NEC Article 517",exp:"Article 517 = healthcare facilities: hospitals, nursing homes, limited care facilities, clinics. Covers essential electrical systems, patient care areas, wet procedure locations, and life safety circuits."},
{id:255,mod:7,cat:"Special Occupancies",diff:"Medium",q:"Marina receptacles (Article 553) require GFCI protection because:",opts:["Marina electrical systems are outdoors","Electric shock drowning hazard — stray current in water can paralyze swimmers","Marine environments are wet locations","Marina circuits supply 30A and 50A loads"],ans:1,ref:"NEC 553.10",exp:"Electric shock drowning (ESD) is a specific hazard in marinas — AC current leaking into water can paralyze swimmers within 30 feet. GFCI protection for all 125V 15 and 20A receptacles in marinas is a life-safety requirement."},
{id:256,mod:7,cat:"Special Occupancies",diff:"Hard",q:"Agricultural buildings (Article 547) require special wiring because:",opts:["High voltage equipment is used","Moisture, dust, and corrosive gases from animal waste damage standard equipment","Agricultural buildings always have hazardous gas classifications","Only commercial-grade equipment is permitted"],ans:1,ref:"NEC 547.5",exp:"Agricultural buildings present moisture, dust/debris, and corrosive gases from animal waste that damage standard electrical equipment rapidly. Article 547 requires moisture-resistant, dust-tight enclosures and corrosion-resistant wiring methods."},
{id:257,mod:7,cat:"Special Occupancies",diff:"Medium",q:"Electrical equipment inside a spray paint booth must be:",opts:["Standard commercial equipment with ventilation","Explosion-proof or otherwise approved for Class I, Division 1 locations","Only GFCI protection required","No special equipment required if spraying is intermittent"],ans:1,ref:"NEC 516.10(A)",exp:"Spray paint booths = Class I, Division 1 (flammable solvents normally present). All electrical equipment inside the booth must be explosion-proof rated for the specific solvent group. Ventilation reduces but doesn't eliminate the hazard classification."},
{id:258,mod:7,cat:"Special Occupancies",diff:"Medium",q:"RV park (Article 551) electrical service at each site must provide at minimum:",opts:["15A, 120V outlet is sufficient","At least one 20A, 125V receptacle and one 30A or 50A, 125/250V receptacle","50A, 125/250V only","20A, 120V and 30A outlets per site minimum"],ans:1,ref:"NEC 551.71(A) & (B)",exp:"RV parks: each site needs minimum one 20A, 125V receptacle. Sites designed for larger RVs also need 30A or 50A receptacles. GFCI protection required for outdoor receptacles."},
{id:259,mod:7,cat:"Special Occupancies",diff:"Medium",q:"Stage portable cable for theatres (Article 520) must:",opts:["Standard NM cable is acceptable","Be specifically listed for stage use — flexible, voltage rated, with construction for dragging and repeated flexing","No special requirements — standard branch circuit rules apply","Must be in rigid metal conduit"],ans:1,ref:"NEC 520.68",exp:"Stage cables must be specifically listed for stage use: flexible, rated for voltage and current, and constructed for dragging on floors and repeated flexing. Standard cables fail quickly under stage use conditions."},
{id:260,mod:7,cat:"Special Occupancies",diff:"Easy",q:"Which NEC article covers swimming pools, fountains, and similar water features?",opts:["Article 500","Article 547","Article 680","Article 700"],ans:2,ref:"NEC Article 680",exp:"Article 680 = swimming pools, fountains, hot tubs, spas, and similar. Extensive requirements for bonding, GFCI protection, luminaire placement, underwater lighting, and equipment clearances."},
{id:261,mod:7,cat:"Special Occupancies",diff:"Hard",q:"Maximum voltage between any two exposed conductive surfaces in a patient care area?",opts:["5 millivolts","20 millivolts","100 millivolts","500 millivolts"],ans:1,ref:"NEC 517.13(B)",exp:"Patient care areas: equipotential bonding must limit voltage between any two accessible conductive surfaces to less than 20 millivolts. Patients connected to medical equipment can experience ventricular fibrillation from micro-shock currents as low as 10 microamperes."},
{id:262,mod:7,cat:"Special Occupancies",diff:"Medium",q:"125V, 15A and 20A receptacles within what distance of a pool inside wall require GFCI?",opts:["10 feet","15 feet","20 feet","25 feet"],ans:2,ref:"NEC 680.22(A)(1)",exp:"All 125V, 15A and 20A receptacles within 20 feet of inside pool walls require GFCI protection. At least one receptacle must be between 6 and 20 feet from the pool. No receptacle may be within 6 feet of the pool edge."},
{id:263,mod:7,cat:"Special Occupancies",diff:"Medium",q:"Carnivals and fairs (Article 525) require what protection for 125V, 15 and 20A receptacles?",opts:["Standard circuit protection only","GFCI protection for all 125V, 15 and 20A receptacles","AFCI protection for all circuits","Both GFCI and AFCI"],ans:1,ref:"NEC 525.23(A)",exp:"Carnivals, circuses, fairs: GFCI required for all 125V, 15 and 20A receptacles. High foot traffic, outdoor environment, and amusement rides create serious shock hazards."},
{id:264,mod:7,cat:"Special Occupancies",diff:"Hard",q:"Purged and pressurized equipment in Class I locations differs from explosion-proof how?",opts:["They are the same — interchangeable terms","Purged/pressurized enclosures maintain positive internal pressure with clean air to keep hazardous atmosphere out, rather than containing an internal explosion","Purged equipment uses water mist to suppress ignition","Pressurized equipment operates at reduced voltage"],ans:1,ref:"NEC 500.7(E) & NFPA 496",exp:"Purged/pressurized equipment: maintains positive pressure inside enclosure, preventing flammable atmosphere from entering. Explosion-proof: designed to contain any internal ignition. Both are valid for Class I — purging preferred for large enclosures."},
{id:265,mod:7,cat:"Special Occupancies",diff:"Medium",q:"Primary advantage of intrinsically safe equipment over explosion-proof equipment?",opts:["Less expensive","Limits electrical energy below ignition levels — inherently safe even with open circuits or sparks","Easier to install","Explosion-proof unavailable for small instruments"],ans:1,ref:"NEC 504.1 & 500.7(F)",exp:"Intrinsically safe systems limit energy in the hazardous area below ignition levels even under worst-case faults. Inherently safer than explosion-proof (which contains, not prevents, ignitions). Preferred for instrumentation and low-power devices."},
{id:266,mod:7,cat:"Special Occupancies",diff:"Easy",q:"Minimum clearance for a luminaire permanently installed over a pool?",opts:["5 feet","7.5 feet","12 feet","Luminaires may not be installed over pools"],ans:2,ref:"NEC 680.22(B)(1)",exp:"Luminaires over pools must be at least 12 feet above the water surface. Prevents contact by pool users, diving boards, or poles used in the pool."},
{id:267,mod:7,cat:"Special Occupancies",diff:"Hard",q:"Pool bonding (Article 680.26) must include:",opts:["Only the pump motor","Pool water, forming shell, all metal fittings, metal within 5 feet of pool, and equipment","Only underwater luminaires and their conduit","Only required when electrically operated equipment is installed"],ans:1,ref:"NEC 680.26",exp:"Pool bonding: pool water, metal forming shell, all metal fittings within or attached to pool, metal parts of pool equipment within 5 feet, metal conduit, and pump motor. All must be bonded together to prevent voltage gradients in or near water."},
{id:268,mod:7,cat:"Special Occupancies",diff:"Medium",q:"Underwater pool luminaires must be installed at minimum depth:",opts:["6 inches below water","18 inches below normal water level","24 inches below water","No minimum — any depth acceptable"],ans:1,ref:"NEC 680.23(B)(1)",exp:"Underwater pool luminaire tops must be at least 18 inches below normal water level. Protects from swimmers' feet, equipment, and reduces electrical hazard if lens breaks."},
{id:269,mod:7,cat:"Special Occupancies",diff:"Medium",q:"In a hospital, the essential electrical system must restore power within how many seconds?",opts:["5 seconds","10 seconds","30 seconds","60 seconds"],ans:1,ref:"NEC 517.31(B)",exp:"Healthcare facilities: life safety and critical branch of the essential electrical system must restore power within 10 seconds of normal power failure. Life-supporting equipment, OR lighting, and exit lighting cannot wait longer."},
{id:270,mod:7,cat:"Special Occupancies",diff:"Hard",q:"Area adjacent to an open-top battery charging room is classified as:",opts:["Unclassified — not enough gas to classify","Class I, Division 2 — hydrogen gas from charging can accumulate","Class II, Division 1 — battery acid is combustible","Class III — battery separator fibers are ignitable"],ans:1,ref:"NEC 480.9(A)",exp:"Large lead-acid battery rooms = Class I, Division 2 (hydrogen gas, Group B — most dangerous gas). Proper ventilation reduces but doesn't eliminate classification. Battery room electrical equipment must meet Class I, Division 2, Group B requirements."},
// MODULE 8: MOTORS & TRANSFORMERS (40)
{id:271,mod:8,cat:"Motors & Transformers",diff:"Easy",q:"Motor branch circuit conductors must be rated at minimum what percent of motor FLA?",opts:["100%","115%","125%","150%"],ans:2,ref:"NEC 430.22(A)",exp:"Motor branch circuit conductors = minimum 125% of FLA. Accounts for continuous duty operation. Example: 40A FLA × 1.25 = 50A minimum conductor ampacity."},
{id:272,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"Maximum inverse time breaker for a squirrel cage motor branch circuit?",opts:["125% of FLA","175% of FLA","250% of FLA","400% of FLA"],ans:2,ref:"NEC Table 430.52",exp:"Inverse time breakers: maximum 250% of motor FLA for branch circuit short-circuit and ground-fault protection. Large size allows motor to start (high inrush) without tripping. Separate from overload protection (115-125% FLA)."},
{id:273,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"Motor overload protection must trip at no more than:",opts:["100% of FLA","115% of FLA","125% of FLA","150% of FLA"],ans:2,ref:"NEC 430.32(A)(1)",exp:"Overload protection: trip at no more than 125% of FLA (115% for motors with SF < 1.15 or temperature rise > 40°C). Separate from branch circuit overcurrent protection."},
{id:274,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"If motor disconnect cannot be within sight of the motor, what is required?",opts:["A warning sign at the motor","The disconnect must be lockable in the open position","A second disconnect at the motor","Motor cannot be installed in that location"],ans:1,ref:"NEC 430.102(B) Exception",exp:"Motor disconnect not in sight of motor → must be capable of being locked in the open position. Workers lock disconnect remotely and are assured motor cannot start during maintenance."},
{id:275,mod:8,cat:"Motors & Transformers",diff:"Hard",q:"Motor feeder with three motors: A=20A FLA, B=15A FLA, C=10A FLA. Minimum feeder ampacity?",opts:["45A (sum of all FLA)","50A (largest × 125% + others)","56.25A","60A"],ans:1,ref:"NEC 430.24",exp:"Largest motor × 125% + sum of others: 20 × 1.25 = 25A + 15A + 10A = 50A minimum feeder ampacity. Classic motor feeder calculation."},
{id:276,mod:8,cat:"Motors & Transformers",diff:"Easy",q:"Function of a motor controller?",opts:["Provide overcurrent protection","Start/stop the motor and vary speed or torque","Serve as the disconnecting means","Provide ground fault protection"],ans:1,ref:"NEC Article 100 (Controller)",exp:"Motor controller starts/stops motor and may vary speed, torque, or direction. Separate from disconnects (de-energize) and overcurrent devices (protect conductors)."},
{id:277,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"5 HP, 230V single-phase motor, FLA = 28A. Minimum copper THWN conductor?",opts:["12 AWG (20A ampacity)","10 AWG (30A — insufficient for 35A)","8 AWG (40A ampacity)","Nameplate determines sizing"],ans:2,ref:"NEC 430.22(A) & Table 310.16",exp:"28A × 1.25 = 35A minimum. 10 AWG THWN = 30A (insufficient). 8 AWG THWN = 40A (meets requirement). 8 AWG is minimum."},
{id:278,mod:8,cat:"Motors & Transformers",diff:"Hard",q:"Maximum dual-element time-delay fuse for squirrel cage motor branch circuit?",opts:["125% of FLA","150% of FLA","175% of FLA","225% of FLA"],ans:2,ref:"NEC Table 430.52",exp:"Dual-element time-delay fuses: maximum 175% of motor FLA for squirrel cage motors. Less than 250% permitted for inverse time breakers because dual-element fuses have built-in time delay to accommodate starting."},
{id:279,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"Motor service factor (SF) = 1.15 means:",opts:["Motor's power factor under full load","Motor can operate continuously at 115% of rated horsepower","Motor efficiency at full load","Ratio of starting current to running current"],ans:1,ref:"NEC 430.32(A)(1)",exp:"SF = 1.15 → motor can operate at 115% of rated HP continuously. SF ≥ 1.15 = overload protection can be set at 125% FLA. SF < 1.15 = 115% max overload protection."},
{id:280,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"Motor disconnecting means must be located:",opts:["At the motor starter only","Within sight of motor — visible and not more than 50 feet away","Within 6 feet of motor","At the panelboard serving the circuit"],ans:1,ref:"NEC 430.102(B)",exp:"Motor disconnect must be in sight = visible AND ≤50 feet from motor. Both conditions required. Service personnel must visually confirm disconnect is open before working on motor."},
{id:281,mod:8,cat:"Motors & Transformers",diff:"Hard",q:"Variable frequency drive (VFD) output conductor special consideration?",opts:["VFD output conductors must be shielded cable","Size at 125% of motor FLA same as standard motor conductors","VFD output carries non-sinusoidal current with harmonics — may need derating","VFDs eliminate separate overload protection need"],ans:2,ref:"NEC 430.22(A) & manufacturer req.",exp:"VFD output conductors carry non-sinusoidal waveforms with harmonic content, creating additional heating. May need derating. Shielded cable often recommended to prevent EMI. Follow VFD manufacturer instructions for conductor type and length."},
{id:282,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"Purpose of a motor starter's thermal overload relay?",opts:["Protect branch circuit conductors","Protect motor windings from overheating from sustained overload or locked rotor","Provide ground fault protection","Limit starting current"],ans:1,ref:"NEC 430.32",exp:"Thermal overload relay protects motor windings from overheating. Senses current proportional to heat in windings and trips if current exceeds nameplate for sustained period. Mimics thermal behavior of motor windings."},
{id:283,mod:8,cat:"Motors & Transformers",diff:"Hard",q:"Under what condition may branch circuit OCPD serve as motor overload protection?",opts:["Never — must always be separate","When OCPD rated ≤ 125% of FLA","Portable motors only","Motor ≤ 1/8 HP, manually started, continuously supervised"],ans:3,ref:"NEC 430.32(B)(1)",exp:"Separate overload protection may be omitted for motors ≤ 1/8 HP that are manually started and continuously supervised. Most motors require separate overload protection. Motors marked 'thermally protected' also qualify."},
{id:284,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"Transformer rated 45 kVA, 480V primary, 120/240V secondary. Rated secondary current at 240V?",opts:["93.75A","187.5A","375A","Equals primary current"],ans:1,ref:"NEC 450.3 (sizing basis)",exp:"Secondary current = kVA × 1,000 / secondary voltage = 45,000 / 240 = 187.5A at 240V."},
{id:285,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"Overcurrent protection for a 480V primary, 45 kVA dry-type transformer?",opts:["100% of primary FLA","No more than 125% of primary FLA","No more than 250% of primary FLA","No overcurrent protection required for transformers under 50 kVA"],ans:1,ref:"NEC 450.3(B)",exp:"Primary FLA = 45,000 / 480 = 93.75A × 1.25 = 117A maximum primary protection. Primary overcurrent protection for transformers under 600V: maximum 125% of primary FLA."},
{id:286,mod:8,cat:"Motors & Transformers",diff:"Hard",q:"Dry-type transformer rated over 112.5 kVA installed indoors must be in:",opts:["Transformer room with fire-rated walls","Fire-resistant transformer room or vault","Outdoor location only","Dedicated electrical room with working space"],ans:1,ref:"NEC 450.21(B)",exp:"Dry-type transformers > 112.5 kVA must be in a transformer room or vault of fire-resistant construction when installed indoors. Smaller dry-type (≤112.5 kVA) with Class 155+ insulation may be in open areas."},
{id:287,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"NEC Table values for motor FLA versus nameplate FLA — which is used for conductor sizing?",opts:["Always use nameplate FLA for conductor sizing","Use NEC Table 430.248/250 FLA for conductor sizing; nameplate FLA for overload protection","Either — they should be close","Nameplate only when lower than table value"],ans:1,ref:"NEC 430.6(A)(1) & 430.22",exp:"NEC Tables 430.248/250 used for conductor and overcurrent device sizing. Nameplate FLA used for overload protection sizing. Critical distinction — using wrong value results in under-protected conductors or nuisance overload tripping."},
{id:288,mod:8,cat:"Motors & Transformers",diff:"Easy",q:"Purpose of the motor disconnecting means?",opts:["Provide overcurrent protection","De-energize motor circuit for maintenance","Control motor speed","Start/stop motor during normal operation"],ans:1,ref:"NEC 430.102",exp:"Motor disconnect = safety device to de-energize circuit for maintenance and repair. NOT for starting/stopping (controller) and NOT for fault protection (OCPD)."},
{id:289,mod:8,cat:"Motors & Transformers",diff:"Hard",q:"75 kVA, 120/208V three-phase transformer. Secondary FLA?",opts:["208.2A","180A","300A","360A"],ans:0,ref:"NEC 450.3 (sizing basis)",exp:"Secondary FLA = 75,000 / (208 × 1.732) = 75,000 / 360.3 = 208.2A. Conductor minimum = 208.2 × 1.25 = 260.3A minimum ampacity."},
{id:290,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"10 HP, 3-phase 208V motor, FLA = 30.8A. Maximum inverse time breaker?",opts:["40A breaker (125% of FLA)","80A breaker (250% of FLA — rounds to 80A)","70A breaker (next size ≤ 250% of FLA)","50A breaker"],ans:2,ref:"NEC Table 430.52 & 430.52(C)(1) Exception",exp:"30.8 × 250% = 77A. Standard size ≤ 77A = 70A. If 70A causes nuisance tripping, may increase to 80A. 70A is the code answer unless starting issues documented."},
{id:291,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"Dry-type transformer clearance requirement:",opts:["No clearance required if in enclosure","Clearance per installation instructions and Article 110 working space rules","12 inches on all sides","6 feet in front for working space"],ans:1,ref:"NEC 450.13 & 110.26",exp:"Transformer clearance: per installation instructions AND NEC Article 110 working space requirements. Both govern. Must provide adequate ventilation and access for inspection."},
{id:292,mod:8,cat:"Motors & Transformers",diff:"Hard",q:"Maximum dual-element fuse for wound-rotor AC motor?",opts:["125% of FLA","150% of FLA","175% of FLA","250% of FLA"],ans:1,ref:"NEC Table 430.52",exp:"Wound-rotor AC motors: maximum dual-element fuse = 150% FLA — less than 175% for squirrel cage motors. Different starting characteristics require different protection headroom."},
{id:293,mod:8,cat:"Motors & Transformers",diff:"Easy",q:"NEC Table 430.250 FLA values are used for sizing:",opts:["Overload protection only","Branch circuit conductors and overcurrent protection devices","Motor nameplate verification","Only when nameplate is missing"],ans:1,ref:"NEC 430.6(A)(1) & 430.22/430.52",exp:"Table 430.250 used for: (1) branch circuit conductors (FLA × 125%) and (2) branch circuit OCPDs (FLA × 250% for inverse time breakers). Nameplate FLA used for overload protection."},
{id:294,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"When two or more motors share a single branch circuit, required conditions?",opts:["Combined FLA cannot exceed 20A","Each motor must have individual overload protection and circuit rated for total load","Only motors under 1 HP may share","Shared motor circuits never permitted"],ans:1,ref:"NEC 430.53",exp:"Multiple motors on shared circuit: each motor needs individual overload protection, and circuit rated for the combination. Circuit protected at no more than values permitted for the smallest motor on circuit."},
{id:295,mod:8,cat:"Motors & Transformers",diff:"Hard",q:"Transformer impedance %Z = 5% means:",opts:["5% of input power lost as heat","At 5% of rated voltage, full rated current flows (short-circuit condition)","At full load, voltage drops 5% from no-load to full-load","5% of turns are for tap adjustment"],ans:1,ref:"NEC 450.3 & IEEE C57",exp:"%Z = percentage of rated primary voltage needed to drive full short-circuit current. 5% Z = only 5% of normal voltage drives full-rated fault current. Lower %Z = higher fault current. Critical for short-circuit analysis and breaker interrupting capacity selection."},
{id:296,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"Motor in wet or damp location must have enclosure rated:",opts:["Open drip-proof (ODP) is acceptable everywhere","Enclosure suitable for the location — drip-proof, splash-proof, TEFC, or weatherproof as appropriate","Only TEFC motors permitted in wet locations","GFCI protection on branch circuit required for all wet location motors"],ans:1,ref:"NEC 430.11",exp:"Motor enclosure type must match environment. ODP for clean, dry indoor only. Splash-proof or TEFC for wet/damp. Explosion-proof for hazardous. Using ODP in wet location allows water ingress causing winding failure and shock hazard."},
{id:297,mod:8,cat:"Motors & Transformers",diff:"Hard",q:"Effect of reduced voltage on motor torque and current?",opts:["Reduces both proportionally","Reduces torque (proportional to voltage squared) while motor draws excess current trying to meet torque demand","No effect on performance","Increases motor efficiency"],ans:1,ref:"NEC 430.83 & motor theory",exp:"Motor torque ∝ voltage². 10% voltage reduction → ~19% torque reduction. If load needs full torque, motor draws excessive current = overheating. Voltage quality is critical for motor life."},
{id:298,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"Motor marked 'thermally protected' — additional external overload protection required?",opts:["Yes — additional overload required","No — built-in thermal protection satisfies overload protection requirement","GFCI branch circuit protection required instead","Thermal protection must be tested annually"],ans:1,ref:"NEC 430.32(A)(2)",exp:"'Thermally protected' motors have integral thermal cutouts that open when windings overheat. Satisfies Article 430 overload protection requirements. Simplifies installation for smaller motors."},
{id:299,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"480V to 120/240V transformer (separately derived system) grounding requirements?",opts:["Bonds to primary system ground through steel frame","GEC must connect secondary to grounding electrode system AND system bonding jumper required","Secondary neutral connects back to primary service neutral","No grounding required — primary grounding adequate"],ans:1,ref:"NEC 250.30(A)",exp:"Separately derived system: (1) system bonding jumper connecting secondary neutral to secondary EGC, and (2) GEC connecting secondary to grounding electrode system. Equivalent to service grounding requirements."},
{id:300,mod:8,cat:"Motors & Transformers",diff:"Hard",q:"Maximum permitted length of conductor between motor and overload relay?",opts:["Relay must be at the motor","Relay may be at controller — no length restriction","Must not exceed 6 feet","May be up to 25 feet from motor"],ans:1,ref:"NEC 430.37",exp:"Overload relays are typically in the motor starter, not at the motor. No NEC restriction on conductor length between motor and overload relay — the relay senses current proportional to motor winding heat."},
{id:301,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"Wye-delta starting reduces starting current to approximately:",opts:["Doubles starting current","Approximately 1/3 of across-the-line starting current","1/2 of normal starting current","Starting current unchanged"],ans:1,ref:"NEC 430.52 & motor theory",exp:"Wye-delta starting reduces current to approximately 1/3 of across-the-line starting (torque also reduced to 1/3). In wye, each winding receives ~58% of line voltage. Motor must start under reduced load."},
{id:302,mod:8,cat:"Motors & Transformers",diff:"Easy",q:"'Stalled rotor current' (locked rotor current) refers to:",opts:["Current at full load","Current when rotor is stationary — approximately 6-10 times FLA","Current during normal starting","Current when first energized"],ans:1,ref:"NEC Table 430.251(A) & (B)",exp:"Locked rotor current = motor's maximum current when energized at full voltage with rotor stationary — typically 6-10 × FLA. Motor controllers must be rated to interrupt this current safely."},
{id:303,mod:8,cat:"Motors & Transformers",diff:"Hard",q:"Motor nameplate Code Letter indicates:",opts:["Efficiency rating","Locked-rotor kVA per horsepower — affects overcurrent protection sizing","Motor insulation class","Single-phase or three-phase designation"],ans:1,ref:"NEC 430.7(A)(9) & Table 430.7(B)",exp:"Code Letter (A through V) = locked-rotor kilovolt-amperes per HP. Higher letters = higher starting kVA and inrush current. Used to properly size branch circuit overcurrent protection."},
{id:304,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"480V primary, 208V/120V delta-wye transformer. Turns ratio?",opts:["480:208","480:120","2.31:1 (480/208)","4:1 (480/120)"],ans:2,ref:"NEC 450.3 (sizing basis)",exp:"Turns ratio = primary / secondary voltage. For 208V secondary: 480/208 = 2.31:1. For 120V secondary: 480/120 = 4:1. Delta-wye transformer ratio based on line voltages."},
{id:305,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"For a controller to also serve as disconnecting means:",opts:["All controllers serve as disconnects","Controller must be listed and rated for the purpose — not all qualify","Contactor always qualifies","Only manually operated controllers qualify"],ans:1,ref:"NEC 430.111",exp:"Not all controllers qualify as disconnects. Controller used as disconnect must be listed and rated for the purpose including HP rating and ability to open under running current. Many contactors are NOT rated as disconnects."},
{id:306,mod:8,cat:"Motors & Transformers",diff:"Hard",q:"Protection required for transformers installed outdoors on utility poles?",opts:["No special protection needed","Weatherproof enclosures and physical damage protection required","Only fall protection for workers","GFCI on all secondary circuits"],ans:1,ref:"NEC 450.22 & 450.13",exp:"Outdoor transformers must be weatherproof and protected from physical damage. Pad-mounted transformers must have tamper-resistant, lockable enclosures to prevent public access to energized parts."},
{id:307,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"Purpose of a reduced voltage motor starter (soft starter)?",opts:["Permanently reduce voltage for energy savings","Gradually ramp up voltage during starting to reduce mechanical shock and electrical inrush","Step down voltage from 480V to 240V","Provide adjustable speed control throughout operation"],ans:1,ref:"NEC 430.52 & 430.83",exp:"Soft starters gradually increase voltage during starting, reducing inrush current and mechanical shock. NOT for speed control during running — once at full speed, full voltage applied. Common for conveyors, pumps, compressors."},
{id:308,mod:8,cat:"Motors & Transformers",diff:"Easy",q:"Motor Code Letter (locked rotor kVA designation) is used for:",opts:["Determining conductor size","Selecting overcurrent protection to allow starting without nuisance tripping","Selecting overload relay heater","Identifying efficiency class"],ans:1,ref:"NEC 430.52(C)(1) & Table 430.7(B)",exp:"Code Letter affects overcurrent protection selection. Higher Code Letter motors may need larger overcurrent devices to handle starting current without tripping. NEC allows increasing up to specified maximums if nuisance tripping occurs."},
{id:309,mod:8,cat:"Motors & Transformers",diff:"Hard",q:"Delta transformer bank with one failed transformer — what operating mode is possible?",opts:["Cannot operate with one failed transformer","Open-delta (V-connection) at approximately 58% of original capacity","Reduced capacity wye operation","Single-phase operation only"],ans:1,ref:"NEC 450.3 & transformer theory",exp:"Open-delta (V-delta): remaining two transformers provide three-phase power at approximately 58% (1/√3) of original capacity. Emergency measure — reduced capacity, unbalanced phase voltages, poor regulation."},
{id:310,mod:8,cat:"Motors & Transformers",diff:"Medium",q:"Motor not in sight from controller — what additional requirement?",opts:["No additional protection required","Controller must be capable of being locked in the open position","Separate in-sight disconnect must be at motor","Motor must have built-in thermal cutout"],ans:1,ref:"NEC 430.87",exp:"Motor not in sight from controller: controller must be lockable in open (off) position. Prevents remote starting while maintenance personnel work on motor or driven machinery."},
// MODULE 9: COMMUNICATIONS & EMERGENCY (25)
{id:311,mod:9,cat:"Communications & Emergency",diff:"Easy",q:"Emergency systems (Article 700) must restore power within:",opts:["5 seconds","10 seconds","30 seconds","60 seconds"],ans:1,ref:"NEC 700.12",exp:"Emergency systems must restore power within 10 seconds of normal failure. Applies to emergency lighting, exit signs, fire alarms, and life-safety systems."},
{id:312,mod:9,cat:"Communications & Emergency",diff:"Medium",q:"Emergency systems vs. legally required standby systems — key difference?",opts:["Same — interchangeable terms","Emergency systems = life-safety functions; legally required standby = public safety required by law but less immediately life-critical","Emergency systems require 10-second transfer; legally required standby has no time requirement","Emergency systems use generators; legally required standby uses UPS"],ans:1,ref:"NEC Article 700 vs Article 701",exp:"Emergency systems (Article 700) = life-safety systems. Legally required standby (Article 701) = systems required by law but not immediately life-critical such as refrigeration, communication systems."},
{id:313,mod:9,cat:"Communications & Emergency",diff:"Medium",q:"Maximum voltage for a Class 2 circuit (Article 725)?",opts:["24V DC only","30V AC or 60V DC","100V","120V"],ans:1,ref:"NEC 725.121(A)(4) & Table 11",exp:"Class 2 circuits: maximum 30V AC or 60V DC with limited power (VA). Common for thermostats, doorbells, security systems, low-voltage lighting control."},
{id:314,mod:9,cat:"Communications & Emergency",diff:"Hard",q:"Class 2 conductors sharing a raceway with power conductors require:",opts:["Always prohibited","A solid fixed barrier separating Class 2 from power conductors","6 inches separation","Power conductors must be rated 600V minimum"],ans:1,ref:"NEC 725.136(A)",exp:"Class 2 circuits sharing a raceway with power circuits require a solid fixed barrier separating them — or they must be in separate raceways. Prevents damage to low-voltage insulation and induction of harmful voltages."},
{id:315,mod:9,cat:"Communications & Emergency",diff:"Medium",q:"Generators for emergency systems must:",opts:["Any standby generator is acceptable","Supply full emergency load within 10 seconds with sufficient fuel supply and automatic starting","Only natural gas generators may be used","Generators for emergency must be tested monthly only"],ans:1,ref:"NEC 700.12(B)",exp:"Emergency system generators: supply full load within 10 seconds of normal power failure, automatic starting, automatic transfer, minimum 2-hour fuel supply. In California, emissions regulations also apply to standby generators."},
{id:316,mod:9,cat:"Communications & Emergency",diff:"Easy",q:"Fire alarm circuits (Article 760) are classified as:",opts:["Class 1 — power limited only","Power-limited fire alarm (PLFA) or non-power-limited fire alarm (NPLFA) circuits","Class 3 circuits","High-impedance circuits"],ans:1,ref:"NEC 760.41 & 760.61",exp:"Article 760 fire alarm circuits: PLFA (Power-Limited Fire Alarm) or NPLFA (Non-Power-Limited). Classification determines permissible wiring methods, conduit requirements, and cable mixing rules."},
{id:317,mod:9,cat:"Communications & Emergency",diff:"Medium",q:"CATV system must be grounded at building entrance to:",opts:["Electrical panel neutral bus","The grounding electrode system — typically the GEC or service equipment enclosure","Utility company's ground rod","Grounding not required — surge protectors used instead"],ans:1,ref:"NEC 820.100(B)",exp:"CATV shields and outer conductors must bond to building's grounding electrode system at building entrance. Prevents dangerous voltage differences between communications ground and electrical ground."},
{id:318,mod:9,cat:"Communications & Emergency",diff:"Hard",q:"Emergency systems require automatic transfer switches because:",opts:["Manual switches acceptable if person is present 24/7","Automatic operation required — 10-second restoration cannot be reliably met with manual switching","Transfer switches optional if generator manually started","Circuit breaker interlock serves as acceptable transfer switch for emergency systems"],ans:1,ref:"NEC 700.5(A)",exp:"Emergency systems require ATSs that operate without manual intervention. The 10-second restoration requirement cannot reliably be met if a person must manually operate a switch."},
{id:319,mod:9,cat:"Communications & Emergency",diff:"Medium",q:"Telephone system conductors (Article 800) entering a building must have:",opts:["GFCI protection","A listed protector to guard against lightning surges and power contact","Metallic conduit for physical protection","Surge-protective device rated for telephone voltage"],ans:1,ref:"NEC 800.90(A)",exp:"Article 800 requires listed protectors (surge arrestors) at the building entrance of communications circuits. Guards against lightning surges and inadvertent contact with power lines."},
{id:320,mod:9,cat:"Communications & Emergency",diff:"Hard",q:"Fire alarm cables in plenums must be:",opts:["Any listed cable acceptable in plenums","Plenum-rated cables (FPLP) with low smoke and flame-spread characteristics","Standard THWN in conduit always acceptable","NM cable in metal conduit suitable for plenums"],ans:1,ref:"NEC 760.53(A)(1)",exp:"Fire alarm cables in plenums must be plenum-rated (FPLP type) with limited flame spread and low smoke emission. Non-plenum cable in plenums is a serious safety violation — can spread fire through air handling system."},
{id:321,mod:9,cat:"Communications & Emergency",diff:"Medium",q:"Exit signs connected to emergency circuits must be illuminated:",opts:["Only during normal business hours","At all times when the building is occupied","Only when emergency power is active","Only during power outages"],ans:1,ref:"NEC 700.16",exp:"Exit signs must be illuminated at ALL times the building is occupied. Connected to emergency circuit so they remain on during power outages."},
{id:322,mod:9,cat:"Communications & Emergency",diff:"Hard",q:"Emergency lighting units must provide illumination for how long after normal power failure?",opts:["30 minutes","60 minutes","90 minutes","Until generator starts"],ans:2,ref:"NEC 700.12(E)",exp:"Emergency lighting: minimum 90 minutes after normal power failure. Monthly 30-second tests verify unit starts. Annual 90-minute test verifies battery capacity. Failed batteries must be replaced."},
{id:323,mod:9,cat:"Communications & Emergency",diff:"Medium",q:"Emergency circuit wiring must be separated from normal power wiring:",opts:["No separation required","Emergency and normal wiring must be in separate raceways, cable trays, or cables except in transfer equipment","Emergency wiring must be in dedicated room","Only 12-inch physical separation required"],ans:1,ref:"NEC 700.10(B)(1)",exp:"Emergency wiring must be entirely independent of normal power wiring — separate raceways, cable assemblies, boxes, and cabinets except at transfer equipment. Ensures normal wiring fault can't simultaneously damage emergency system."},
{id:324,mod:9,cat:"Communications & Emergency",diff:"Easy",q:"Low-voltage landscape lighting (Article 411) typically operates at:",opts:["24V DC","30V or less","120V through transformer","277V for efficiency"],ans:1,ref:"NEC 411.2",exp:"Article 411 = low-voltage lighting systems operating at 30V or less. Typical landscape lighting uses 12V through step-down transformers. Lower voltage = reduced shock hazard and lighter wire gauge."},
{id:325,mod:9,cat:"Communications & Emergency",diff:"Hard",q:"Optional standby system (Article 702) differs from legally required standby how?",opts:["Optional standby has no NEC requirements","Optional standby installed at owner's discretion for comfort/productivity; legally required standby mandated by law for safety","Optional must transfer within 60 seconds; legally required within 30 seconds","The terms mean the same thing"],ans:1,ref:"NEC Article 702 vs Article 701",exp:"Optional standby (Article 702) = voluntary, for comfort or business continuity. Legally required standby (Article 701) = mandated by codes for safety. Different reliability and time requirements."},
{id:326,mod:9,cat:"Communications & Emergency",diff:"Medium",q:"Fire alarm circuit breaker must be:",opts:["Red in color to identify as life safety circuit","Standard breaker color is acceptable","Green to indicate approved circuit","Gray to indicate low voltage"],ans:0,ref:"NEC 760.21",exp:"Fire alarm circuit breakers must be RED in color and identified as 'FIRE ALARM CIRCUIT CONTROL.' Red color provides quick visual identification to prevent inadvertent de-energization during electrical work."},
{id:327,mod:9,cat:"Communications & Emergency",diff:"Hard",q:"Key difference between PLFA and NPLFA fire alarm cable?",opts:["PLFA indoor only; NPLFA outdoor","PLFA operates at limited power — allows less robust wiring methods; NPLFA has higher power requiring conduit or heavy cables","PLFA uses copper; NPLFA uses aluminum","They are the same — interchangeable terms"],ans:1,ref:"NEC 760.41 & 760.61",exp:"PLFA (power-limited) = smaller, flexible cables with less restrictive wiring method requirements. NPLFA (non-power-limited) = higher power, requires wiring methods similar to power circuits. Classification determines what methods are permissible."},
{id:328,mod:9,cat:"Communications & Emergency",diff:"Medium",q:"Optical fiber cable and power conductors in same raceway:",opts:["Always prohibited","May share if optical fiber is listed for the purpose","No restrictions — fiber is non-conductive","6-inch minimum separation required"],ans:1,ref:"NEC 770.133",exp:"Optical fiber cables may be in same raceway as power conductors only when specifically listed for such applications (composite cable types). Standard optical fiber cables cannot share raceways with power conductors."},
{id:329,mod:9,cat:"Communications & Emergency",diff:"Easy",q:"Typical residential data network cable type?",opts:["Category 5e or better UTP (unshielded twisted pair)","Coaxial cable only","Fiber optic for all residential","NM cable with data conductors added"],ans:0,ref:"NEC Article 800 & 725",exp:"Residential data networks use Cat 5e, Cat 6, or Cat 6A UTP cable for Ethernet. Falls under Article 800 (communications) or Article 725 (Class 2/3 circuits). Requires separation from power conductors."},
{id:330,mod:9,cat:"Communications & Emergency",diff:"Hard",q:"Required annual test duration for emergency lighting units?",opts:["30 minutes","60 minutes","90 minutes — the full rated duration","Duration equals battery rating divided by load"],ans:2,ref:"NEC 700.3(B)",exp:"Emergency lighting must be tested for full rated duration (minimum 90 minutes) annually. Monthly 30-second tests verify unit starts. Annual 90-minute test verifies battery has capacity for required duration."},
{id:331,mod:9,cat:"Communications & Emergency",diff:"Medium",q:"Before testing a fire alarm system, who must be notified?",opts:["Electrical inspector must be present","Fire alarm installer and building owner notify the monitoring company — and occupants should be informed","Only the monitoring company","No notification — system automatically signals test condition"],ans:1,ref:"NFPA 72 Chapter 14 & NEC 760",exp:"Before fire alarm testing: notify monitoring company (prevents unnecessary fire department dispatch) and notify building occupants and management (prevents panic). Contractor and building owner share responsibility."},
{id:332,mod:9,cat:"Communications & Emergency",diff:"Hard",q:"Maximum voltage for Class 3 remote-control circuits (Article 725)?",opts:["30V AC","60V DC","150V maximum","300V maximum"],ans:2,ref:"NEC 725.121(B) & Table 11(A)",exp:"Class 3 circuits: maximum 150V with limited power. Class 3 allows higher voltage than Class 2 (30V AC max) but still limits power to reduce fire and shock hazard. Used for some audio, access control, and intercom systems."},
{id:333,mod:9,cat:"Communications & Emergency",diff:"Medium",q:"For a whole-house residential optional standby generator, what transfer method is acceptable?",opts:["Listed ATS always required","Interlock on main breaker never code-compliant","Listed load management device or ATS required regardless of size","Listed interlock on main breaker is permitted for optional standby systems when properly installed"],ans:3,ref:"NEC 702.5",exp:"For optional standby systems (Article 702), a listed breaker interlock is an accepted transfer method. Prevents simultaneous utility and generator connection. Less expensive than ATS, popular for residential whole-house generators."},
{id:334,mod:9,cat:"Communications & Emergency",diff:"Easy",q:"A listed transfer switch prevents:",opts:["Overloads on the generator","Simultaneous connection of utility and generator — preventing dangerous backfeed into power lines","Overvoltage from generator","Generator from exceeding its rated kW"],ans:1,ref:"NEC 700.5(D) & 702.5",exp:"Listed transfer switch specifically designed to prevent both sources from connecting simultaneously. Backfeed into utility lines is extremely dangerous to line workers — listed transfer switch prevents this fatal hazard."},
{id:335,mod:9,cat:"Communications & Emergency",diff:"Hard",q:"Required testing intervals for emergency systems?",opts:["Monthly testing only","Monthly tests (minimum 30 minutes) and annual tests (minimum 2 hours under simulated load)","Weekly testing","Quarterly tests of 30 minutes each"],ans:1,ref:"NEC 700.3(B)(1) & (B)(2)",exp:"Emergency systems: monthly tests of at least 30 minutes under load + annual tests of at least 2 hours under simulated load. Witnessed by building owner or authorized representative with records kept."},
// MODULE 10: CALCULATIONS (60)
{id:336,mod:10,cat:"Calculations",diff:"Easy",q:"Ampacity of 12 AWG THWN copper at 60°C column of Table 310.16?",opts:["15A","20A","25A","30A"],ans:1,ref:"NEC Table 310.16 (60°C column)",exp:"12 AWG copper at 60°C = 20A. At 75°C = 20A. At 90°C = 25A. For 60°C terminations (most residential): 20A. Memorize: 14AWG=15A, 12AWG=20A, 10AWG=30A at 60°C."},
{id:337,mod:10,cat:"Calculations",diff:"Easy",q:"Ampacity of 10 AWG copper THWN at 75°C column of Table 310.16?",opts:["30A","35A","40A","45A"],ans:1,ref:"NEC Table 310.16 (75°C column)",exp:"10 AWG copper at 75°C = 35A. At 60°C = 30A. At 90°C = 40A. 75°C column used when equipment is rated 75°C (most commercial panelboards and breakers)."},
{id:338,mod:10,cat:"Calculations",diff:"Medium",q:"A 240V single-phase load draws 30A continuously. Minimum circuit ampacity?",opts:["30A","37.5A","40A","50A"],ans:1,ref:"NEC 210.20(A)",exp:"Continuous loads = 125% capacity. 30A × 1.25 = 37.5A minimum circuit ampacity. Conductor must be rated ≥ 37.5A; overcurrent device minimum 37.5A (use next standard size = 40A)."},
{id:339,mod:10,cat:"Calculations",diff:"Medium",q:"Using Ohm's Law: current through 120V circuit with 24-ohm resistance?",opts:["2.88A","5A","10A","2,880A"],ans:1,ref:"Ohm's Law (I=V/R)",exp:"I = V/R = 120/24 = 5A. Ohm's Law: V=IR, I=V/R, R=V/I. Power at this point: P = IV = 5 × 120 = 600 watts."},
{id:340,mod:10,cat:"Calculations",diff:"Medium",q:"Power consumed by a 120V, 15A load?",opts:["8 watts","125 watts","1,800 watts","18,000 watts"],ans:2,ref:"Power formula (P=IV)",exp:"P = IV = 15A × 120V = 1,800W (1.8 kW). Maximum power a 15A, 120V circuit can supply. P=IV used constantly in load calculations."},
{id:341,mod:10,cat:"Calculations",diff:"Hard",q:"2,400 sq ft dwelling: general lighting (3 VA/sq ft), two small appliance circuits, one laundry circuit. Total before demand factors?",opts:["7,200 VA","10,200 VA","11,700 VA","13,200 VA"],ans:2,ref:"NEC 220.12 & 220.52",exp:"Lighting: 2,400 × 3 = 7,200 VA. Small appliance: 2 × 1,500 = 3,000 VA. Laundry: 1,500 VA. Total = 11,700 VA (before demand factors). After Table 220.42: first 3,000 at 100%, remainder at 35%."},
{id:342,mod:10,cat:"Calculations",diff:"Medium",q:"Voltage drop for 120V circuit, 20A, 100-foot one-way run, 12 AWG copper (K=12.9)?",opts:["2.15%","3.58%","6.6%","8.72%"],ans:2,ref:"NEC 210.19(A)(1) Informational Note",exp:"VD = 2 × 12.9 × 20 × 100 / 6,530 = 51,600/6,530 = 7.9V. VD% = 7.9/120 × 100 = 6.6%. Exceeds 3% recommended. Use 2× for single-phase round trip. The formula: VD = 2×K×I×D/CM."},
{id:343,mod:10,cat:"Calculations",diff:"Hard",q:"What AWG copper conductor limits voltage drop to 3% for 240V, 30A circuit run 150 feet? (K=12.9)",opts:["8 AWG (16,510 CM)","6 AWG (26,240 CM)","4 AWG (41,740 CM)","2 AWG (66,360 CM)"],ans:1,ref:"NEC 210.19(A)(1) Informational Note",exp:"Max VD = 240 × 3% = 7.2V. Required CM = 2 × 12.9 × 30 × 150 / 7.2 = 116,100/7.2 = 16,125 CM. 6 AWG = 26,240 CM (meets requirement). 8 AWG = 16,510 CM (barely meets but 6 AWG provides safety margin)."},
{id:344,mod:10,cat:"Calculations",diff:"Medium",q:"Three-phase, 208V, 45 kVA load — line current?",opts:["125A","72.2A","124.9A","216.3A"],ans:2,ref:"Three-phase formula",exp:"Three-phase: I = kVA × 1,000 / (V × 1.732) = 45,000 / (208 × 1.732) = 45,000/360.3 = 124.9A ≈ 125A. Always use 1.732 for three-phase current calculations."},
{id:345,mod:10,cat:"Calculations",diff:"Easy",q:"Number of 20A circuits needed for 5,000 sq ft office at 3.5 VA/sq ft?",opts:["6 circuits","7 circuits","10 circuits","11 circuits"],ans:2,ref:"NEC Table 220.12 & 210.20(A)",exp:"Total = 5,000 × 3.5 = 17,500 VA. Continuous: each 20A, 120V circuit = 1,920 VA (20A × 120V × 80%). Circuits = 17,500/1,920 = 9.1 → 10 circuits minimum."},
{id:346,mod:10,cat:"Calculations",diff:"Hard",q:"480V 3-phase 4-wire wye system, 120 kW at unity power factor. Line current?",opts:["83.3A","144.3A","166.7A","250A"],ans:1,ref:"Three-phase power formula",exp:"At unity PF: kVA = kW = 120,000 VA. I = VA/(V × √3) = 120,000/(480 × 1.732) = 120,000/831.4 = 144.3A."},
{id:347,mod:10,cat:"Calculations",diff:"Medium",q:"Conduit fill for three 12 AWG THWN conductors in 1/2-inch EMT?",opts:["Within the 40% fill limit","Exceeds the 40% fill limit","Exactly 40% fill","Cannot determine without conductor length"],ans:0,ref:"NEC Annex C, Table C1",exp:"From Annex C Table C1 (EMT): 1/2-inch EMT accommodates up to 7 conductors of 12 AWG THWN. Three conductors = well within limit. Use Annex C tables directly at the exam — fastest method."},
{id:348,mod:10,cat:"Calculations",diff:"Easy",q:"Power factor of a purely resistive load?",opts:["0","0.5","0.866","1.0"],ans:3,ref:"Power factor theory",exp:"Purely resistive loads (incandescent lights, electric heaters) = power factor 1.0 (unity). All apparent power (VA) is real power (watts) — no reactive component."},
{id:349,mod:10,cat:"Calculations",diff:"Medium",q:"10 HP, 460V, 3-phase motor, FLA = 13.6A. Minimum branch circuit conductor ampacity?",opts:["13.6A","15A","17A","20A"],ans:2,ref:"NEC 430.22(A)",exp:"Motor conductor = FLA × 125% = 13.6 × 1.25 = 17A minimum. 12 AWG THWN = 20A at 75°C — meets 17A requirement."},
{id:350,mod:10,cat:"Calculations",diff:"Hard",q:"Service demand: lighting 6,045 VA, appliance 8,500 VA, HVAC 14,400 VA, water heater 4,500 VA. Total at 240V?",opts:["140A","141A","145A","150A"],ans:0,ref:"NEC 220.87 & 230.79",exp:"Total VA = 6,045 + 8,500 + 14,400 + 4,500 = 33,445 VA. Current = 33,445/240 = 139.4A ≈ 140A. Next standard service = 150A or 200A."},
{id:351,mod:10,cat:"Calculations",diff:"Medium",q:"Circular mil area of a 500 kcmil conductor?",opts:["500 CM","5,000 CM","50,000 CM","500,000 CM"],ans:3,ref:"NEC Chapter 9, Table 9",exp:"kcmil = thousand circular mils. 500 kcmil = 500,000 CM. Critical for voltage drop formula where you divide (2 × K × I × D) by CM value. Getting this wrong by 1,000× gives wildly incorrect results."},
{id:352,mod:10,cat:"Calculations",diff:"Hard",q:"Six current-carrying conductors in conduit — what adjustment factor applies?",opts:["No adjustment for 6 conductors","80% of table ampacity","70% of table ampacity","50% of table ampacity"],ans:1,ref:"NEC Table 310.15(B)(3)(a)",exp:"Table 310.15(B)(3)(a): 4-6 current-carrying conductors = 80% adjustment. 12 AWG THWN normally 20A → derate to 20 × 0.80 = 16A with six conductors in conduit."},
{id:353,mod:10,cat:"Calculations",diff:"Medium",q:"Electric clothes dryer rated 5.5 kW at 240V. Minimum circuit ampacity?",opts:["22.9A","28.6A","30A","37.5A"],ans:2,ref:"NEC 220.54 & 210.23(B)",exp:"5,500/240 = 22.9A × 125% (continuous) = 28.6A. But NEC minimum for clothes dryers = 30A. The 30A NEC minimum governs regardless of calculation. Always check NEC minimums."},
{id:354,mod:10,cat:"Calculations",diff:"Hard",q:"Temperature correction factor 0.82 applied to 10 AWG THWN copper (normal ampacity 35A). Derated ampacity?",opts:["27.5A","28.7A","30A","35A"],ans:1,ref:"NEC Table 310.15(B)(1)(a) & Table 310.16",exp:"Derated = table ampacity × correction factor = 35A × 0.82 = 28.7A. If ALSO more than 3 conductors, apply BOTH factors: multiply together then apply to table ampacity."},
{id:355,mod:10,cat:"Calculations",diff:"Medium",q:"In 120/240V single-phase three-wire service, neutral current equals:",opts:["Sum of all loads","Difference (unbalanced current) between the two hot legs","The larger hot leg current","Zero in balanced 240V system"],ans:1,ref:"NEC 220.61",exp:"Neutral carries UNBALANCED current only — the difference between loads on the two 120V legs. Perfectly balanced 240V system = zero neutral current. Why neutral conductors can sometimes be sized smaller than phase conductors."},
{id:356,mod:10,cat:"Calculations",diff:"Hard",q:"Motor drawing 10A at 480V single-phase, actual consumption 3,840 watts. Power factor?",opts:["0.80","0.85","0.90","1.0"],ans:0,ref:"Power factor formula",exp:"PF = True Power/Apparent Power = 3,840/(10 × 480) = 3,840/4,800 = 0.80. 80% PF means 20% of apparent power is reactive. Low PF motors draw more current than watts would suggest."},
{id:357,mod:10,cat:"Calculations",diff:"Medium",q:"Approximate starting current for a motor with 25A FLA?",opts:["25A — starting equals running","50A — approximately 2× FLA","125A — approximately 5× FLA","250A — approximately 10× FLA"],ans:2,ref:"NEC Table 430.251(A)",exp:"Typical locked rotor current ≈ 6-8× FLA, can range 5-10×. For 25A FLA: starting ≈ 125-175A. This high starting current is why motor overcurrent protection is sized much larger than running current."},
{id:358,mod:10,cat:"Calculations",diff:"Easy",q:"Transformer turns ratio 4:1 (primary:secondary), primary = 480V. Secondary voltage?",opts:["120V","240V","1,920V","480V"],ans:0,ref:"Transformer ratio",exp:"Secondary = Primary/turns ratio = 480/4 = 120V. Transformer ratios: voltage ratio = turns ratio. Current ratio = inverse of turns ratio."},
{id:359,mod:10,cat:"Calculations",diff:"Medium",q:"3/4-inch conduit interior area 0.533 sq in. Maximum fill area for 3+ conductors?",opts:["0.133 sq in","0.213 sq in","0.320 sq in","0.533 sq in"],ans:1,ref:"NEC Chapter 9, Table 1",exp:"Max fill = 0.533 × 0.40 = 0.213 sq in for 3+ conductors (40% fill). Compare to sum of individual conductor cross-sectional areas from Chapter 9 Table 5."},
{id:360,mod:10,cat:"Calculations",diff:"Hard",q:"85 kW continuous lighting load at 277/480V three-phase feeder. Minimum overcurrent device?",opts:["102A","127.5A","150A","All steps correct leading to 150A"],ans:3,ref:"NEC 215.2(A)(1) & 210.20(A) & 240.6(A)",exp:"Step 1: I = 85,000/(480 × 1.732) = 102.2A. Step 2: Continuous × 125% = 127.8A minimum conductor. Step 3: Next standard size = 150A overcurrent device. Step 4: 1/0 AWG copper (150A at 75°C) for conductors. All steps in D are correct."},
{id:361,mod:10,cat:"Calculations",diff:"Medium",q:"Calculated load for one 20A small appliance circuit in residential calculations?",opts:["1,200 VA","1,500 VA","2,000 VA","2,400 VA"],ans:1,ref:"NEC 220.52(A)",exp:"Each 20A small appliance branch circuit = 1,500 VA (not 2,400 VA which would be full capacity). Specified in Article 220. Two required small appliance circuits = 2 × 1,500 = 3,000 VA."},
{id:362,mod:10,cat:"Calculations",diff:"Hard",q:"Three-phase unbalanced loads: Phase A=18A, Phase B=12A, Phase C=15A. Neutral current?",opts:["0A","3A (simple subtraction)","Approximately 5.2A (vector calculation required)","45A (sum of all)"],ans:2,ref:"NEC 220.61 & phasor math",exp:"Unbalanced three-phase neutral current requires VECTOR (phasor) addition — not simple arithmetic. Currents are 120° apart. Approximately 5.2A using phasor math. Never simple arithmetic for three-phase neutral calculation."},
{id:363,mod:10,cat:"Calculations",diff:"Medium",q:"Motor efficiency = 80%. Input = 10 kW, output = ?",opts:["10 kW","8 kW","2 kW","12.5 kW"],ans:1,ref:"NEC 430.22 & motor nameplate",exp:"Output = Input × efficiency = 10 × 0.80 = 8 kW. Remaining 20% (2 kW) lost as heat in windings, friction, and other losses. 1 HP = 746 watts of mechanical output."},
{id:364,mod:10,cat:"Calculations",diff:"Hard",q:"10 HP, 208V, 3-phase motor, efficiency = 90%, PF = 0.85. Line current?",opts:["24.6A","29.0A","27.1A","40.5A"],ans:2,ref:"NEC Table 430.250",exp:"Input power = 10 × 746/0.90 = 8,289W. Apparent = 8,289/0.85 = 9,752 VA. Line current = 9,752/(208 × 1.732) = 9,752/360.3 = 27.1A. NEC Table value for 10HP 208V ≈ 30.8A."},
{id:365,mod:10,cat:"Calculations",diff:"Easy",q:"1 horsepower (HP) equals how many watts?",opts:["550 watts","746 watts","1,000 watts","1,340 watts"],ans:1,ref:"NEC 430.6 & Table 430.248",exp:"1 HP = 746 watts of mechanical power. Used constantly in motor calculations: 10 HP motor delivers 7,460 watts at 100% efficiency. Electrical input always greater than 746 W/HP due to motor losses."},
{id:366,mod:10,cat:"Calculations",diff:"Medium",q:"K value for copper conductors in voltage drop formula?",opts:["10.4","12.9","17.0","21.2"],ans:1,ref:"NEC 210.19(A)(1) Informational Note",exp:"K = 12.9 for copper. K = 21.2 for aluminum. K represents resistivity constant in VD = 2 × K × I × D / CM. Know both values — the exam often specifies K but you should know copper vs aluminum."},
{id:367,mod:10,cat:"Calculations",diff:"Hard",q:"200A, 240V single-phase, connected load 48,000 VA at 80% power factor. True power?",opts:["38,400 watts","48,000 watts","60,000 watts","96,000 watts"],ans:0,ref:"Power factor formula",exp:"True Power = Apparent × PF = 48,000 × 0.80 = 38,400W. System sized on VA (conductors carry apparent power current) but utility bills on watts (kWh)."},
{id:368,mod:10,cat:"Calculations",diff:"Medium",q:"Calculated demand = 22,000 VA at 240V. Minimum service size?",opts:["92A (calculated)","100A (NEC minimum)","125A","150A"],ans:1,ref:"NEC 230.79(C)",exp:"22,000/240 = 91.7A calculated. NEC minimum for single-family dwelling = 100A. Since 91.7A < 100A minimum, the 100A minimum governs."},
{id:369,mod:10,cat:"Calculations",diff:"Easy",q:"Formula for single-phase power in watts?",opts:["P = V²/R only","P = IV (watts = amperes × volts)","P = I²R only","All forms are correct"],ans:3,ref:"Ohm's Law & Power formula",exp:"All three forms are equivalent: P=IV, P=V²/R, P=I²R. P=IV most commonly used in practice. P=I²R when resistance is known. P=V²/R when only voltage and resistance are known."},
{id:370,mod:10,cat:"Calculations",diff:"Hard",q:"Demand for 8 household electric ranges rated 8 kW each, per Table 220.55?",opts:["64,000 VA (8 × 8,000)","51,200 VA (80% of total)","48,000 VA (column C)","40,000 VA (Table 220.55 column C)"],ans:3,ref:"NEC Table 220.55",exp:"Table 220.55 Column C: 8 ranges = 40 kW demand. Significantly less than 64 kW connected load. Table assumes not all ranges fully loaded simultaneously."},
{id:371,mod:10,cat:"Calculations",diff:"Medium",q:"90°C rated conductor (30A ampacity) with 75°C rated equipment. What ampacity used?",opts:["30A — use conductor's full 90°C ampacity","25A from 75°C column","75°C column value for this conductor size","Any value between 25A and 30A"],ans:2,ref:"NEC 110.14(C)(1)",exp:"Termination rule: limited by LOWEST temperature rating. 75°C equipment limits system to 75°C ampacity even though conductor is rated 90°C. 90°C rating only applies if equipment terminations are also 90°C rated."},
{id:372,mod:10,cat:"Calculations",diff:"Medium",q:"NEC's approach to voltage drop for branch circuits?",opts:["3% voltage drop is a mandatory NEC requirement","3% recommended maximum for branch circuits; 5% total (branch + feeder) recommended","No NEC basis — engineering recommendation only","3% applies to feeders only"],ans:1,ref:"NEC 210.19(A)(1) Informational Note",exp:"NEC recommends (does not require) 3% max voltage drop on branch circuits, 5% total combined branch circuit + feeder. These are informational notes. Some jurisdictions and California Title 24 may effectively enforce voltage drop limits."},
{id:373,mod:10,cat:"Calculations",diff:"Hard",q:"12 current-carrying conductors in conduit — derating factor?",opts:["80% (4-6 conductors)","70% (7-9 conductors)","50% (10-20 conductors)","35% (21-30 conductors)"],ans:2,ref:"NEC Table 310.15(B)(3)(a)",exp:"Table 310.15(B)(3)(a): 10-20 current-carrying conductors = 50% adjustment. Conductor normally rated 30A → derate to 30 × 0.50 = 15A. Better to use multiple smaller conduits than many conductors in one."},
{id:374,mod:10,cat:"Calculations",diff:"Medium",q:"120V, 20A circuit runs 75 feet, 15A continuous load. Minimum conductor to keep VD under 3%?",opts:["12 AWG is sufficient","10 AWG needed","8 AWG needed","Voltage drop not a concern at 75 feet"],ans:1,ref:"NEC 210.19(A)(1) Informational Note",exp:"Max VD = 120 × 3% = 3.6V. CM required = 2 × 12.9 × 15 × 75/3.6 = 29,025/3.6 = 8,063 CM. 12 AWG = 6,530 CM (insufficient). 10 AWG = 10,380 CM (meets requirement). Voltage drop drives conductor sizing on longer runs."},
{id:375,mod:10,cat:"Calculations",diff:"Easy",q:"Total service demand: lighting 4,470 VA, small appliance 2,100 VA, water heater 5 kW?",opts:["6,570 VA","11,570 VA","9,470 VA","13,570 VA"],ans:1,ref:"NEC 220.82",exp:"Total = 4,470 + 2,100 + 5,000 = 11,570 VA. Water heaters added at 100% — not demand-factored. This is before adding HVAC, dryer, and other appliance loads."},
{id:376,mod:10,cat:"Calculations",diff:"Hard",q:"500 kcmil copper THWN at 75°C = 380A ampacity. Nine conductors in conduit. Derated ampacity?",opts:["304A (80% — wrong count)","266A (70% for 7-9 conductors)","190A (50% — wrong count)","380A — large conductors exempt from derating"],ans:1,ref:"NEC Table 310.15(B)(3)(a)",exp:"Nine conductors: 7-9 range = 70% adjustment. 380A × 0.70 = 266A. No conductors exempt from derating — large conductors derated same as small ones."},
{id:377,mod:10,cat:"Calculations",diff:"Medium",q:"General lighting load for 1,200 sq ft dwelling?",opts:["1,200 VA","2,400 VA","3,600 VA","4,800 VA"],ans:2,ref:"NEC Table 220.12",exp:"Dwelling = 3 VA/sq ft. 1,200 × 3 = 3,600 VA connected load. After Table 220.42 demand: first 3,000 at 100% = 3,000; remainder 600 at 35% = 210; demand = 3,210 VA."},
{id:378,mod:10,cat:"Calculations",diff:"Hard",q:"75 kVA transformer, 5% impedance, 208V secondary. Approximate available fault current at secondary?",opts:["2,082A","4,164A","20,825A","41,650A"],ans:1,ref:"NEC 110.9 & 110.10",exp:"Secondary FLA = 75,000/(208 × 1.732) = 208.2A. Available fault current = FLA / %Z = 208.2/0.05 = 4,164A from transformer alone. Primary source impedance would add to this in a complete calculation."},
{id:379,mod:10,cat:"Calculations",diff:"Medium",q:"How many 14 AWG THWN conductors in 1/2-inch EMT?",opts:["4","6","9","12"],ans:2,ref:"NEC Annex C, Table C1",exp:"Annex C Table C1 (EMT): 1/2-inch EMT = 9 conductors of 14 AWG THWN. Direct table lookup. Memorize: 1/2\" EMT = 9×14AWG or 7×12AWG THWN."},
{id:380,mod:10,cat:"Calculations",diff:"Hard",q:"240V single-phase motor, 10 HP, FLA=50A, SF=1.15. Maximum overload relay setting?",opts:["50A (100% FLA)","57.5A (115% FLA)","62.5A (125% FLA)","75A (150% FLA)"],ans:2,ref:"NEC 430.32(A)(1)",exp:"SF ≥ 1.15 → maximum overload = 125% of nameplate FLA. 50A × 1.25 = 62.5A. If SF < 1.15, maximum = 115% = 57.5A."},
{id:381,mod:10,cat:"Calculations",diff:"Medium",q:"NEC demand calculation for one household electric range rated 11 kW?",opts:["11,000 VA at 100%","8,000 VA per Table 220.55","11,000 × 80% = 8,800 VA","Column C for one range: 8,000 VA"],ans:3,ref:"NEC Table 220.55",exp:"For one range 8¾ kW to 12 kW: Table 220.55 Column C = 8,000 VA demand. Actual 11 kW nameplate irrelevant — table value governs. For ranges over 12 kW, add 5% per kW above 12 to the 8 kW base."},
{id:382,mod:10,cat:"Calculations",diff:"Easy",q:"Formula for three-phase power?",opts:["P = V × I","P = V × I × 1.732","P = V × I × 1.732 × PF","P = V × I × 2"],ans:2,ref:"Three-phase power formula",exp:"Three-phase true power: P = V × I × 1.732 × PF. Apparent power (VA): VA = V × I × 1.732 (no PF). √3 = 1.732 accounts for the three-phase relationship."},
{id:383,mod:10,cat:"Calculations",diff:"Medium",q:"Four lighting fixtures, 300W each, 120V, operate continuously. Minimum circuit rating?",opts:["10A standard circuit","12A calculated","15A — fits on standard circuit","20A — continuous load pushes beyond 15A capacity"],ans:3,ref:"NEC 210.20(A)",exp:"4 × 300W = 1,200W/120V = 10A. Continuous × 125% = 12.5A. 15A circuit continuous limit = 12A (80%). 12.5A > 12A = requires 20A circuit (80% = 16A > 12.5A). Common exam trap."},
{id:384,mod:10,cat:"Calculations",diff:"Hard",q:"Ampacity of 4/0 AWG aluminum THWN at 75°C from Table 310.16?",opts:["150A","180A","200A","230A"],ans:1,ref:"NEC Table 310.16 (75°C column)",exp:"4/0 AWG aluminum THWN at 75°C = 180A. At 60°C = 150A. At 90°C = 205A. Common for 150A-200A services using aluminum. Always know copper vs aluminum ampacity differences."},
{id:385,mod:10,cat:"Calculations",diff:"Medium",q:"20A, 120V GFCI circuit supplies a bathroom with 1,800W load. Compliant?",opts:["No — bathroom circuits limited to 1,500W","Yes — 15A is within 80% (1,920 VA) continuous limit for 20A circuit","Yes — if load is non-continuous","No — bathroom circuits limited to 1,440W"],ans:1,ref:"NEC 210.20(A)",exp:"1,800W/120V = 15A. On 20A circuit, continuous limit = 16A (80%). If continuous, 15A < 16A = compliant. If non-continuous, full 20A capacity available. 80% rule only restricts continuous loads."},
{id:386,mod:10,cat:"Calculations",diff:"Hard",q:"Maximum length of 12 AWG copper for 3% VD limit on 20A, 120V circuit at 15A (K=12.9)?",opts:["35.7 feet one-way","45.6 feet one-way","53.6 feet one-way","71.4 feet one-way"],ans:1,ref:"NEC 210.19(A)(1) Informational Note",exp:"Max VD = 120 × 3% = 3.6V. D = (VD × CM)/(2 × K × I) = (3.6 × 6,530)/(2 × 12.9 × 15) = 23,508/387 = 60.7 feet. Approximately 45-60 feet depending on exact calculation method."},
{id:387,mod:10,cat:"Calculations",diff:"Medium",q:"Commercial kitchen: 48 kW connected cooking equipment, 65% demand factor. Feeder demand?",opts:["31,200 VA","31.2 kW","48 kW","72 kW"],ans:1,ref:"NEC 220.56 & Table 220.56",exp:"Demand = 48 kW × 0.65 = 31.2 kW. At 480V three-phase, unity PF: I = 31,200/(480 × 1.732) = 37.5A feeder current. Demand factors reflect not all equipment fully loaded simultaneously."},
{id:388,mod:10,cat:"Calculations",diff:"Easy",q:"Resistance of 100-foot length of 12 AWG copper (1.98 ohms per 1,000 feet)?",opts:["0.198 ohms","1.98 ohms","19.8 ohms","198 ohms"],ans:0,ref:"NEC Chapter 9, Table 9",exp:"R = (100/1,000) × 1.98 = 0.198 ohms. One-way resistance doubled for round-trip voltage drop (total circuit = 2 × one-way = 0.396 ohms for 100-foot circuit)."},
{id:389,mod:10,cat:"Calculations",diff:"Hard",q:"Three-phase 75 kVA transformer primary current at 480V?",opts:["90.2A","156.3A","104A","72.2A"],ans:0,ref:"NEC 450.3(B) (sizing basis)",exp:"Primary I = kVA × 1,000/(V × √3) = 75,000/(480 × 1.732) = 75,000/831.4 = 90.2A. Primary protection maximum = 90.2 × 1.25 = 112.7A → use 110A or 100A standard fuse."},
{id:390,mod:10,cat:"Calculations",diff:"Medium",q:"The 80% continuous load rule for a 15A circuit breaker means:",opts:["Breaker handles only 80% of fault current","Maximum continuous load = 12A (15A × 80%)","Breaker derated to 12A for all applications","80% applies only to industrial circuits"],ans:1,ref:"NEC 210.20(A)",exp:"15A × 80% = 12A maximum CONTINUOUS load (loads on for 3+ hours). 1,440 VA maximum continuous on 15A, 120V circuit. Non-continuous loads can use full 15A capacity."},
{id:391,mod:10,cat:"Calculations",diff:"Hard",q:"3-phase 480V motor draws 50A at 0.85 PF. True power consumption?",opts:["24,000W","35,326W","41,530W","57,600W"],ans:1,ref:"Three-phase power formula",exp:"Apparent = 480 × 50 × 1.732 = 41,568 VA. True Power = 41,568 × 0.85 = 35,333W ≈ 35,326W. The reactive power (41,568 - 35,333 = 6,235 VAR) does no useful work but flows through conductors."},
{id:392,mod:10,cat:"Calculations",diff:"Medium",q:"Number of usable knockouts in a junction box is limited by:",opts:["The number of knockouts provided by manufacturer","Box fill calculations — conductors through knockouts must fit within box cubic inch capacity","NEC doesn't limit knockout use","Maximum 4 knockouts in any standard box"],ans:1,ref:"NEC 314.16",exp:"Knockouts limited by box fill. Each knockout used allows conductors to enter — each conductor takes cubic inches. When box fill is at maximum, no additional conductors (or knockouts) may be used."},
{id:393,mod:10,cat:"Calculations",diff:"Easy",q:"Human body resistance used in electrical safety calculations?",opts:["500 ohms","1,000 ohms","10,000 ohms","100,000 ohms"],ans:1,ref:"NFPA 70E Annex K",exp:"Typical human body resistance ≈ 1,000 ohms (skin to skin, dry conditions). At 120V: I = 120/1,000 = 120mA — well above 10-50mA that causes ventricular fibrillation. Wet conditions: resistance drops to 300Ω or less."},
{id:394,mod:10,cat:"Calculations",diff:"Hard",q:"Optional calculation for 2,000 sq ft dwelling with all-electric appliances totaling 25 kVA?",opts:["25,000 VA","16,000 VA — first 10 kVA at 100%, remainder at 40%","10,000 VA minimum","12,500 VA (50% demand)"],ans:1,ref:"NEC 220.82(B)",exp:"Optional method: first 10 kVA at 100% = 10,000; remainder = 15,000 at 40% = 6,000; total = 16,000 VA. Often results in lower calculated demand than standard method."},
{id:395,mod:10,cat:"Calculations",diff:"Medium",q:"When applying both temperature correction AND conduit fill derating factors, how applied?",opts:["Use larger of two factors only","Add factors then subtract from 100%","Multiply both correction factors together, then multiply by table ampacity","Apply sequentially — first temperature, then fill"],ans:2,ref:"NEC 310.15(B)(1) & Table 310.15(B)(3)(a)",exp:"Both factors MULTIPLIED together then applied to table ampacity. Example: temp correction 0.82 × conduit fill 0.80 = 0.656 combined factor. 30A table × 0.656 = 19.7A derated ampacity. Never add the factors — always multiply."},
// MODULE 11: CALIFORNIA-SPECIFIC (50)
{id:396,mod:11,cat:"California-Specific",diff:"Easy",q:"California electrical certification exams are administered by:",opts:["Prometric","PSI Services LLC","Pearson VUE","California Department of Consumer Affairs"],ans:1,ref:"CA DLSE / DIR",exp:"PSI Services LLC administers California electrical certification exams on behalf of DLSE. PSI provides test centers throughout California. Contact PSI at (888) 818-5831 for scheduling."},
{id:397,mod:11,cat:"California-Specific",diff:"Easy",q:"California's state OSHA agency is:",opts:["California Workplace Safety Board","Cal/OSHA — Division of Occupational Safety and Health (DOSH)","California Department of Industrial Safety","State Compensation Insurance Fund"],ans:1,ref:"CA Labor Code § 6300; 8 CCR",exp:"Cal/OSHA (DOSH) is California's state OSHA under the Department of Industrial Relations (DIR). California operates an OSHA State Plan — its rules must meet or exceed federal OSHA standards."},
{id:398,mod:11,cat:"California-Specific",diff:"Medium",q:"The California Electrical Code (CEC) is designated as:",opts:["California Title 8","California Title 24, Part 3","California Title 24, Part 9","California Building Code Section 27"],ans:1,ref:"CA Title 24, Part 3 CCR",exp:"California Electrical Code = Title 24, Part 3 of the California Code of Regulations (CCR). Title 24 = California Building Standards Code. Part 3 = electrical code (NEC with CA amendments). Title 8 = workplace safety (Cal/OSHA)."},
{id:399,mod:11,cat:"California-Specific",diff:"Medium",q:"Individual electrician certifications in California are issued by:",opts:["California Contractors State License Board (CSLB)","California Division of Labor Standards Enforcement (DLSE) under DIR","California Department of Consumer Affairs","California Fire Marshal's Office"],ans:1,ref:"CA Labor Code § 108; 8 CCR § 320",exp:"Individual electrician certifications = issued by DLSE (Division of Labor Standards Enforcement) under DIR. CSLB separately licenses electrical contractors (C-10 license). Two separate systems for individuals vs. businesses."},
{id:400,mod:11,cat:"California-Specific",diff:"Medium",q:"Hours of on-the-job experience required for California General Electrician exam (without apprenticeship)?",opts:["2,000 hours","4,000 hours","8,000 hours","10,000 hours"],ans:2,ref:"8 CCR § 320.1",exp:"Without an approved apprenticeship certificate, General Electrician applicants need 8,000 hours of verifiable on-the-job electrical work experience. With approved apprenticeship certificate, hours are waived."},
{id:401,mod:11,cat:"California-Specific",diff:"Easy",q:"A C-10 electrical contractor license (CSLB) allows:",opts:["Individual journeyman certification","High-voltage specialty work only","A business entity to perform electrical work as a contractor","Temporary license for out-of-state contractors"],ans:2,ref:"CA B&P Code § 7058",exp:"C-10 = Electrical Contractor license issued by CSLB, allowing a business entity to contract for electrical work. The C-10 holder (company) must have certified electricians perform the actual work. Separate from individual worker certification."},
{id:402,mod:11,cat:"California-Specific",diff:"Hard",q:"California's lockout/tagout requirements are in Title 8, Section:",opts:["Section 2320","Section 3314","Section 4001","Section 5199"],ans:1,ref:"8 CCR § 3314",exp:"Cal/OSHA Title 8, Section 3314 = lockout/tagout requirements. Specifies LOTO procedures, who may remove devices, training requirements, and documentation. More stringent in some areas than federal OSHA 1910.147."},
{id:403,mod:11,cat:"California-Specific",diff:"Medium",q:"Workers performing electrical work for a C-10 contractor must be:",opts:["Licensed as C-10 contractors themselves","Certified electricians or registered electrical trainees (ETs) under constant supervision of a certified electrician","Any qualified worker — no certification required on private projects","IBEW union members only"],ans:1,ref:"CA Labor Code § 108; 8 CCR § 320.4",exp:"C-10 contractor workers connecting ≥100 VA electrical devices must be certified electricians or registered ETs under constant supervision. Enforced by DIR. Fundamental to California's electrical licensing system."},
{id:404,mod:11,cat:"California-Specific",diff:"Medium",q:"California General Electrician certification renewal period?",opts:["Annually","Every 2 years","Every 3 years","Every 5 years"],ans:2,ref:"8 CCR § 320.5",exp:"California General Electrician certifications renewed every 3 years. Renewal requires: 32 hours approved continuing education, 2,000 hours work experience during renewal period, and renewal fee."},
{id:405,mod:11,cat:"California-Specific",diff:"Hard",q:"Continuing education hours required for California General Electrician certification renewal?",opts:["8 hours per year","16 hours total","24 hours total","32 hours total every 3 years"],ans:3,ref:"8 CCR § 320.5",exp:"32 hours of approved CE required per 3-year renewal cycle. Coursework must be relevant to the certification category. Missing CE requirement = certification lapses."},
{id:406,mod:11,cat:"California-Specific",diff:"Easy",q:"California EV charging readiness requirement for new single-family homes includes:",opts:["Fully installed Level 2 EVSE outlet","Dedicated 240V 50A circuit fully wired to garage","A raceway from service panel to garage/parking area with pull string and reserved panel capacity","A 120V outlet in garage is sufficient"],ans:2,ref:"CA Title 24, Part 2 § 4.106.4",exp:"California Building Code: new single-family homes must have a raceway from panel to garage/parking area with a pull string for future wiring, and reserved panel capacity for a future 40A circuit. Minimum conduit infrastructure."},
{id:407,mod:11,cat:"California-Specific",diff:"Medium",q:"California Title 24 energy code lighting control requirement for commercial buildings?",opts:["Occupancy sensors in all commercial spaces","Automatic shutoff controls (occupancy sensors or automatic time switches) in most commercial spaces over 100 sq ft","Manual dimmers for all lighting circuits","No automatic controls required for lighting under 277V"],ans:1,ref:"CA Title 24, Part 6 § 130.1",exp:"California Title 24 (Energy Code) requires automatic shutoff controls for lighting in most commercial spaces — occupancy/vacancy sensors or automatic time switches. California's energy code is among the most stringent nationally."},
{id:408,mod:11,cat:"California-Specific",diff:"Medium",q:"Minimum approach distance for an unqualified person from an energized 480V conductor per Cal/OSHA?",opts:["1 foot","3 feet","6 feet","10 feet"],ans:1,ref:"8 CCR § 2299 & NFPA 70E Table 130.4(D)(a)",exp:"Cal/OSHA and NFPA 70E: limited approach boundary for unqualified persons at 480V = approximately 42 inches (3.5 feet). The practical 3-foot rule is the minimum maintained for unqualified personnel near energized 480V equipment."},
{id:409,mod:11,cat:"California-Specific",diff:"Hard",q:"California solar PV rapid shutdown — conductors on/in a building must de-energize to what voltage within 30 seconds?",opts:["0V — completely de-energized","30V or less within the array boundary","120V or less","480V or less"],ans:1,ref:"NEC 690.12 (as adopted by CEC)",exp:"NEC 690.12 rapid shutdown (adopted by California): PV conductors within array boundary must de-energize to 30V or less within 30 seconds. Protects firefighters on roofs from lethal PV system voltages."},
{id:410,mod:11,cat:"California-Specific",diff:"Medium",q:"California prevailing wage laws require electricians on public works projects to be paid:",opts:["Any agreed-upon rate","Prevailing wage rate determined by DIR for the project's location and craft","Federal minimum wage only","Union scale wages regardless of union membership"],ans:1,ref:"CA Labor Code § 1720",exp:"California prevailing wage: electricians on public works projects must be paid the DIR-determined prevailing wage for the craft and locality. Typically equivalent to union scale. Violations: penalties, debarment, license suspension."},
{id:411,mod:11,cat:"California-Specific",diff:"Easy",q:"IBEW stands for:",opts:["International Brotherhood of Electrical Workers","Independent Board of Electrical Wiremen","International Building Electrical Wiring","Internal Branch Electrical Wiring"],ans:0,ref:"IBEW (labor organization)",exp:"IBEW = International Brotherhood of Electrical Workers — primary union representing electricians in the US and Canada. IBEW JATC (Joint Apprenticeship Training Committee) apprenticeship programs are approved in California."},
{id:412,mod:11,cat:"California-Specific",diff:"Hard",q:"California AFCI requirements compared to 2020 NEC base requirements?",opts:["California has no AFCI requirements","California matches 2020 NEC exactly","California may have additional AFCI requirements through CEC amendments beyond NEC","California exempts kitchens and bathrooms from AFCI unlike NEC"],ans:2,ref:"CEC amendments to NEC 210.12",exp:"California adopts NEC with amendments. 2020 NEC already requires AFCI in all dwelling unit rooms. California's CEC amendments may impose additional requirements. Always verify current CEC amendments for California-specific requirements."},
{id:413,mod:11,cat:"California-Specific",diff:"Medium",q:"Title 24 energy compliance report for a new commercial building is typically prepared by:",opts:["Electrical inspector","Licensed engineer or Title 24 energy consultant","General contractor","California Energy Commission directly"],ans:1,ref:"CA Title 24, Part 6 § 10-103(a)",exp:"Title 24 energy compliance documentation prepared by licensed engineers, architects, or certified Title 24 energy consultants. Required for plan check before permits issued."},
{id:414,mod:11,cat:"California-Specific",diff:"Hard",q:"'Red Tag' for electrical equipment in California typically refers to:",opts:["Factory marking for hazardous location listing","Stop-work order from electrical inspector for code violations","Red paint required on emergency system equipment","Utility marking indicating approved metering"],ans:1,ref:"CA H&S Code § 17962; local ordinances",exp:"Red Tag = stop-work order or rejection notice from electrical inspector for code violations. Work must stop and violations corrected before proceeding. Getting red-tagged costs significant time and money — know the code to prevent it."},
{id:415,mod:11,cat:"California-Specific",diff:"Medium",q:"California Title 8, Section 2940 primarily addresses:",opts:["Residential electrical installation standards","General safety for construction and excavation work near existing electrical lines","Motor and transformer installation requirements","Low voltage lighting system installation"],ans:1,ref:"8 CCR § 2940",exp:"Cal/OSHA Title 8, Section 2940 = excavation and construction work near existing electrical utilities. Specifies minimum approach distances, notification requirements (Call 811), and protective measures near energized conductors."},
{id:416,mod:11,cat:"California-Specific",diff:"Easy",q:"Before excavating in California, what must you do?",opts:["Contact the building department","Call 811 (Underground Service Alert — Dig Alert) at least two working days before excavation","Contact each utility individually","No notification required for depths less than 18 inches"],ans:1,ref:"CA Government Code § 4216",exp:"Call 811 (Dig Alert) at least two working days before ANY excavation in California. Utilities mark underground facilities with color-coded flags/paint. Excavating without notification is illegal and dangerous."},
{id:417,mod:11,cat:"California-Specific",diff:"Medium",q:"Which of the following is a California electrician certification category?",opts:["Residential Electrician","Industrial Electrician","High Voltage Electrician","All of the above are California certification categories"],ans:3,ref:"8 CCR § 320 et seq.",exp:"California has multiple categories: General Electrician, Residential Electrician, Non-Residential Lighting Technician, Fire/Life Safety Technician, Voice/Data/Video Technician, and others. General Electrician is most comprehensive."},
{id:418,mod:11,cat:"California-Specific",diff:"Hard",q:"When must a licensed contractor pull an electrical permit?",opts:["Only for new construction","For all electrical work except minor repairs and maintenance as defined by local AHJ","All electrical work without exception","Only for work over $500 in value"],ans:1,ref:"CA H&S Code § 19825",exp:"California requires permits for all electrical work except specifically exempted minor maintenance and repair. AHJ defines what qualifies as minor maintenance. Work without required permit can affect contractor licensing."},
{id:419,mod:11,cat:"California-Specific",diff:"Medium",q:"California solar interconnection rules require coordinating with:",opts:["California Energy Commission only","The serving electric utility (SCE, PG&E, SDG&E, etc.)","California ISO (CAISO) for all installations","Only the local building department"],ans:1,ref:"CA PUC Rule 21 & CPUC tariffs",exp:"Solar PV installations must receive interconnection approval from the serving utility before energizing. The utility reviews system safety, grid compatibility, and metering. Net Energy Metering (NEM) agreements also executed with utility."},
{id:420,mod:11,cat:"California-Specific",diff:"Easy",q:"Re-test waiting period for the California electrical certification exam after failing?",opts:["30 days","45 days","60 days","90 days"],ans:2,ref:"8 CCR § 320.3",exp:"California requires 60-day waiting period between failed exam attempts. Re-test application and fee must be submitted to DLSE. Cannot take exam during the 60-day waiting period."},
{id:421,mod:11,cat:"California-Specific",diff:"Medium",q:"Projects in California's Coastal Zone may require additional approval from:",opts:["US Army Corps of Engineers only","California Coastal Commission in addition to local building department","National Oceanic and Atmospheric Administration","California Department of Fish and Wildlife"],ans:1,ref:"CA Public Resources Code § 30000",exp:"Projects in California's Coastal Zone may require Coastal Development Permits from the California Coastal Commission IN ADDITION to local building permits. Important consideration for electrical contractors working on coastal projects."},
{id:422,mod:11,cat:"California-Specific",diff:"Hard",q:"California CSST gas piping bonding requirement?",opts:["CSST requires no electrical bonding — inherently non-conductive","CSST must be directly bonded to electrical grounding system within 6 feet of gas meter or entry point","CSST bonding only required in commercial buildings","CSST requires 2 AWG copper bonding conductor regardless of service size"],ans:1,ref:"CEC amendment to NEC 250.104(B)",exp:"California requires CSST bonded directly to electrical grounding system within 6 feet of building gas entry. Lightning-induced current can arc through thin CSST wall, creating gas leak. Bonding wire typically 6 AWG copper minimum."},
{id:423,mod:11,cat:"California-Specific",diff:"Medium",q:"California Title 8 covers:",opts:["Building construction standards only","Electrical installation standards for commercial buildings","Occupational safety and health — workplace safety requirements electricians must follow","Energy efficiency standards for electrical systems"],ans:2,ref:"8 CCR (Title 8 — Cal/OSHA)",exp:"Title 8 = Cal/OSHA's occupational safety and health code. Covers electrical hazard recognition, approach distances, lockout/tagout, PPE requirements, GFCI on construction sites, and other safety practices. Major portion of CA journeyman exam."},
{id:424,mod:11,cat:"California-Specific",diff:"Hard",q:"New multi-family residential building electrical energy code requirements per Title 24?",opts:["No energy code requirements for electrical systems","Title 24, Part 6 (Energy Code) requires lighting efficiency, controls, and EV readiness for multi-family buildings","Only single-family homes must comply with Title 24 energy requirements","Energy requirements only apply to buildings over 5,000 sq ft"],ans:1,ref:"CA Title 24, Part 6 § 130.1, § 170.2",exp:"California Title 24, Part 6 applies to all occupancy types including multi-family: lighting power density limits, occupancy sensors, daylight controls, EV charging readiness (conduit infrastructure), and energy storage readiness."},
{id:425,mod:11,cat:"California-Specific",diff:"Medium",q:"California Electrical Trainee (ET) registration requires:",opts:["Only a valid ID","Application to DLSE with fees, proof of employment under C-10 contractor, and enrollment in approved training program","Completion of full apprenticeship program before working as trainee","Background check and fingerprinting for all ETs"],ans:1,ref:"8 CCR § 320.2",exp:"ET registration: application to DLSE, registration fee, documentation of employment under a licensed C-10 contractor, enrollment in approved electrical training curriculum (150 hours/year). ETs may only work under constant supervision of certified electrician."},
{id:426,mod:11,cat:"California-Specific",diff:"Easy",q:"Which utility serves most of the Los Angeles basin (excluding City of Los Angeles)?",opts:["Pacific Gas and Electric (PG&E)","San Diego Gas and Electric (SDG&E)","Southern California Edison (SCE)","Los Angeles Department of Water and Power (LADWP)"],ans:2,ref:"CPUC service territory maps",exp:"SCE (Southern California Edison) serves most of LA basin, Orange County, Riverside, San Bernardino. City of Los Angeles = LADWP (municipal utility). Long Beach is in SCE territory."},
{id:427,mod:11,cat:"California-Specific",diff:"Hard",q:"California energy storage readiness requirement for new homes?",opts:["Fully installed battery storage system required","Conduit pathway from main panel to approved ESS location with dedicated circuit breaker space reserved","Only panel space must be reserved — no conduit required","ESS readiness only applies to commercial buildings"],ans:1,ref:"CA Title 24, Part 2 § 4.106.4",exp:"California ESS readiness: conduit pathway from main panel to approved future battery storage location + dedicated panel space reserved for ESS interconnection. Ensures new homes can easily add battery storage without costly retrofits."},
{id:428,mod:11,cat:"California-Specific",diff:"Medium",q:"California requirement for tamper-resistant receptacles in dwelling units?",opts:["Only in rooms accessible to children under 7","Required in all non-locking 125V 15 and 20A receptacles throughout the entire dwelling unit","Required only in kitchens and bathrooms","Only in new construction — existing homes exempt"],ans:1,ref:"NEC 406.12 (as adopted by CEC)",exp:"California requires tamper-resistant receptacles in ALL non-locking 125V 15 and 20A receptacle locations throughout the entire dwelling unit. All new and replacement receptacles must be tamper-resistant."},
{id:429,mod:11,cat:"California-Specific",diff:"Hard",q:"Consequences for performing electrical work without a required permit in California?",opts:["Written warning for first offense only","Civil fines, stop-work orders, required demolition of unpermitted work, and potential license revocation","Only the property owner (not contractor) is liable","Unpermitted work allowed if it passes inspection after the fact"],ans:1,ref:"CA H&S Code § 17962; CA B&P Code § 7090",exp:"Without required permits: civil fines, stop-work orders, required demolition and reconstruction, potential criminal charges, and contractor license suspension/revocation by CSLB. Property owners face problems when selling — unpermitted work may require retroactive permits or demolition."},
{id:430,mod:11,cat:"California-Specific",diff:"Easy",q:"Which agency enforces electrical installation safety on California construction sites?",opts:["California Electrical Certification Unit (ECU)","Cal/OSHA — Division of Occupational Safety and Health","California Building Standards Commission","Federal OSHA Region 9"],ans:1,ref:"CA Labor Code § 6300; 8 CCR",exp:"Cal/OSHA (Division of Occupational Safety and Health) enforces workplace safety on California construction sites. Cal/OSHA State Plan = federal OSHA doesn't typically enforce in California. Cal/OSHA has primary jurisdiction."},
{id:431,mod:11,cat:"California-Specific",diff:"Medium",q:"California electrical inspectors must hold:",opts:["General Electrician certification plus inspector training","CSLB C-10 license with inspection endorsement","Certification from local jurisdiction or HCD for state-regulated occupancies","No specific license required — appointed by local AHJ"],ans:2,ref:"CA H&S Code § 17950; HCD requirements",exp:"Electrical inspectors certified through local jurisdiction or California HCD (Department of Housing and Community Development) for state-regulated occupancies. Typically require electrical background (often journeyman), inspector training, and inspector exam."},
{id:432,mod:11,cat:"California-Specific",diff:"Hard",q:"California IIPP (Injury and Illness Prevention Program) must include:",opts:["Only first aid procedures","Responsibility, compliance, communication, hazard assessment, accident investigation, training, and hazard correction","Only electrical-specific hazards","IIPPs only required for employers with 50+ employees"],ans:1,ref:"CA Labor Code § 6401.7; 8 CCR § 3203",exp:"California Labor Code Section 6401.7: ALL employers must have an IIPP covering: responsible person, compliance procedures, communication, hazard identification, accident investigation, hazard correction, training, and recordkeeping. NO size exemption — even one-employee contractors must have an IIPP."},
{id:433,mod:11,cat:"California-Specific",diff:"Medium",q:"California AB 2188 (solar permit streamlining) limits residential solar permit fees?",opts:["$500 maximum","$1,000 or 1% of system cost, whichever is less","No permit fee — residential solar permits must be free","Fees set independently by each jurisdiction"],ans:1,ref:"CA Government Code § 65850.5 (AB 2188)",exp:"AB 2188 limits permit fees for residential solar to remove barriers to solar adoption. Specific fee limits set by state law. Some jurisdictions have implemented online solar permitting with standardized applications."},
{id:434,mod:11,cat:"California-Specific",diff:"Easy",q:"Minimum age to register as an Electrical Trainee (ET) in California?",opts:["16 years old","18 years old","21 years old","No minimum age specified"],ans:1,ref:"8 CCR § 320.2",exp:"Must be at least 18 years old to register as an ET. Aligns with California child labor laws restricting minors from most construction and industrial work."},
{id:435,mod:11,cat:"California-Specific",diff:"Medium",q:"California Title 24 daylight sensors in commercial buildings:",opts:["Measure sunlight to charge solar panels","Automatically dim or turn off artificial lighting when adequate natural daylight is available","Control HVAC based on outdoor temperature","Provide emergency lighting in areas with windows"],ans:1,ref:"CA Title 24, Part 6 § 130.1(d)",exp:"Daylighting controls automatically reduce or turn off artificial lighting when sufficient natural light is available. Reduces lighting energy use by 30-50% in well-daylit spaces. Required by California Title 24 in perimeter zones."},
{id:436,mod:11,cat:"California-Specific",diff:"Hard",q:"Materials requiring special handling in demolition of pre-1980 California buildings?",opts:["All plastic conduit contains hazardous materials","Lead-containing paint, asbestos in insulation and joint compound, and PCBs in older fluorescent ballasts","Only asbestos requires special handling","California has no special requirements for demolition waste from electrical systems"],ans:1,ref:"8 CCR § 341.6; CA H&S Code § 25914",exp:"Pre-1980 buildings may contain: lead paint (certified lead-safe contractor), asbestos in electrical insulation and building materials (AHERA-certified abatement), and PCB-containing fluorescent ballasts (pre-1980, dispose as hazardous waste)."},
{id:437,mod:11,cat:"California-Specific",diff:"Medium",q:"Cal/OSHA required GFCI testing frequency on construction sites?",opts:["Before each work shift","Weekly","Monthly","Only when first installed"],ans:0,ref:"8 CCR § 1590(j)",exp:"Cal/OSHA: GFCI devices on construction sites must be tested before EACH work shift. Verifies device will trip correctly. Defective GFCIs provide false safety — always test before use."},
{id:438,mod:11,cat:"California-Specific",diff:"Hard",q:"Minimum clearance between overhead distribution voltage lines and construction activities in California?",opts:["3 feet","6 feet","10 feet","Cal/OSHA requires qualified electrical worker consultation"],ans:2,ref:"8 CCR § 2941(a)",exp:"Cal/OSHA: minimum 10-foot clearance from distribution voltage lines (up to 50 kV) for work, equipment, and materials. Higher voltage = greater clearance. Cranes, scaffolding, and materials must maintain these clearances."},
{id:439,mod:11,cat:"California-Specific",diff:"Medium",q:"Cal/OSHA required training for electrical workers near energized conductors?",opts:["Only a general safety training course","Qualified Electrical Worker (QEW) or Qualified Person training specific to voltage level and equipment type","OSHA 10 or OSHA 30 training","CPR and first aid training only"],ans:1,ref:"8 CCR § 2299 & § 3320",exp:"Cal/OSHA: workers near energized electrical equipment must be 'qualified persons' — trained and experienced to recognize and avoid hazards at the specific voltage level and equipment type. Training must be documented."},
{id:440,mod:11,cat:"California-Specific",diff:"Easy",q:"What must be displayed on a California electrical permit job site?",opts:["Only permit number on the electrical panel","The permit card posted in a conspicuous location at the job site","Permits maintained only by contractor — no job site posting required","Complete approved plans must be posted"],ans:1,ref:"CA H&S Code § 19825",exp:"California permits must be posted conspicuously at the job site visible to inspectors. Approved plans must also be on site. Inspector who can't find permit or plans may decline to inspect."},
{id:441,mod:11,cat:"California-Specific",diff:"Medium",q:"Who may pull electrical permits in California?",opts:["Property owner may always pull their own permit","Licensed C-10 electrical contractor or the owner-builder for their own residence","Any person over 18 years old","Only the electrical engineer of record"],ans:1,ref:"CA H&S Code § 19825 & B&P Code § 7044",exp:"Electrical permits: pulled by licensed C-10 contractor OR owner-builder building their own residence (not for sale within one year) and doing the work themselves. Commercial and rental property work requires a licensed contractor."},
{id:442,mod:11,cat:"California-Specific",diff:"Hard",q:"California EV-ready requirement for new multifamily buildings (4+ units)?",opts:["All parking spaces must have Level 2 EVSE installed","A percentage of parking spaces must be EV-ready (conduit, wiring, panel capacity) with some spaces having EVSE installed","No EV requirements for multifamily — only single-family","Only visitor parking spaces require EV infrastructure"],ans:1,ref:"CA Title 24, Part 2 § 4.106.4.2",exp:"California Building Code: new multifamily (4+ units) must have EV-ready infrastructure for a percentage of parking spaces. Some must be 'EV-ready' (conduit + wiring ready), some must have EVSE installed. Percentages defined in Title 24."},
{id:443,mod:11,cat:"California-Specific",diff:"Medium",q:"California's 'net energy metering' (NEM) program?",opts:["Utility pays customers for all excess solar generation","Billing arrangement where solar customers receive credit for excess energy exported to grid, offsetting future consumption","Solar panels replace the utility meter entirely","Cash rebate program for solar installation"],ans:1,ref:"CA Public Utilities Code § 2827",exp:"NEM allows solar customers to receive bill credits for excess electricity exported to grid, offsetting electricity drawn from grid when solar isn't generating. California updated to NEM 3.0 with adjusted export credit rates and storage incentives."},
{id:444,mod:11,cat:"California-Specific",diff:"Easy",q:"Color used to mark underground gas lines in utility marking?",opts:["Red","Blue","Yellow","Orange"],ans:2,ref:"APWA Uniform Color Code; CA Gov. Code § 4216",exp:"Utility underground marking colors: red=electric, blue=water, green=sewer/drain, yellow=gas/oil, orange=communications, pink=temporary survey. Electricians must know these colors to safely work near other utilities."},
{id:445,mod:11,cat:"California-Specific",diff:"Hard",q:"Arc flash hazard analysis for commercial/industrial electrical equipment is governed by:",opts:["NEC Article 240","NFPA 70E Standard for Electrical Safety in the Workplace","Cal/OSHA Title 8 Section 4001","IEEE 1584 (calculation method referenced by NFPA 70E)"],ans:1,ref:"NFPA 70E Article 130; 8 CCR § 2299",exp:"NFPA 70E governs arc flash hazard analysis. Cal/OSHA incorporates NFPA 70E by reference. IEEE 1584 provides the calculation methodology. Equipment must be labeled with arc flash hazard information based on the analysis."},
// MODULE 12: SAFETY, MAINTENANCE & REPAIR (55)
{id:446,mod:12,cat:"Safety & Maintenance",diff:"Easy",q:"LOTO stands for:",opts:["Lock Out Tag Out — the energy control procedure","Limitation of Task Output","Line Outage Test Operations","Load Override Transfer Operations"],ans:0,ref:"8 CCR § 3314",exp:"LOTO = Lockout/Tagout — energy control procedure required by Cal/OSHA (Title 8, Section 3314). Lockout physically prevents operation; tagout uses warning tag when lockout is not feasible."},
{id:447,mod:12,cat:"Safety & Maintenance",diff:"Easy",q:"Who is authorized to remove a lockout or tagout device?",opts:["Any journeyman electrician on the job","The foreman or supervisor","Only the employee who applied the device (with limited exceptions)","The safety officer"],ans:2,ref:"8 CCR § 3314(b)(8)",exp:"Only the employee who applied the LOTO device may remove it, except in documented emergency situations. Prevents someone from inadvertently re-energizing equipment while another worker is still in the danger zone."},
{id:448,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"Correct LOTO sequence?",opts:["Notify, Identify, Isolate, Apply LOTO, Verify, Release stored energy","Notify affected employees, Identify all energy sources, Shut down equipment, Isolate energy, Apply LOTO, Release stored energy, Verify de-energized","Shut down, Isolate, Apply LOTO, Release stored energy, Verify, Notify","Apply LOTO, Notify, Verify, Shut down, Release stored energy, Isolate"],ans:1,ref:"8 CCR § 3314(b)(1)-(8)",exp:"Correct LOTO sequence: (1) Notify affected employees, (2) Identify all energy sources, (3) Shut down equipment, (4) Isolate energy, (5) Apply LOTO devices, (6) Release stored energy (bleed pressure, discharge capacitors), (7) Verify de-energized (try-start, voltage test). Verification step is critical."},
{id:449,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"PPE required for working on energized 480V equipment?",opts:["Standard work clothes and safety glasses","Voltage-rated rubber gloves, arc flash face shield, and FR (flame-resistant) clothing","Only rubber gloves","Hard hat and safety glasses are sufficient"],ans:1,ref:"NFPA 70E Table 130.7(C)(15)(a)",exp:"Energized 480V work: rubber insulating gloves rated for voltage (minimum Class 00 for 500V), leather protectors over gloves, arc flash face shield or hood rated for incident energy, FR clothing. Specific PPE determined by arc flash hazard analysis."},
{id:450,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"The arc flash boundary is:",opts:["Distance at which arc flash ignites clothing","Boundary where workers need arc flash PPE — where incident energy could exceed 1.2 cal/cm² (threshold for second-degree burns)","Restricted approach boundary for unqualified persons","Distance where arc flash energy equals zero"],ans:1,ref:"NFPA 70E 130.5(B)",exp:"Arc flash boundary = distance from arc source where a person without arc flash PPE would receive onset of second-degree burn (1.2 cal/cm²). Within boundary, arc flash PPE required. Determined by arc flash hazard analysis."},
{id:451,mod:12,cat:"Safety & Maintenance",diff:"Hard",q:"Difference between limited approach boundary and restricted approach boundary?",opts:["Same — interchangeable terms","Limited approach = where unqualified persons must stop; restricted approach = where even qualified persons need special PPE and precautions","Limited applies during normal operation; restricted during maintenance only","Restricted is for high voltage; limited is for low voltage"],ans:1,ref:"NFPA 70E Table 130.4(D)(a)",exp:"Limited approach: unqualified persons must not cross without escort. Restricted approach: even qualified persons crossing need rubber insulating equipment, appropriate PPE, and energized electrical work permit."},
{id:452,mod:12,cat:"Safety & Maintenance",diff:"Easy",q:"FIRST action when witnessing someone receiving electric shock?",opts:["Immediately grab victim and pull away","Shut off or disconnect the power source before touching the victim","Call 911 before doing anything else","Begin CPR immediately"],ans:1,ref:"NFPA 70E 130.7(C)(1)",exp:"FIRST — shut off or disconnect the power. Touching the victim while in contact with energized conductor will electrocute you too. Use non-conductive object to separate victim from conductor only if power cannot be immediately disconnected. After power off: call 911, then first aid/CPR."},
{id:453,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"A 'qualified person' for electrical safety means:",opts:["Any licensed electrician","Person with documented training and demonstrated knowledge of energized electrical equipment and hazards at the specific voltage level","Any person with 5 years electrical experience","Certified electrical safety officer only"],ans:1,ref:"NFPA 70E Article 100 & 8 CCR § 2299",exp:"Qualified person: (1) training and knowledge of electrical equipment and hazards, (2) ability to perform work safely, (3) training specific to voltage levels and equipment types encountered. Task-specific and equipment-specific — not universal."},
{id:454,mod:12,cat:"Safety & Maintenance",diff:"Hard",q:"An energized electrical work permit is required when?",opts:["For all work within an electrical room","When justified work must be performed on or near live electrical parts — when de-energizing would create greater hazard or is infeasible","Only for work on circuits above 600V","When work is performed alone without second person present"],ans:1,ref:"NFPA 70E 130.2(A)(3)",exp:"Energized work permit required when work must be performed while energized. Documents: justification (de-energizing creates greater hazard or infeasible), scope of work, all hazards, required PPE, and management authorization."},
{id:455,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"Voltage-rated rubber insulating gloves must be electrically tested how frequently?",opts:["Monthly","Every 6 months","Annually — before each use if showing visible damage","Before each use only — formal testing not required"],ans:1,ref:"NFPA 70E 130.7(C)(11)(a)",exp:"Rubber insulating gloves must be electrically tested EVERY 6 MONTHS and whenever subjected to suspected damage. Visual inspection catches obvious damage; 6-month electrical test (high-voltage proof test) identifies hidden flaws."},
{id:456,mod:12,cat:"Safety & Maintenance",diff:"Easy",q:"Safety label signal word colors — DANGER, WARNING, CAUTION?",opts:["All use the same red and white","DANGER = red background; WARNING = orange background; CAUTION = yellow background","DANGER = yellow; WARNING = red; CAUTION = orange","All electrical warnings must use black on white"],ans:1,ref:"ANSI Z535.4 & NEC labels",exp:"ANSI/ISO: DANGER (red background, white letters) = imminently hazardous — will cause death/serious injury. WARNING (orange, black) = potentially hazardous — could cause death/serious injury. CAUTION (yellow, black) = possibly hazardous — may cause minor injury."},
{id:457,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"Circuit breaker that has been tripping repeatedly — first action?",opts:["Reset it and see if it holds","Identify and correct the cause of tripping before resetting","Immediately replace with larger ampere rating","Reset only after shutting off all loads"],ans:1,ref:"NEC 240.4 & NFPA 70E general",exp:"Repeatedly tripping breakers = a problem. Find and fix the cause FIRST. Resetting without investigation = dangerous — may result in conductor overheating or fire. Replacing with larger breaker without correction is extremely dangerous."},
{id:458,mod:12,cat:"Safety & Maintenance",diff:"Hard",q:"OSHA required testing frequency for portable GFCI devices on construction sites?",opts:["Before each use (test button)","Weekly","Monthly","GFCI devices don't require regular testing"],ans:0,ref:"8 CCR § 1590(j)",exp:"Portable GFCI devices must be tested before EACH use with the test button. Test button only verifies basic trip mechanism — not ground fault detection circuit. For comprehensive testing, use a GFCI tester that simulates actual ground fault current."},
{id:459,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"When must an electrician immediately stop work and report a hazard?",opts:["Only when hazard involves imminent death or serious injury","Whenever they observe a condition that violates safety standards","Only if hazard directly affects the electrician's own safety","When directed by foreman to stop"],ans:1,ref:"CA Labor Code § 6310",exp:"Workers have a right and responsibility to stop work when encountering hazardous conditions and report to supervisor. Cal/OSHA prohibits employer retaliation against workers who report safety hazards."},
{id:460,mod:12,cat:"Safety & Maintenance",diff:"Hard",q:"Arc flash incident energy analysis is:",opts:["Test measuring brightness of an arc flash","Engineering calculation determining thermal energy released at a specific working distance during arc flash — used to select appropriate PPE","Test required before each panel opening","Measurement of voltage available at arc flash location"],ans:1,ref:"NFPA 70E 130.5",exp:"Incident energy analysis uses fault current data, protective device clearing times, and working distances to calculate thermal energy (cal/cm²) at a specific working distance. Determines required PPE category and arc flash boundary distance."},
{id:461,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"Electrical hazard (EH) safety shoes protect against:",opts:["Direct shock from energized conductors","Step potential — current through ground from downed conductor creating potential difference between feet","Both shock protection and step potential","No electrical protection — general impact protection only"],ans:2,ref:"ASTM F2413 & NFPA 70E 130.7(C)(8)",exp:"EH-rated safety shoes: (1) secondary protection against shock if worker contacts energized circuit through feet, and (2) some protection against step potential hazards. Non-conductive soles increase resistance to ground. NOT a substitute for GFCI or insulating platforms."},
{id:462,mod:12,cat:"Safety & Maintenance",diff:"Easy",q:"What should you do with a tripped GFCI or ground fault protection device?",opts:["Reset immediately — ground faults are transient","Find and correct the ground fault before resetting","Replace breaker with GFCI breaker same amperage","Reset — most ground faults won't recur"],ans:1,ref:"NEC 210.8 & GFCI theory",exp:"GFCI trip indicates current flowing through unintended path — possibly through a person or damaged insulation. LOCATE and CORRECT the ground fault before resetting. Common causes: damaged cord, water in outlet, wiring fault."},
{id:463,mod:12,cat:"Safety & Maintenance",diff:"Hard",q:"Purpose of a non-contact voltage tester (NCVT)?",opts:["Measure exact voltage at a test point","Detect presence or absence of voltage without direct contact with energized conductors","Test GFCI outlets for proper operation","Measure resistance in electrical circuits"],ans:1,ref:"NFPA 70E 110.4(A)(5)",exp:"NCVTs detect AC voltage presence by sensing electromagnetic field around energized conductors. Provide go/no-go indication — NOT actual voltage measurement. Always verify tester works on known live source before AND after testing unknown circuit."},
{id:464,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"Cal/OSHA requirement when a worker reports an electrical hazard?",opts:["Investigate and document but work may continue","Immediately correct hazard or provide interim protection, and document the correction","Simply post a warning sign","Only address hazard during next scheduled safety inspection"],ans:1,ref:"8 CCR § 3203 & CA Labor Code § 6401.7",exp:"Cal/OSHA: correct identified hazards in timely manner. Imminent hazards: work must stop until corrected. Non-imminent: corrected within reasonable time. All reports and corrections must be documented in IIPP."},
{id:465,mod:12,cat:"Safety & Maintenance",diff:"Easy",q:"Minimum safe distance from overhead power lines during construction?",opts:["3 feet","6 feet","10 feet for lines up to 50 kV","20 feet for all voltage levels"],ans:2,ref:"8 CCR § 2941(a)",exp:"Cal/OSHA: minimum 10-foot clearance from overhead power lines up to 50 kV for equipment, personnel, and materials. Higher voltage = greater required clearance. Overhead line contact = leading cause of construction fatalities."},
{id:466,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"Electrical shock physiological effects?",opts:["Any physical contact with electrical equipment","Physiological effect on body when current passes through it — can cause burns, muscle paralysis, respiratory failure, and cardiac arrest","Force exerted by electromagnetic field","Voltage difference between two conductors"],ans:1,ref:"NFPA 70E Annex K",exp:"Shock = current through body. Effects by level: 1mA = perceptible; 5mA = painful; 10-20mA = can't let go (muscle freeze); 50-100mA = ventricular fibrillation; 100-200mA = nearly certain death. Current kills — voltage drives the current."},
{id:467,mod:12,cat:"Safety & Maintenance",diff:"Hard",q:"'Step potential' and when it presents danger?",opts:["Voltage required to start a motor step by step","Hazardous voltage difference between points on the ground near a fault or downed conductor","Voltage between different floors of a building","Potential energy stored in elevated cable"],ans:1,ref:"NFPA 70E Annex O",exp:"Step potential: fault current through earth creates voltage gradient along ground surface. Points closer to fault at higher potential than points farther away. Person straddling two different-potential points = circuit through body without touching faulted conductor. Shuffle step minimizes exposure."},
{id:468,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"Proper way to use a multimeter to measure voltage in a live panel?",opts:["Use current clamp — avoid inserting probes into live panels","Set meter to highest voltage range, work down to appropriate range; keep one hand behind back or in pocket","Always use both hands for accuracy","Insert both probes simultaneously"],ans:1,ref:"NFPA 70E 130.6(B)",exp:"Safe multimeter technique: set to highest range first (prevents meter damage), then reduce. One hand behind back keeps current from crossing chest (heart) if accidental contact occurs. Use insulated probes and appropriate PPE."},
{id:469,mod:12,cat:"Safety & Maintenance",diff:"Hard",q:"Difference between Class 00 and Class 4 rubber insulating gloves?",opts:["Only color differs","Class 00 rated 500V (proof tested 2,500V); Class 4 rated 36,000V (proof tested 40,000V)","Class 00 for wet; Class 4 for dry","Class 4 thicker but same voltage rating as Class 00"],ans:1,ref:"ASTM D120 & NFPA 70E Table 130.7(C)(7)(b)",exp:"Rubber glove classes: 00=500V max (2,500V proof); 0=1,000V; 1=7,500V; 2=17,000V; 3=26,500V; 4=36,000V max (40,000V proof). Glove class must match or exceed voltage of work being performed."},
{id:470,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"FR (Flame Resistant) clothing protects against:",opts:["Electric shock — FR prevents current through body","Arc flash thermal energy — FR self-extinguishes and doesn't continue burning after arc energy dissipates","Both shock and arc flash protection","Only static electricity sparks"],ans:1,ref:"NFPA 70E 130.7(C)(5) & ASTM F1506",exp:"FR clothing protects against arc flash by: (1) not continuing to burn after arc energy dissipates (self-extinguishes), and (2) limiting skin burn injury. FR does NOT protect against shock — rubber insulating equipment required for that. Standard polyester/nylon melts and continues burning, dramatically worsening burn injuries."},
{id:471,mod:12,cat:"Safety & Maintenance",diff:"Easy",q:"First step when finding a circuit that needs repair?",opts:["Begin repairs immediately to restore power quickly","De-energize the circuit using proper LOTO procedure before beginning work","Test circuit with multimeter to understand fault before de-energizing","Notify building owner before doing anything"],ans:1,ref:"8 CCR § 3314 & NFPA 70E 130.2",exp:"Always de-energize with proper LOTO BEFORE beginning work. Rushing to diagnose without de-energizing is how experienced electricians get electrocuted — familiarity breeds dangerous complacency. No exceptions."},
{id:472,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"Test sequence to verify a circuit is de-energized before beginning work?",opts:["Visual inspection of open breaker is sufficient","Test with voltage tester on known live source, test on circuit to verify no voltage, then test on known live source again (test-before-touch)","Testing only required for circuits above 240V","Visual confirmation breaker is off is all that's needed"],ans:1,ref:"NFPA 70E 120.5(7)",exp:"Test-before-touch sequence: (1) Verify tester works on known live source, (2) Test circuit to verify no voltage, (3) Verify tester still works on known live source. Three steps catch both dead circuits AND dead testers."},
{id:473,mod:12,cat:"Safety & Maintenance",diff:"Hard",q:"NFPA 70E PPE category system for arc flash?",opts:["Classes 1-5 based on voltage level","PPE Categories 1-4 based on incident energy levels in cal/cm²","Hazard levels A through D based on fault current","Protection levels based on equipment age"],ans:1,ref:"NFPA 70E Table 130.7(C)(15)(a)",exp:"NFPA 70E PPE Categories 1-4: Cat 1 = min 4 cal/cm² (minimum arc rating); Cat 2 = min 8 cal/cm²; Cat 3 = min 25 cal/cm²; Cat 4 = min 40 cal/cm². Above 40 cal/cm² requires incident energy analysis for specific PPE."},
{id:474,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"'Buddy system' in electrical safety — when required?",opts:["Sharing tools between workers","Having a second qualified person present when working on energized electrical equipment — required by Cal/OSHA for certain energized work","Pairing apprentices with journeymen for training","Checking each other's work before energizing"],ans:1,ref:"8 CCR § 2299 & NFPA 70E 130.2",exp:"Buddy system (second qualified person present) required by Cal/OSHA when working on energized equipment above certain voltage levels. Second person can: call for help in emergency, assist with safe rescue, provide additional safety check."},
{id:475,mod:12,cat:"Safety & Maintenance",diff:"Easy",q:"Maximum voltage considered 'low-voltage' for shock hazard purposes per NFPA 70E?",opts:["30V","50V","120V","600V"],ans:1,ref:"NFPA 70E 130.2(A)(4)",exp:"NFPA 70E: 50V is the threshold for electrical shock hazard. Below 50V, shock hazard minimal under normal dry conditions (though GFCI may still be required). Above 50V, all approach boundary, PPE, and qualified person requirements apply."},
{id:476,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"An electrical safety program required by NFPA 70E and Cal/OSHA must include:",opts:["Only a list of prohibited actions","Safety policies, training requirements, PPE selection, energized work permit procedures, LOTO procedures, approach boundaries, and incident investigation","List of qualified personnel only","Only the LOTO procedure — other requirements optional"],ans:1,ref:"NFPA 70E 110.3",exp:"Electrical safety program elements: written safety policies, training/retraining requirements, energized work procedures, energized work permit system, LOTO procedures, approach boundary documentation, PPE selection procedures, and incident investigation procedures."},
{id:477,mod:12,cat:"Safety & Maintenance",diff:"Hard",q:"Cal/OSHA electrical safety training refresher frequency?",opts:["Once at initial hire — no refresher required","Annually and whenever an electrician demonstrates unsafe practices or is involved in an electrical incident","Every 3 years aligned with certification renewal","Only when job duties change significantly"],ans:1,ref:"8 CCR § 3203 & NFPA 70E 110.2",exp:"Cal/OSHA: electrical safety training repeated at regular intervals (typically annually), AND whenever: (1) employee demonstrates unsafe practices, (2) after electrical incident or near-miss. Documentation of all training must be maintained."},
{id:478,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"What to do with a circuit breaker showing burned or scorched contact marks?",opts:["Clean contacts with electrical contact cleaner and reinstall","Replace the breaker — burned contacts indicate fault operation; internal mechanism may be compromised","Lubricate with dielectric grease","Test and reinstall if passes test"],ans:1,ref:"NEC 240.4 & NFPA 70E general",exp:"Burned/pitted/carbonized contacts = breaker has operated under fault conditions. Internal mechanism may be compromised even if it resets. Replace damaged breakers — never trust a breaker showing signs of fault interruption stress."},
{id:479,mod:12,cat:"Safety & Maintenance",diff:"Easy",q:"Required PPE for working in a panel that is fully de-energized with service disconnected?",opts:["No PPE required — panel is de-energized","Safety glasses minimum; leather gloves and hard hat if risk of dropped tools","Arc flash PPE same as energized work","No PPE — if verified de-energized, standard work clothes acceptable"],ans:1,ref:"NFPA 70E 130.2 & 8 CCR § 3314",exp:"De-energized panel: shock hazard eliminated but other hazards remain (dropped tools, sharp metal edges). Minimum: safety glasses, leather gloves for cuts, hard hat for overhead work. Arc flash PPE not required for verified de-energized work."},
{id:480,mod:12,cat:"Safety & Maintenance",diff:"Hard",q:"Tool for locating a ground fault on a 480V commercial circuit?",opts:["Standard multimeter set to voltage","Megger (insulation resistance tester) to find damaged insulation, combined with clamp meter to trace fault current","Non-contact voltage tester only","Circuit breaker trip mechanism indicates fault location"],ans:1,ref:"NFPA 70E 110.4 & IEEE 1584",exp:"Finding ground faults: (1) Megohmmeter (Megger) applies high DC test voltage to stress-test conductor insulation to ground, (2) clamp meter measures to trace where fault current flows, (3) visual inspection. Megger testing requires circuit de-energized first."},
{id:481,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"What is a 'tag' in a tagout system when lockout is not possible?",opts:["Colored marker on conductors for identification","Warning tag attached to energy isolation point indicating equipment must not be operated — used when physical lockout device cannot be applied","Label indicating circuit amperage","Property tag indicating equipment ownership"],ans:1,ref:"8 CCR § 3314(b)",exp:"Tagout device = warning tag applied to energy isolation point when physical lockout is impractical due to equipment design. Tag states 'Do Not Operate' or similar warning. Tagout alone provides LESS protection than lockout — relies on people reading and obeying the tag."},
{id:482,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"Proper disposal of mercury-containing fluorescent lamps in California?",opts:["May be disposed of in regular trash","Must be recycled through approved lamp recycler — they are hazardous waste in California","Only large quantities (100+) require special disposal","Must be crushed before disposal to reduce volume"],ans:1,ref:"CA H&S Code § 25215 et seq.",exp:"California prohibits fluorescent lamp disposal in regular trash — they are hazardous waste. Must be recycled through: utility-sponsored programs, retail collection (Home Depot, IKEA), mail-in recyclers, or licensed hazardous waste facilities."},
{id:483,mod:12,cat:"Safety & Maintenance",diff:"Easy",q:"After completing work on an electrical system, the proper restoration sequence?",opts:["Simply restore power and leave","Remove LOTO devices, verify tools and materials are cleared, notify all affected employees, and restore energy in controlled manner","Remove lockout and restore power without notification","Turn power back on quickly to minimize downtime"],ans:1,ref:"8 CCR § 3314(b)(9)-(10)",exp:"Proper energy restoration: (1) verify all work complete, tools/materials cleared, (2) ensure all personnel are clear, (3) notify affected employees, (4) remove LOTO devices (only the person who applied them), (5) restore energy in controlled manner."},
{id:484,mod:12,cat:"Safety & Maintenance",diff:"Hard",q:"'Double insulation' and its effect on grounding requirements?",opts:["Two layers of electrical insulation on conductors — all conductors must be double insulated","Design where tool enclosure is non-conductive, providing protection without a grounding conductor — double insulated tools don't require third grounding wire","Method of wrapping junction box connections with two layers of tape","Insulating both conductors — required for high voltage only"],ans:1,ref:"UL 943 & NFPA 70E 130.7(C)(10)",exp:"Double insulation: non-conductive outer enclosure PLUS individually insulated internal components. No grounding wire (green wire) needed. Marked with square-within-square symbol. No third grounding pin on their plugs."},
{id:485,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"Requirements when electrical work must be performed without de-energizing?",opts:["A second qualified person must be present","Energized electrical work permit, appropriate PPE based on arc flash hazard analysis, and qualified person performing the work","GFCI protection must be provided","No additional requirements — a qualified electrician may work on any energized equipment"],ans:1,ref:"NFPA 70E 130.2(A)(3)",exp:"Energized work: (1) documented justification that de-energizing creates greater hazard or is infeasible, (2) energized electrical work permit authorized by management, (3) appropriate PPE from arc flash hazard analysis, (4) performed by qualified person."},
{id:486,mod:12,cat:"Safety & Maintenance",diff:"Hard",q:"OSHA requirement when opening panels for inspection (not maintenance or repair)?",opts:["Inspection permitted without PPE — no contact with energized parts","If no inadvertent contact anticipated, minimum PPE; if possible inadvertent contact, appropriate PPE required","Opening panels always requires full arc flash PPE","Visual inspection from distance requires no PPE"],ans:1,ref:"NFPA 70E 130.2(A)(2)",exp:"OSHA/NFPA 70E distinguish: inspection from safe distance without possible contact = minimum PPE. Inspection within approach boundaries = appropriate PPE based on incident energy. Opening a panel to read a meter while staying outside approach boundaries doesn't require arc flash PPE."},
{id:487,mod:12,cat:"Safety & Maintenance",diff:"Easy",q:"Safety label signal word colors?",opts:["All warnings use same red and white","DANGER = red background; WARNING = orange; CAUTION = yellow","DANGER = yellow; WARNING = red; CAUTION = orange","All electrical warnings must be black on white"],ans:1,ref:"ANSI Z535.4",exp:"ANSI/ISO standard: DANGER (red, will cause death/serious injury), WARNING (orange, could cause death/serious injury), CAUTION (yellow, may cause minor injury). Electricians must understand these signal word distinctions."},
{id:488,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"What does the GFCI test button actually test?",opts:["Tests GFCI's response to actual ground fault current","Tests only the trip mechanism — not the ground fault detection circuitry","Proves the circuit is dead and safe to work on","Resets the GFCI after a trip"],ans:1,ref:"NEC 210.8 & UL 943",exp:"GFCI test button verifies ONLY the internal trip mechanism — NOT whether the device will detect an actual ground fault. A GFCI with failed ground fault sensing but working trip mechanism would pass the button test but fail to protect against ground faults. Use a GFCI tester for comprehensive testing."},
{id:489,mod:12,cat:"Safety & Maintenance",diff:"Hard",q:"Documentation required for a written LOTO program under Cal/OSHA?",opts:["No written documentation required — verbal procedures acceptable","Written program, equipment-specific energy control procedures for each equipment type, and records of annual inspections and training","Only initial training records for each employee","Only names of authorized employees"],ans:1,ref:"8 CCR § 3314(a)(3)",exp:"Cal/OSHA LOTO documentation: (1) written energy control program, (2) equipment-specific lockout procedures for each equipment type with multiple energy sources, (3) annual inspection records, (4) training records for each authorized and affected employee, (5) records of group LOTO procedures."},
{id:490,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"Working in energized 480V panel with exposed bus bars — required rubber insulating equipment?",opts:["Rubber gloves only","Class 00 rubber gloves with leather protectors, insulated tools, and insulating blankets/barriers to prevent accidental contact","No rubber insulating equipment required for 480V — only 600V+ requires rubber goods","Standard leather gloves provide adequate protection for 480V"],ans:1,ref:"NFPA 70E 130.7(C)(7)",exp:"Working near exposed 480V bus bars: rubber insulating gloves (minimum Class 00, rated 500V) with leather protectors, insulated tools, and insulating barriers/blankets for adjacent energized parts. Leather gloves alone = NO electrical protection."},
{id:491,mod:12,cat:"Safety & Maintenance",diff:"Easy",q:"Minimum rubber insulating glove rating for 120V, single-phase circuit?",opts:["Class 00 — rated 500V max use","Class 0 — rated 1,000V","Class 1 — rated 7,500V","Any rubber glove provides adequate protection for 120V"],ans:0,ref:"ASTM D120 & NFPA 70E Table 130.7(C)(7)(b)",exp:"Class 00 (500V max use) is minimum for 120V work. Glove voltage rating must exceed circuit voltage. Many safety programs require at least Class 0 (1,000V) for any electrical work for adequate safety margin."},
{id:492,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"Before working in a confined space with electrical work required?",opts:["Simply enter and complete work quickly","Conduct atmospheric testing, obtain required permits, ensure adequate ventilation, and have trained attendant outside","Only tie off with safety harness","Confined space permits only required for spaces more than 5 feet deep"],ans:1,ref:"8 CCR § 5157 & CA Labor Code",exp:"Permit-required confined spaces: (1) atmospheric testing (oxygen, combustible gas, toxic atmosphere), (2) entry permit completed and signed, (3) attendant stationed outside throughout work, (4) rescue equipment available, (5) ventilation as required. Electrical equipment in confined spaces = compounded hazards."},
{id:493,mod:12,cat:"Safety & Maintenance",diff:"Hard",q:"'Try-start' verification in LOTO procedure means?",opts:["Starting equipment to verify it runs before locking out","After applying LOTO, attempting to operate equipment at normal control point to verify it cannot start — confirming energy isolation","Diagnostic procedure to identify intermittent faults","Testing the lockout device to ensure it cannot be removed without a key"],ans:1,ref:"8 CCR § 3314(b)(5)",exp:"Try-start: after applying all LOTO devices, attempt to operate at normal control point (start button, switch). If it doesn't start = isolation confirmed. Critical verification step before work begins. Then also use voltage tester to verify no voltage at work point."},
{id:494,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"Discovering an unlabeled wire in a junction box — appropriate action?",opts:["Assume it's neutral based on color","Test with voltage tester while maintaining approach distance — never assume any wire is de-energized based on color or location","Cut it — unlabeled wires are abandoned and safe","Ignore it and work around it"],ans:1,ref:"NFPA 70E 120.5(7) & 8 CCR § 3314",exp:"Never assume any conductor is de-energized based on color, location, or assumption. Unlabeled wires may be live circuits, switched legs that energize under certain conditions, or wires with reversed color coding. Test before touch — always."},
{id:495,mod:12,cat:"Safety & Maintenance",diff:"Hard",q:"Cal/OSHA requirement for working on circuits at 600V or less in industrial facilities?",opts:["Same requirements as commercial buildings","Cal/OSHA Title 8, Section 2299 et seq. covers electrical safety for general industry — specific requirements for qualified workers, PPE, LOTO, and approach boundaries","Industrial facilities follow OSHA 1910.303, not Cal/OSHA","Only NFPA 70E applies to industrial facilities — Cal/OSHA is for construction only"],ans:1,ref:"8 CCR §§ 2299-2399 (General Industry Electrical Safety)",exp:"Cal/OSHA Title 8 has separate electrical safety standards for general industry (Article 36, Sections 2299-2399) covering: qualified person requirements, LOTO procedures, approach boundaries, PPE selection. Cal/OSHA standards apply to industrial facilities and often exceed federal OSHA."},
{id:496,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"Proper response when a worker's clothing ignites from arc flash?",opts:["Run to water source","Stop, drop, and roll — use fire blanket to extinguish flames if available","Remove burning clothing immediately","Stand still — moving fans the flames"],ans:1,ref:"NFPA 70E 130.7(A) & first aid",exp:"Clothing ignites: STOP, DROP, ROLL. Running fans flames. Rolling smothers them. FR clothing self-extinguishes and won't melt onto skin, but can still ignite. Fire blanket can smother flames. After extinguishing: call 911, seek immediate medical treatment."},
{id:497,mod:12,cat:"Safety & Maintenance",diff:"Easy",q:"Device allowing testing for live voltage without physically touching the conductor?",opts:["A clamp meter","A non-contact voltage tester (NCVT)","A megohmmeter","An analog voltmeter"],ans:1,ref:"NFPA 70E 110.4(A)(5)",exp:"Non-contact voltage tester (NCVT, 'tick tracer,' 'voltage pen') detects AC voltage without contact — senses electromagnetic field around energized conductors. First tool to use when approaching any unknown circuit — quick, safe, simple."},
{id:498,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"When must electrical contractor's journeyman update safety training records?",opts:["Only when changing employers","At each certification renewal (every 3 years)","When job duties change to include new hazards, after incidents, or when employer's safety program changes","Safety training records are employee's personal responsibility"],ans:2,ref:"8 CCR § 3203 & NFPA 70E 110.2(D)",exp:"Training records updated whenever: (1) job duties change to include new electrical hazards, (2) employee involved in incident or near-miss, (3) changes to employer's safety program or regulations. Employers must maintain training records with dates, content, and employee acknowledgment."},
{id:499,mod:12,cat:"Safety & Maintenance",diff:"Hard",q:"Additional requirements for high-voltage maintenance above 600V beyond low-voltage work?",opts:["No additional requirements — same procedures at all voltages","Larger approach boundaries, higher-rated insulating equipment (Class 1-4 gloves), qualified high-voltage workers with specific training, and greater PPE requirements","High voltage work simply requires a second person present","Only utility employees may work on circuits above 600V"],ans:1,ref:"NFPA 70E 130.2 & 8 CCR §§ 2299-2399",exp:"Above 600V: larger approach boundaries, higher-rated rubber insulating equipment (Class 1-4 gloves), specialized high-voltage qualified worker training, and more stringent PPE requirements because higher voltages generate higher fault currents and more severe arc flash hazards."},
{id:500,mod:12,cat:"Safety & Maintenance",diff:"Medium",q:"Most important single safety practice an electrician can adopt to prevent electrical shock?",opts:["Always wear rubber gloves","Always de-energize circuits before working and verify de-energization — treat all conductors as energized until verified otherwise","Always work with a partner","Install GFCI on all circuits"],ans:1,ref:"8 CCR § 3314 & NFPA 70E 120.5",exp:"De-energizing before working — and VERIFYING de-energization — is the single most effective electrical safety practice. Most electrical fatalities involve workers who believed circuits were de-energized when they were not. Test-before-touch + proper LOTO eliminates nearly all shock fatality risk."},
{id:501,mod:10,cat:"Calculations",diff:"Easy",q:"Where in the NEC codebook is Table 310.16 (conductor ampacity) located?",opts:["Article 100","Chapter 3, Article 310","Chapter 9","Annex C"],ans:1,ref:"NEC Article 310",exp:"Table 310.16 is in Article 310 — Conductors for General Wiring. It covers ampacity values for copper and aluminum at 60°C, 75°C, and 90°C columns. It's one of the most-referenced tables on the exam — conductor sizing, overcurrent protection, temperature correction all depend on it. Know exactly where it is before exam day."},
{id:502,mod:10,cat:"Calculations",diff:"Easy",q:"Where in the NEC codebook is Table 8 (conductor properties — circular mil areas) located?",opts:["Article 250","Article 310","Chapter 9","Annex A"],ans:2,ref:"NEC Chapter 9, Table 8",exp:"Table 8 is in Chapter 9 — Tables. It lists conductor properties including circular mil (CM) area, needed for the voltage drop formula: VD = 2×K×I×D÷CM. Chapter 9 also contains Table 1 (conduit fill %), Table 5 (conductor cross-sections), and Table 9 (impedance). Tab the whole Chapter 9 section — multiple question types draw from it."},
{id:503,mod:10,cat:"Calculations",diff:"Medium",q:"A voltage drop calculation requires the circular mil area of 6 AWG copper. Which NEC table provides this value?",opts:["Table 310.16","Table 250.66","Chapter 9, Table 8","Annex C, Table C1"],ans:2,ref:"NEC Chapter 9, Table 8",exp:"Chapter 9, Table 8 lists conductor properties including circular mil area. 6 AWG copper = 26,240 CM. Table 310.16 gives ampacity — not CM area. For voltage drop you need both: Table 310.16 to verify conductor size is adequate, Table 8 for the CM value to plug into the formula."},
{id:504,mod:10,cat:"Calculations",diff:"Easy",q:"NEC Chapter 9 contains tables used primarily for:",opts:["Equipment grounding conductor sizing","Conductor ampacity at various temperatures","Conduit fill, conductor properties, and voltage drop data","California-specific code amendments"],ans:2,ref:"NEC Chapter 9",exp:"Chapter 9 is the calculation toolbox: Table 1 (conduit fill %), Table 4 (conduit dimensions), Table 5 (conductor cross-section areas), Table 8 (conductor CM area for voltage drop), Table 9 (conductor impedance). If a question requires a number you have to calculate, the data is almost certainly in Chapter 9."},
{id:505,mod:10,cat:"Calculations",diff:"Easy",q:"Annex C of the NEC codebook is most useful for which type of exam question?",opts:["Load calculation questions","Conductor ampacity questions","Conduit fill — maximum number of conductors by conduit type and size","GFCI and AFCI protection requirements"],ans:2,ref:"NEC Annex C",exp:"Annex C contains conduit and tubing fill tables (C1–C12) for each conduit type — EMT, RMC, PVC, etc. Each table lists maximum conductor counts by conductor size. These are direct lookups: find conduit size and conductor gauge, read the answer. Example: Annex C Table C1, 1/2-inch EMT = 7 conductors of 12 AWG THWN."},
{id:506,mod:1,cat:"Definitions",diff:"Easy",q:"Where are definitions of terms used throughout the NEC located?",opts:["Article 90 — Introduction","Article 100 — Definitions","Chapter 9 — Tables","Annex A"],ans:1,ref:"NEC Article 100",exp:"Article 100 contains definitions for terms used in two or more NEC articles. Terms used in only one article are defined within that article. When a question turns on what a term means — 'feeder,' 'branch circuit,' 'dwelling unit,' 'readily accessible' — Article 100 is the first stop. Tab it."},
{id:507,mod:10,cat:"Calculations",diff:"Medium",q:"Which two NEC tables appear most frequently on the California Journeyman exam?",opts:["Table 220.42 and Table 430.52","Table 310.16 (ampacity) and Chapter 9 Table 8 (conductor properties)","Table 250.66 and Table 314.16(B)","Annex C Table C1 and Table 240.6(A)"],ans:1,ref:"NEC Table 310.16 & Chapter 9 Table 8",exp:"Table 310.16 (conductor ampacity) and Chapter 9 Table 8 (conductor CM area) appear on virtually every exam. Table 310.16 is needed for conductor sizing, overcurrent protection, and temperature correction. Table 8 is needed for voltage drop calculations. Know exactly where both are before you sit down."},
{id:508,mod:10,cat:"Calculations",diff:"Medium",q:"On the open-book exam, a question asks for box fill requirements for 4 conductors. The fastest lookup path is:",opts:["Scan Chapter 3 until box fill rules appear","NEC index → 'boxes' or 'box fill' → Article 314.16","Table 310.16, then cross-reference Chapter 9","Annex C for conductor fill percentages"],ans:1,ref:"NEC 314.16 & NEC Index",exp:"Index → keyword → article is the fastest path for any code lookup. Box fill: index → 'boxes, outlet, device' or 'fill, boxes' → Article 314.16. Table 314.16(B) lists volume allowances per conductor type. Using the index instead of scanning chapters can save 60–90 seconds per question — significant when 110 questions share 270 minutes."},
{id:509,mod:10,cat:"Calculations",diff:"Easy",q:"The NEC index lists 'GFCI protection, garages' and points to which article?",opts:["Article 230.70","Article 250.30","Article 210.8","Article 314.16"],ans:2,ref:"NEC 210.8(A)(2)",exp:"GFCI protection for garage receptacles is in Article 210.8(A)(2). The index workflow — keyword → article → verify — is the fastest way to confirm code requirements on the open-book exam. Practice index lookups during study sessions so the habit is automatic by test day."},
{id:510,mod:10,cat:"Calculations",diff:"Hard",q:"You have 110 questions and 270 minutes. A load calculation takes ~3 minutes. A code lookup takes ~30 seconds. What is the correct time management approach?",opts:["Work through questions in order — never skip","Answer all code lookup questions first, flag calculation questions, return to them at the end","Skip the last 20 questions to reserve time for calculations","Do all calculation questions first while concentration is highest"],ans:1,ref:"DLSE CA Journeyman Exam format",exp:"270 minutes ÷ 110 questions = ~2.5 minutes average. Code lookups (20–40 sec) and calculations (2–3 min) earn identical points. Answering fast code questions first maximizes total correct answers. Flag calculations, sweep the exam for quick points, then return. Never leave a flagged question blank — there is no penalty for guessing."},
{id:511,mod:10,cat:"Calculations",diff:"Medium",q:"A question requires sizing a conductor for a 50A continuous load at 75°C terminations. The correct two-step process is:",opts:["Estimate from field experience, confirm with inspector","Apply 125% rule (210.20A) → 62.5A minimum, then find first conductor meeting that in Table 310.16 at 75°C column","Look up 50A directly in Table 310.16 and use that conductor size","Use Chapter 9 Table 9 for impedance-based sizing"],ans:1,ref:"NEC 210.20(A) & Table 310.16",exp:"Continuous load rule: 50A × 1.25 = 62.5A minimum conductor ampacity (NEC 210.20(A)). Then Table 310.16, 75°C column: 4 AWG copper = 70A — first size meeting 62.5A. This two-step pattern — identify the rule, apply the table — covers the majority of conductor sizing questions on the exam."},
{id:512,mod:10,cat:"Calculations",diff:"Medium",q:"During the exam you reach a complex motor circuit calculation. The best approach is:",opts:["Spend as much time as needed — one question can change a pass to a fail","Flag it, continue answering code lookup questions, return to it at the end","Leave it blank — calculation questions are harder and worth attempting last","Guess immediately without flagging and move on permanently"],ans:1,ref:"DLSE CA Journeyman Exam format",exp:"All 110 questions carry equal weight. Flagging a hard calculation and returning later is not giving up — it's efficient scoring. A code question answered in 30 seconds earns the same point as a 3-minute calculation. Never leave a flagged question permanently blank: with 4 answer choices and no penalty for wrong answers, a guess is always worth making."},
];

